-- Poems batch 225
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f1d22496-5c7b-4311-9dcd-bf380c7fe725','題客省','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','煉就紅鉛不計斤，五湖四海十餘春。',32,'全唐诗/poet.song.207000.json','["煉就紅鉛不計斤，五湖四海十餘春。", "今朝杖屨廬山下，雨笠烟簑一箇身。"]'),
('6bcb2db1-58cf-467b-9c4f-fd49f11bee2e','洞前亭','白玉蟾','宋','宋诗','song-poetry','','[]','洞前春水漾桃溪，洞後數聲青鳥啼。',32,'全唐诗/poet.song.207000.json','["洞前春水漾桃溪，洞後數聲青鳥啼。", "二十四巖風雨夜，神仙過此話刀圭。"]'),
('cb194aef-a59d-4701-a454-f1b4651f4b89','送林古虛歸閩','白玉蟾','宋','宋诗','song-poetry','','[]','名落江湖二十春，江湖那個是知音。',32,'全唐诗/poet.song.207000.json','["名落江湖二十春，江湖那個是知音。", "于今拄杖挑明月，雲滿千山何處尋。"]'),
('13161c47-b621-49c6-8ef8-bbf10672f4bc','和劉司門韻題臨溪亭','白玉蟾','宋','宋诗','song-poetry','','[]','臨水皤然兩鬢絲，山煙凝翠入鶉衣。',32,'全唐诗/poet.song.207000.json','["臨水皤然兩鬢絲，山煙凝翠入鶉衣。", "橫吹鐵笛且歸去，懶把漁竿立蘚磯。"]'),
('59a3f5c8-5920-49a6-9e82-6a936dd5e491','黄仙菴字謎','白玉蟾','宋','宋诗','song-poetry','','[]','青紅白黑欠中央，聞道西人已大方。',32,'全唐诗/poet.song.207000.json','["青紅白黑欠中央，聞道西人已大方。", "二十一人田下電，阿誰訪之詹仲皇。"]'),
('2550007b-6617-4dc1-b3b9-c81281799603','登愛閣有感','白玉蟾','宋','宋诗','song-poetry','','[]','五六年前彭覺非，同登愛閣翫荷池。',32,'全唐诗/poet.song.207000.json','["五六年前彭覺非，同登愛閣翫荷池。", "如今再到還重省，十二闌干謾雨絲。"]'),
('53247872-2b28-4d7e-9dc7-fb0e07e25a2b','琴','白玉蟾','宋','宋诗','song-poetry','','[]','夜靜無雲月似銀，清宵鶴唳一傷神。',32,'全唐诗/poet.song.207000.json','["夜靜無雲月似銀，清宵鶴唳一傷神。", "子期玉骨寒於雪，世上知音能幾人。"]'),
('0879419c-53af-45af-9fad-f4b6555d770b','天窗','白玉蟾','宋','宋诗','song-poetry','','[]','屋頭除却數條椽，政好臨風對月眠。',32,'全唐诗/poet.song.207000.json','["屋頭除却數條椽，政好臨風對月眠。", "行客只從門外過，豈知屋裏有青天。"]'),
('2804d6ed-4cfd-4bae-8a04-b286184889a8','七臺山','白玉蟾','宋','宋诗','song-poetry','','[]','六月泉聲带雨寒，斜陽染出淡紅山。',32,'全唐诗/poet.song.207000.json','["六月泉聲带雨寒，斜陽染出淡紅山。", "白雲無恙青楓老，不見龔劉振錫鐶。"]'),
('fbe0a3e8-0d44-4ed2-a35c-91b56df4744c','春風  其一','白玉蟾','宋','宋诗','song-poetry','','[]','一一鬚梢一霧珠，曉來雨意尚躊躇。',32,'全唐诗/poet.song.207000.json','["一一鬚梢一霧珠，曉來雨意尚躊躇。", "落花也避東風惡，水面相驅嚲向隅。"]'),
('a9cbf14a-e277-46c2-bb33-871e094337a8','春風  其二','白玉蟾','宋','宋诗','song-poetry','','[]','燕燕于飛引蝶狂，嬌鶑歌懶笑蜂忙。',32,'全唐诗/poet.song.207000.json','["燕燕于飛引蝶狂，嬌鶑歌懶笑蜂忙。", "庭前萱草臺前竹，也學春風舞綠楊。"]'),
('967cd5c4-cbb3-40f1-8f7a-7687a428181f','春風  其三','白玉蟾','宋','宋诗','song-poetry','','[]','底事東風苦欲寒，不教詩客縱游觀。',32,'全唐诗/poet.song.207000.json','["底事東風苦欲寒，不教詩客縱游觀。", "無端虛把鞦韆送，落盡梨花似雪團。"]'),
('fcada81e-aad3-4724-9be6-393a33ee82f2','春風  其四','白玉蟾','宋','宋诗','song-poetry','','[]','遠草將人雙眼行，飛花誤蝶乞流鶑。',32,'全唐诗/poet.song.207000.json','["遠草將人雙眼行，飛花誤蝶乞流鶑。", "更饒一夜東風劣，且博三朝五日晴。"]'),
('21a3f6e8-5a36-4d2b-9637-4a3d0f6140f2','觀物  其一','白玉蟾','宋','宋诗','song-poetry','','[]','蜂占薔薇封食邑，蟻侵蜾蠃借軍須。',32,'全唐诗/poet.song.207000.json','["蜂占薔薇封食邑，蟻侵蜾蠃借軍須。", "雨天風急鳩呼婦，水國煙寒鴈喚奴。"]'),
('c3132f6b-a36f-4817-a404-c0dd9d2100e7','觀物  其二','白玉蟾','宋','宋诗','song-poetry','','[]','曉鷺守溪圖口腹，暮蛛借屋計家生。',32,'全唐诗/poet.song.207000.json','["曉鷺守溪圖口腹，暮蛛借屋計家生。", "不羈野馬空中騁，無喘蝸牛壁上耕。"]'),
('061254df-87ab-4719-a1d0-a6821ad32047','荷池追凉','白玉蟾','宋','宋诗','song-poetry','','[]','清曉無人知此凉，岸巾植杖立銀塘。',32,'全唐诗/poet.song.207000.json','["清曉無人知此凉，岸巾植杖立銀塘。", "晴霞燒眼收將斂，荷葉生風綠水香。"]'),
('261bee63-0b4b-40a6-bc62-0736c63720bb','舟程苦遲','白玉蟾','宋','宋诗','song-poetry','','[]','水馬輕便勝陸行，衝風遡水反多程。',32,'全唐诗/poet.song.207000.json','["水馬輕便勝陸行，衝風遡水反多程。", "溪流詰曲成千摺，雲色陰晴沒十成。"]'),
('dcae93a1-fd3f-4f2a-b223-ea18d24bfea1','曉醒追思夜來句  其一','白玉蟾','宋','宋诗','song-poetry','','[]','孤夢歸從偃月城，清寒入骨倚危亭。',32,'全唐诗/poet.song.207000.json','["孤夢歸從偃月城，清寒入骨倚危亭。", "雪花散作楊花片，酒色酤來竹葉青。"]'),
('0f074003-c30a-4104-b1aa-81e00391cb25','曉醒追思夜來句  其二','白玉蟾','宋','宋诗','song-poetry','','[]','茆屋蕭然詩滿懷，一天風雪白皚皚。',32,'全唐诗/poet.song.207000.json','["茆屋蕭然詩滿懷，一天風雪白皚皚。", "身如紙帳梅花夢，心似香爐柏子灰。"]'),
('4e910fa3-102a-4fdf-a3e7-044dc3f767de','曉醒追思夜來句  其三','白玉蟾','宋','宋诗','song-poetry','','[]','孤雲野鶴寄山家，不料寒空璨六花。',32,'全唐诗/poet.song.207000.json','["孤雲野鶴寄山家，不料寒空璨六花。", "越樣月明渾不夜，箇般天氣好分茶。"]'),
('95699b09-746e-41f2-932f-be7e75f63709','曉醒追思夜來句  其四','白玉蟾','宋','宋诗','song-poetry','','[]','竹林如洗靜娟娟，雪意猶酣曉色鮮。',32,'全唐诗/poet.song.207000.json','["竹林如洗靜娟娟，雪意猶酣曉色鮮。", "雲纏山腰腰带緩，雨沾水面面花圓。"]'),
('828f7825-9056-4df9-822b-cbf6ebce0363','立馬待舟','白玉蟾','宋','宋诗','song-poetry','','[]','拂曉匆匆馬首東，嫩寒初破酒無功。',32,'全唐诗/poet.song.207000.json','["拂曉匆匆馬首東，嫩寒初破酒無功。", "自知霧帽清珠濕，少立霜橋脆玉鬆。"]'),
('1620a1ab-ae2f-4aaf-bf11-d5e9a1491a5a','夕眺風泉亭  其一','白玉蟾','宋','宋诗','song-poetry','','[]','苒苒斜陽戀竹邊，秋陰慘昧響寒泉。',32,'全唐诗/poet.song.207000.json','["苒苒斜陽戀竹邊，秋陰慘昧響寒泉。", "如何今夜成無月，却遣西風一問天。"]'),
('c2cf4656-bcec-4f78-97ff-7dd19c967f18','夕眺風泉亭  其二','白玉蟾','宋','宋诗','song-poetry','','[]','拄杖相尋訪夕陽，詩肩獨聳到昏黄。',32,'全唐诗/poet.song.207000.json','["拄杖相尋訪夕陽，詩肩獨聳到昏黄。", "白蘋洲上西風起，黄葉聲中秋意長。"]'),
('cf575319-2eb4-4c35-b3e0-e7d874bed506','夕眺風泉亭  其三','白玉蟾','宋','宋诗','song-poetry','','[]','西風黄葉夕陽村，山水蒼寒霧靄昏。',32,'全唐诗/poet.song.207000.json','["西風黄葉夕陽村，山水蒼寒霧靄昏。", "手撚菊花都是淚，枯松骨立綠毛鬈。"]'),
('0a0c19d9-5197-4156-879c-0d7ce7bcedd2','鳳簫閣翫月  其一','白玉蟾','宋','宋诗','song-poetry','','[]','一醉高寒清到骨，四無塵滓月當空。',32,'全唐诗/poet.song.207000.json','["一醉高寒清到骨，四無塵滓月當空。", "光芒萬里今猶昔，牢落十年西復東。"]'),
('f637f0d4-42a9-4a13-a6ff-c6c07192def7','鳳簫閣翫月  其二','白玉蟾','宋','宋诗','song-poetry','','[]','暮靄收無歸鳥盡，鳳簫閣上聽松濤。',32,'全唐诗/poet.song.207000.json','["暮靄收無歸鳥盡，鳳簫閣上聽松濤。", "宿枝不穩鴉飛起，照水當中月上高。"]'),
('2de0792c-2a15-4df8-b6a4-4b0741a63ae4','鳳簫閣翫月  其三','白玉蟾','宋','宋诗','song-poetry','','[]','畫閣巋然百尺危，吹來花片點春衣。',32,'全唐诗/poet.song.207000.json','["畫閣巋然百尺危，吹來花片點春衣。", "黄昏璧月溪心浴，白晝銀盤水面飛。"]'),
('8b5adfd7-0c82-4d67-835c-9a42b8e428e6','鳳簫閣翫月  其四','白玉蟾','宋','宋诗','song-poetry','','[]','鳳簫吹斷無人見，但有寒光拂太虛。',32,'全唐诗/poet.song.207000.json','["鳳簫吹斷無人見，但有寒光拂太虛。", "仰面笑天天亦笑，此心如月月何如。"]'),
('dd65f7bb-0b77-4f6e-bd68-805337bea757','栩菴同步偶成','白玉蟾','宋','宋诗','song-poetry','','[]','枯木冷灰甘寂寞，片雲孤月自優游。',32,'全唐诗/poet.song.207000.json','["枯木冷灰甘寂寞，片雲孤月自優游。", "君生平事皆如夢，我兩眉間不著愁。"]'),
('dd32b06c-4049-4e56-8a94-3f0c3fbc3780','同鄧孤舟林片雪二友晚吟  其一','白玉蟾','宋','宋诗','song-poetry','','[]','扁舟如葉片帆孤，少霽臨江得句無。',32,'全唐诗/poet.song.207000.json','["扁舟如葉片帆孤，少霽臨江得句無。", "雨竹似人扶酒病，風松學我撚吟鬚。"]'),
('c4a6686f-5a13-4064-8d3e-08d895f793d6','同鄧孤舟林片雪二友晚吟  其二','白玉蟾','宋','宋诗','song-poetry','','[]','君非愛此數峰青，肯戀扁舟尚蓼汀。',32,'全唐诗/poet.song.207000.json','["君非愛此數峰青，肯戀扁舟尚蓼汀。", "群鴈橫空成一字，孤螢度水似雙星。"]'),
('6b82920f-0ae0-4a2e-953c-df9662ec1ac7','同鄧孤舟林片雪二友晚吟  其三','白玉蟾','宋','宋诗','song-poetry','','[]','江天漠漠但黄蘆，鴈鶩相呼日已晡。',32,'全唐诗/poet.song.207000.json','["江天漠漠但黄蘆，鴈鶩相呼日已晡。", "雨過月如全趙璧，烟深山似紿秦圖。"]'),
('4816d8c4-dc35-4f9e-a6ae-4c9671468704','上元翫燈  其一','白玉蟾','宋','宋诗','song-poetry','','[]','碧玉融成萬里天，滿城羅綺競春妍。',32,'全唐诗/poet.song.207000.json','["碧玉融成萬里天，滿城羅綺競春妍。", "柳梢掛月黄昏後，夜市張燈白晝然。"]'),
('ca9193da-049e-4b0c-9813-0931a9de94d1','上元翫燈  其二','白玉蟾','宋','宋诗','song-poetry','','[]','上界天官此按行，五雲深處有簫笙。',32,'全唐诗/poet.song.207000.json','["上界天官此按行，五雲深處有簫笙。", "一輪寶月明如晝，萬斛金蓮開滿城。"]'),
('7622a6ca-82cf-43ee-866d-d5f6d200afb9','寄王察院  其一','白玉蟾','宋','宋诗','song-poetry','','[]','不讀儒書讀道書，故人聽我自江湖。',32,'全唐诗/poet.song.207000.json','["不讀儒書讀道書，故人聽我自江湖。", "君今一武登臺省，我亦三清直殿廬。"]'),
('fb9a89ea-101f-4849-bc41-476fc0254e8f','寄王察院  其二','白玉蟾','宋','宋诗','song-poetry','','[]','恩怨榮污總不知，片雲隻鶴久相期。',32,'全唐诗/poet.song.207000.json','["恩怨榮污總不知，片雲隻鶴久相期。", "驅磨花月三千界，斷送風波十二時。"]'),
('d15008ed-cfc9-42ee-87ae-374c24711fea','寄王察院  其三','白玉蟾','宋','宋诗','song-poetry','','[]','黄金臺逈鴛鴻集，碧玉壺深日月長。',32,'全唐诗/poet.song.207000.json','["黄金臺逈鴛鴻集，碧玉壺深日月長。", "大隠從來在朝市，謫仙况復富文章。"]'),
('b773c0f8-b19a-4ad5-84a0-8cde8c87e336','新正  其一','白玉蟾','宋','宋诗','song-poetry','','[]','九天日月開黄道，十洞烟霞接紫清。',32,'全唐诗/poet.song.207000.json','["九天日月開黄道，十洞烟霞接紫清。", "爲問蟠桃當熟未，人間春草幾枯榮。"]'),
('13b077de-ef9a-43df-b55f-889cac2763f8','新正  其二','白玉蟾','宋','宋诗','song-poetry','','[]','九重天上星三點，萬頃波心月一鈎。',32,'全唐诗/poet.song.207000.json','["九重天上星三點，萬頃波心月一鈎。", "醉有百篇來筆下，愁無半點到眉頭。"]'),
('b5fed381-10c8-4e97-87f1-929a73747d29','新正  其三','白玉蟾','宋','宋诗','song-poetry','','[]','一番桃李又春風，送古迎今事不窮。',32,'全唐诗/poet.song.207000.json','["一番桃李又春風，送古迎今事不窮。", "南北故人鴻去外，東西野渡雪晴中。"]'),
('a309d3e8-6c5e-47e1-85bc-52aa3ebacac5','張樓','白玉蟾','宋','宋诗','song-poetry','','[]','前度相逢一似曾，瘦寬金鐲可憐生。',32,'全唐诗/poet.song.207000.json','["前度相逢一似曾，瘦寬金鐲可憐生。", "綠窗朱戶如無恙，酌我百杯秋月明。"]'),
('618ea343-e687-4e5f-904d-8eb1b6921fdd','中秋','白玉蟾','宋','宋诗','song-poetry','','[]','風卷青天落大江，江風江水自舂撞。',32,'全唐诗/poet.song.207000.json','["風卷青天落大江，江風江水自舂撞。", "萬千人看中秋月，十二樓開八面窗。"]'),
('4d3f745a-87a8-451b-a700-754375488bd7','董樓','白玉蟾','宋','宋诗','song-poetry','','[]','文章道德今誰似，事業功名我不無。',32,'全唐诗/poet.song.207000.json','["文章道德今誰似，事業功名我不無。", "十載江湖一杯酒，夜深說與董歸奴。"]'),
('7332b92b-55af-4ee5-b830-4e9f115e594f','對月  其一','白玉蟾','宋','宋诗','song-poetry','','[]','深秋荷敗柳枯時，霜蟹香棖副所思。',32,'全唐诗/poet.song.207000.json','["深秋荷敗柳枯時，霜蟹香棖副所思。", "月要人窺嬌不上，風知我醉放多吹。"]'),
('2bd783a9-f2ee-4d97-a0c6-8b0ea1613558','對月  其二','白玉蟾','宋','宋诗','song-poetry','','[]','醉袖舞低千嶂月，清歌遏住九天雲。',32,'全唐诗/poet.song.207000.json','["醉袖舞低千嶂月，清歌遏住九天雲。", "鴻歸燕去傷秋老，鶴唳猿啼覺夜分。"]'),
