('efdf9ef7-9fe8-4f29-815d-cdeb6dff3af7','春雨','白玉蟾','宋','宋诗','song-poetry','','[]','柳色烟光正鬭青，桃花落盡杏花驚。',32,'全唐诗/poet.song.207000.json','["柳色烟光正鬭青，桃花落盡杏花驚。", "風從窗眼空中入，雨在簷前滴到明。"]'),
('f13bf148-5bec-467e-8cf2-2985fa9496a7','春興  其一','白玉蟾','宋','宋诗','song-poetry','','[]','草根未放曉霜稀，驟冷初暄蝶倦飛。',32,'全唐诗/poet.song.207000.json','["草根未放曉霜稀，驟冷初暄蝶倦飛。", "行到碧桃花下看，新花良是舊枝非。"]'),
('ed735f3d-105b-4234-8ff4-a3df21ef3490','春興  其二','白玉蟾','宋','宋诗','song-poetry','','[]','未忺盥櫛且看雲，空翠濛濛霽色分。',32,'全唐诗/poet.song.207000.json','["未忺盥櫛且看雲，空翠濛濛霽色分。", "日線穿窗蜂透出，隔窗花影動欣欣。"]'),
('e853d372-dd84-43e7-b383-d4387301b191','春興  其三','白玉蟾','宋','宋诗','song-poetry','','[]','茜草葉交萱草葉，桃花枝映李花枝。',32,'全唐诗/poet.song.207000.json','["茜草葉交萱草葉，桃花枝映李花枝。", "餿風餕雨休相惱，放我水邊林下嬉。"]'),
('7bd9ac00-dac0-4c81-9a44-26978d5c0b00','春興  其四','白玉蟾','宋','宋诗','song-poetry','','[]','曉日激昂山吐霧，東風從臾水生波。',32,'全唐诗/poet.song.207000.json','["曉日激昂山吐霧，東風從臾水生波。", "燕纔邂逅鶑相款，花自將迎蝶見過。"]'),
('dca45617-b657-46ab-ad6f-0aa0a8e18226','春興  其五','白玉蟾','宋','宋诗','song-poetry','','[]','細雨如毛暮靄濃，山光水色醉春空。',32,'全唐诗/poet.song.207000.json','["細雨如毛暮靄濃，山光水色醉春空。", "認來認去燕還舍，吹落吹開花使風。"]'),
('cdf675c0-3b89-4693-8d83-707a65720661','春興  其六','白玉蟾','宋','宋诗','song-poetry','','[]','望中白鳥入空無，一带青山似畫圖。',32,'全唐诗/poet.song.207000.json','["望中白鳥入空無，一带青山似畫圖。", "宿雨初醒雲半斂，垂楊微困水平鋪。"]'),
('68e2ff6c-9619-4bef-9037-594723bfcbd9','春興  其七','白玉蟾','宋','宋诗','song-poetry','','[]','嬌煙嫩靄弄晴暉，誰見詩人太息時。',32,'全唐诗/poet.song.207000.json','["嬌煙嫩靄弄晴暉，誰見詩人太息時。", "風主庭前花壽夭，水占溪上柳安危。"]'),
('6388fd8a-640b-4b44-a6ed-0083a3c30614','晚春遣興二絕  其一','白玉蟾','宋','宋诗','song-poetry','','[]','不但風饕雨更尤，落英滿地訴春愁。',32,'全唐诗/poet.song.207000.json','["不但風饕雨更尤，落英滿地訴春愁。", "詩人分韻留春處，一句韓詩七箇鬮。"]'),
('b6617cbb-ceac-42c3-8493-842be25c13e2','晚春遣興二絕  其二','白玉蟾','宋','宋诗','song-poetry','','[]','臨臨春去却成晴，花落無聲片片輕。',32,'全唐诗/poet.song.207000.json','["臨臨春去却成晴，花落無聲片片輕。", "一句杜鵑香國淚，半簾皓月故人情。"]'),
('59c698a8-5ab9-4816-b9bd-826d05942c4c','春夕與西林老月下坐  其一','白玉蟾','宋','宋诗','song-poetry','','[]','燕子呢喃君得知，深談實相妙難思。',32,'全唐诗/poet.song.207000.json','["燕子呢喃君得知，深談實相妙難思。", "久參貝葉云何梵，一見桃花更不疑。"]'),
('e0939e4f-a279-4dab-ba94-6bc65282b8b4','春夕與西林老月下坐  其二','白玉蟾','宋','宋诗','song-poetry','','[]','一物言無也大奇，如何半夜却傳衣。',32,'全唐诗/poet.song.207000.json','["一物言無也大奇，如何半夜却傳衣。", "於知見處生知見，在是非中起是非。"]'),
('5c572b6e-ee87-4ecc-bc81-3a2c1086558c','竹園  其一','白玉蟾','宋','宋诗','song-poetry','','[]','可惜洋州不再生，此君只許伯夷清。',32,'全唐诗/poet.song.207000.json','["可惜洋州不再生，此君只許伯夷清。", "霜刪近覺林方瘦，笋礙渾無路得行。"]'),
('443ea23c-f9b0-4898-836b-09775ade8ae2','竹園  其二','白玉蟾','宋','宋诗','song-poetry','','[]','一片琅玕香浄天，風吹細細雨娟娟。',32,'全唐诗/poet.song.207000.json','["一片琅玕香浄天，風吹細細雨娟娟。", "龍孫始學斑衣戲，鶖子從談玉版禪。"]'),
('2135b1a2-7a4f-4095-b754-5520151a56a8','竹園  其三','白玉蟾','宋','宋诗','song-poetry','','[]','自笑園丁職事新，一春風雨爲供申。',32,'全唐诗/poet.song.207000.json','["自笑園丁職事新，一春風雨爲供申。", "笋如滕薛皆爭長，瓜似朱陳已結親。"]'),
('0b0b3ca0-c20e-4fd9-92c2-353b3663cb9d','菜羹','白玉蟾','宋','宋诗','song-poetry','','[]','一卷仙家煮菜經，宰夫失笑太官驚。',32,'全唐诗/poet.song.207000.json','["一卷仙家煮菜經，宰夫失笑太官驚。", "藍田山裏空餐玉，豈識聞韶別是清。"]'),
('8c249c54-7c3c-4115-903a-c4edb2b1c0d4','扇','白玉蟾','宋','宋诗','song-poetry','','[]','懷袖相忘去不能，也知輕薄惡蚊蠅。',32,'全唐诗/poet.song.207000.json','["懷袖相忘去不能，也知輕薄惡蚊蠅。", "南風雖汝持權柄，只恐秋風見汝憎。"]'),
('630a56b1-71f2-4b9b-bd53-ebb2a9b3bee2','山歌','白玉蟾','宋','宋诗','song-poetry','','[]','幾家娘子守黄昏，多少郎君醉打門。',32,'全唐诗/poet.song.207000.json','["幾家娘子守黄昏，多少郎君醉打門。", "睡了不知明月好，三更三點似金盆。"]'),
('27b8c9b7-e6d2-4674-bb16-b72ed41b0a22','與趙將軍  其一','白玉蟾','宋','宋诗','song-poetry','','[]','見君除授千牛貴，過眼光榮一蠓微。',32,'全唐诗/poet.song.207000.json','["見君除授千牛貴，過眼光榮一蠓微。", "人爵未如天爵美，脂韋只道布韋非。"]'),
('fc1dad64-2e21-468c-9b7b-32be44a7436a','與趙將軍  其二','白玉蟾','宋','宋诗','song-poetry','','["\u592a\u6e56"]','醉頭一月不曾梳，共整扁舟又太湖。',32,'全唐诗/poet.song.207000.json','["醉頭一月不曾梳，共整扁舟又太湖。", "昔日舞雩多一唯，他人陋巷只如愚。"]'),
('14c508c4-083b-4b1b-8278-0511ea2143c1','與趙將軍  其三','白玉蟾','宋','宋诗','song-poetry','','[]','芒鞋布襪與青藜，朝市迷心忽幾時。',32,'全唐诗/poet.song.207000.json','["芒鞋布襪與青藜，朝市迷心忽幾時。", "料得山中猿鶴冷，多應相怨不相思。"]'),
('6b50ea65-ffed-4037-ae38-6deaaaa1a2db','瑶臺散天花詞  其一','白玉蟾','宋','宋诗','song-poetry','','[]','夜半泠然御八風，下觀四海氣濛濛。',32,'全唐诗/poet.song.207000.json','["夜半泠然御八風，下觀四海氣濛濛。", "舉頭忽已三更上，上有瓊樓十二重。"]'),
('04411647-cb04-4306-832f-540e10cddaac','瑶臺散天花詞  其二','白玉蟾','宋','宋诗','song-poetry','','[]','諸天綵女一雙雙，十二樓前並捧香。',32,'全唐诗/poet.song.207000.json','["諸天綵女一雙雙，十二樓前並捧香。", "太乙真人乘白鶴，雲中端簡候虛皇。"]'),
('50250961-7475-4fcc-a0f3-a4ecf9df9e00','瑶臺散天花詞  其三','白玉蟾','宋','宋诗','song-poetry','','[]','翠幢絳節忽紛紛，空裏笙簫節奏聞。',32,'全唐诗/poet.song.207000.json','["翠幢絳節忽紛紛，空裏笙簫節奏聞。", "碧玉宮中花似雪，蘂珠殿下鶴如雲。"]'),
('92d19a7e-624d-4c95-942b-5822a900c024','竹裏桃花','白玉蟾','宋','宋诗','song-poetry','','[]','風吹雨洗玉猗猗，雲捲霞舒錦陸離。',32,'全唐诗/poet.song.207000.json','["風吹雨洗玉猗猗，雲捲霞舒錦陸離。", "竹夾桃花花映竹，雅如翠障綉西施。"]'),
('d43d82bf-7ebc-401a-bb6e-d523c3cd8d51','水糰','白玉蟾','宋','宋诗','song-poetry','','[]','火宅煎熬不自由，就中澇漉幾沉浮。',32,'全唐诗/poet.song.207000.json','["火宅煎熬不自由，就中澇漉幾沉浮。", "翻身得入清凉國，也合甘心喫水休。"]'),
('fe04436d-149f-475a-8aaf-5802c6c0b5e1','煙中梅花','白玉蟾','宋','宋诗','song-poetry','','[]','煙裏梅花別是清，略無風動亦寒馨。',32,'全唐诗/poet.song.207000.json','["煙裏梅花別是清，略無風動亦寒馨。", "如焚古鼎龍涎餠，坐對幽窗水墨屏。"]'),
('e92fde49-3911-4aea-8c8e-e833a54279c6','湖上偶成  其一','白玉蟾','宋','宋诗','song-poetry','','[]','葭蒲滿蕩起晴烟，總屬霜鷗雪鷺天。',32,'全唐诗/poet.song.207000.json','["葭蒲滿蕩起晴烟，總屬霜鷗雪鷺天。", "一片紫菱開十字，中間放過采蓮船。"]'),
('5829218a-f58c-4e27-833c-4570defe9c1c','湖上偶成  其二','白玉蟾','宋','宋诗','song-poetry','','[]','湖天清曠萬緣虛，暫借僧房作宰予。',32,'全唐诗/poet.song.207000.json','["湖天清曠萬緣虛，暫借僧房作宰予。", "夢覺風凉歸去晚，滿空飛翠撲籃輿。"]'),
('8ebff98f-ea10-4054-9ee9-9c84a2fcdce6','睡起','白玉蟾','宋','宋诗','song-poetry','','[]','清似垂竿釣楚江，酒兵已退睡魔降。',32,'全唐诗/poet.song.207000.json','["清似垂竿釣楚江，酒兵已退睡魔降。", "霜風吹破梅花曉，霧月飛浮竹影窗。"]'),
('97cc902a-bfa5-49f6-919e-5c841af1a209','次韻王御带','白玉蟾','宋','宋诗','song-poetry','','[]','曉風吹醒桃花醉，暮雨添成柳葉愁。',32,'全唐诗/poet.song.207000.json','["曉風吹醒桃花醉，暮雨添成柳葉愁。", "醉了又愁愁又醉，鶑煎燕𠿕過春休。"]'),
('5facf654-9c1e-4c6e-aed7-78e851d8fb4d','徐處士寫予真','白玉蟾','宋','宋诗','song-poetry','','[]','心潛天地笑藏春，月珮雲衿絕一塵。',32,'全唐诗/poet.song.207000.json','["心潛天地笑藏春，月珮雲衿絕一塵。", "前世率陀天上客，今生大宋國中身。"]'),
('44806390-c4d0-4602-ab6e-20c983ff7a70','次韻曾丈探梅','白玉蟾','宋','宋诗','song-poetry','','[]','夜半風吹雪滿階，頭巾不裹把窗開。',32,'全唐诗/poet.song.207000.json','["夜半風吹雪滿階，頭巾不裹把窗開。", "南枝暗就江頭發，一點香從月下來。"]'),
('10a98030-bc95-46c6-b2ce-fbd8691c77fe','紅梅  其一','白玉蟾','宋','宋诗','song-poetry','','[]','明皇愛雪響雲營，侍宴宮娃不計名。',32,'全唐诗/poet.song.207000.json','["明皇愛雪響雲營，侍宴宮娃不計名。", "守等太真眠未起，醺然秉燭到深更。"]'),
('4cef7904-47ad-40bb-8861-a4371a43f6cd','紅梅  其二','白玉蟾','宋','宋诗','song-poetry','','[]','玉妃初醉下瑶臺，紫霧深深撥不開。',32,'全唐诗/poet.song.207000.json','["玉妃初醉下瑶臺，紫霧深深撥不開。", "却恐錯穿桃杏徑，高燒銀燭照歸來。"]'),
('96153aac-d35b-446a-a159-744d7b58a618','題武夷  其一','白玉蟾','宋','宋诗','song-poetry','','[]','不見虹橋接幔亭，空餘水綠與山青。',32,'全唐诗/poet.song.207000.json','["不見虹橋接幔亭，空餘水綠與山青。", "客來剔出些奇勝，五曲溪頭大隠屏。"]'),
('5d66553f-034f-40e9-a57c-815f272e78cf','題武夷  其二','白玉蟾','宋','宋诗','song-poetry','','[]','龍驤仙掌岩頭水，鶴唳幔亭峰上雲。',32,'全唐诗/poet.song.207000.json','["龍驤仙掌岩頭水，鶴唳幔亭峰上雲。", "但得明窗塵一匕，躍身去謁武夷君。"]'),
('21505291-ece5-4f85-a63d-6d1192724a48','題武夷  其三','白玉蟾','宋','宋诗','song-poetry','','[]','芳草暗分流水綠，老松剛借遠山青。',32,'全唐诗/poet.song.207000.json','["芳草暗分流水綠，老松剛借遠山青。", "獨拈鐵笛溪頭立，吹與洞中仙子聽。"]'),
('0b0b7fc7-138d-4cec-8e85-513feb1d088e','題武夷  其四','白玉蟾','宋','宋诗','song-poetry','','[]','顯道真人去不回，幔亭不見舊樓臺。',32,'全唐诗/poet.song.207000.json','["顯道真人去不回，幔亭不見舊樓臺。", "曾孫倚著寒松立，日落風悲猿自哀。"]'),
('4a2812e1-43ec-4a36-ae1b-dd7dccff5094','題武夷  其五','白玉蟾','宋','宋诗','song-poetry','','[]','山聳千層青翡翠，溪流萬頃碧琉璃。',32,'全唐诗/poet.song.207000.json','["山聳千層青翡翠，溪流萬頃碧琉璃。", "遊人來此醉歸去，幾箇親曾到武夷。"]'),
('2f302178-f504-41be-a502-511a78e7e004','旴江舟中聯句','白玉蟾','宋','宋诗','song-poetry','','[]','倏忽僧千兔，尋常涸百蠡。',288,'全唐诗/poet.song.207000.json','["倏忽僧千兔，尋常涸百蠡。", "眼光摩日月，足跡遍山河。", "赤壁聊化鶴，黄庭浪換鵝。", "秋聲歸欵乃，雲影映婆娑。", "夜後調焦尾，風前舞太阿。", "待藏班婕扇，却援魯陽戈。", "點爾言其志，虞兮奈若何。", "道緣寧擇地，世事總隨波。", "萬象由彈壓，千篇在切磋。", "酒徒從狎至，詩客聽相過。", "輟我芒不借，就伊金叵羅。", "峯巔餐地秀，霞外挹天和。", "拍手僛僛舞，忘形踏踏歌。", "力辭金殿客，高應玉皇科。", "八桂招六逸，九疑哀兩娥。", "清漪馴綠鴨，列阜拊眠駝。", "逸韻應無敵，清名到不毛。", "樵仙分我席，力士汙吾靴。", "風沈腰何束，霜潘鬢謾皤。", "懷丹醫病鶴，尋餌釣神鼇。", "爲問六國印，何如一漁簑。", "清飈茶腋爽，韶景醉顔酡。", "且噉藕如臂，從教晷似梭。", "推蓬延月桂，引襋翫煙蘿。"]'),
('b675908c-2919-4d04-a824-184689801fde','南臺舟中聯句','白玉蟾','宋','宋诗','song-poetry','','[]','秋陽紅若柿，曉雨翠如絲。',72,'全唐诗/poet.song.207000.json','["秋陽紅若柿，曉雨翠如絲。", "福地逢迎日，江天笑傲時。", "蓮臙猶殢水，桂粟已粘枝。", "波靜天一色，山低雲四垂。", "垂綸懷渭叟，縱棹擬鴟夷。", "上水遲吾樂，西風壯我詩。"]'),
('ba5e2c94-4033-4b2b-b381-664acc183bfd','疎山舟中聯句','白玉蟾','宋','宋诗','song-poetry','','[]','山影卧寒碧，波光摇虛空。',96,'全唐诗/poet.song.207000.json','["山影卧寒碧，波光摇虛空。", "櫂凌千頃月，帆鼓一天風。", "列岸萬絲柳，遥岑數粒松。", "詩魂混鴈鶩，草聖驚魚龍。", "夢斷江樓笛，吟餘煙寺鍾。", "電華飛我劍，虹暈掛吾弓。", "清嘯騎汗漫，朗吟泛冥濛。", "誰云澤國小，樂亦在其中。"]'),
('ec937a0f-50aa-4bed-a35c-5f15d99a4f77','泊舟浮石寺前有善士百餘輩拜迎因聯句于水濱民居之壁','白玉蟾','宋','宋诗','song-poetry','','[]','三百六旬周復始，二十四巖高且寒。',64,'全唐诗/poet.song.207000.json','["三百六旬周復始，二十四巖高且寒。", "法乳試流鋒上蜜，詩腸畧露管中班。", "山山日脚黄金軟，片片梅心白雪乾。", "遥指煙霄呼縞鶴，一聲清嘯水雲閑。"]'),
('2f547b32-2f24-47e7-b08a-83b60ad62798','冬日同王茂翁聯句','白玉蟾','宋','宋诗','song-poetry','','[]','鑿冰添硯水，燃幹發梅花。',144,'全唐诗/poet.song.207000.json','["鑿冰添硯水，燃幹發梅花。", "踏破霜苔逕，燒紅雪樹槎。", "閉門風愈怒，送客日將斜。", "寒甚酒無力，閑多道有芽。", "楮衾眠不暖，葦壁破難遮。", "他日瑶臺上，流傳仙子家。", "風箭射壁縫，寒稜入被單。", "幽棲悄無夢，神思靜常安。", "紙帳懸冰簾，霜華結玉盤。", "窗外竹敲竹，壇前旛動旛。", "青燈寒燄短，紅炭冷灰殘。", "暗香何處梅，徹夜相檀欒。"]'),
('6dfb58a8-1d7e-47fb-8c42-5f826c7e7ccd','燈花聯句','白玉蟾','宋','宋诗','song-poetry','','[]','青燈知有喜，花發滿堂紅。',168,'全唐诗/poet.song.207000.json','["青燈知有喜，花發滿堂紅。", "寶餠攢金蟻，瓊釵綴玉蟲。", "根非滋夜雨，蘂不綻春風。", "照破乾坤事，能攘日月功。", "燄凝中夜露，燼落五更鍾。", "蟾桂光無比，冰花巧不同。", "無香開瑞瓣，有燄似珍叢。", "鵲噪歡娛定，蛛絲信息通。", "今宵真有感，好事喜相逢。", "不假金烏照，應非玉斧工。", "草蟲空亂樹，野燐謾枮蓬。", "蛾至渾疑蝶，蛟飛不是蜂。", "酒親思杜老，詩詠憶韓公。", "不昧本來者，孤光曜太空。"]'),
('ad83eb5f-7808-4572-94f6-4e0a9500fda1','雪窗聯句','白玉蟾','宋','宋诗','song-poetry','','[]','霜風寒襲人，梅香清透骨。',252,'全唐诗/poet.song.207000.json','["霜風寒襲人，梅香清透骨。", "莫色冥九峯，月華澹雙闕。", "青猿嘯蒼虬，紅螢粘綠髮。", "滕六欲飛花，巽二急催雪。", "爐烹獸炭紅，簾捲鴛羅纈。", "更燒古龍涎，滿斟清鳳血。", "堆盤老榛栗，託契舊瓜葛。", "笑揮白玉麈，共說丹砂訣。", "飄飄志欲仙，酣酣耳正熱。", "松鶴警清露，煙麋卧蒼樾。", "一鴈過天外，孤鵲遶木末。", "隠約銀漢星，微芒翠杉月。", "燭花凍不淚，火柿撥欲滅。", "回首顧壁影，開懷吐談屑。", "結習三生路，慷慨萬人傑。", "聚散如浮萍，死生猶幻沫。", "萬事一置之，四皓不渠劣。", "夜深尸泣鬼，歲晚霜摩鶻。", "泉涸水涯涘，雲渺天空闊。", "餓鼠齧枯藤，凍蠅棲瑣闥。", "觴詠興未闌，烘堂各粲發。"]'),
('7c23fca7-eb80-4946-bce9-f29997342121','櫂歌聯句','白玉蟾','宋','宋诗','song-poetry','','[]','西風起兮，落葉黄兮，黍稷香兮。',60,'全唐诗/poet.song.207000.json','["西風起兮，落葉黄兮，黍稷香兮。", "擊空明兮，泝流光兮，天一方兮。", "彼美人兮，遥相望兮，彼蒼茫兮。", "繫孤舟兮，蓼花傍兮，啼寒螿兮。"]'),
('40656bc4-b4ba-4741-8e46-7d874564ca91','道中與謝紫壺聯句','白玉蟾','宋','宋诗','song-poetry','','[]','陰晴荏苒風吹霜，山北山南稻正黄。',64,'全唐诗/poet.song.207000.json','["陰晴荏苒風吹霜，山北山南稻正黄。", "照澗芙蓉何綽約，掠雲鴻鵠向微茫。", "心同秋水與天遠，夜折巖花和月香。", "嶺海青紅俱在目，先隨夕照入詩腸。"]'),
('a5efa763-4a28-4665-b279-7bb4e6827046','戲聯食𩻣體取其骨糜肉化之義','白玉蟾','宋','宋诗','song-poetry','','[]','何其秀且明，而况清以美。',96,'全唐诗/poet.song.207000.json','["何其秀且明，而况清以美。", "不醉將如何，無吟詎自已。", "凡與共此者，但須行樂耳。", "無意固必我，可久速仕止。", "離合忍復道，光陰能有幾。", "相對默不言，新篘多且旨。", "玄中難致詰，聖處可勝紀。", "何爲是栖栖，未免聊復爾。"]'),
('d6cf4c20-f056-4ef9-9a69-755354a904e8','戲聯仄字體','白玉蟾','宋','宋诗','song-poetry','','[]','一雨倏復霽，旱魃已退壘。',48,'全唐诗/poet.song.207000.json','["一雨倏復霽，旱魃已退壘。", "遠水白浩蕩，列岫翠迤邐。", "古磧纏荇带，宿鷺戀荻米。", "搦笛叫月姊，伴我啜綠蟻。"]'),
('2f0c9d80-2d7b-40f9-9dfb-a6a0a7918c84','戲聯平字體','白玉蟾','宋','宋诗','song-poetry','','[]','西風來無邊，松聲填虛空。',48,'全唐诗/poet.song.207000.json','["西風來無邊，松聲填虛空。", "晴雲飛瀰漫，凉蟾光玲瓏。", "揮觥奔長鯨，憑欄窮冥鴻。", "詩成摛霜毫，吹噓呈天公。"]'),
('42da4b54-140f-49d1-ae37-a5d2fd5ab9be','戲聯疊韻體','白玉蟾','宋','宋诗','song-poetry','','[]','兩槳往莽蒼，弓蓬窮空濛。',48,'全唐诗/poet.song.207000.json','["兩槳往莽蒼，弓蓬窮空濛。", "傴僂苦怒雨，穹窿通雄風。", "美茝迤邐紫，叢楓朦朧紅。", "彼美綺里子，終同隆中翁。"]'),
('78375cb2-ab5d-4b98-a0ca-df491dcf4b2e','戲聯回文體','白玉蟾','宋','宋诗','song-poetry','','[]','水連天渺渺，山映月亭亭。',48,'全唐诗/poet.song.207000.json','["水連天渺渺，山映月亭亭。", "尾櫂依鳬渚，頭船過蓼汀。", "鬼神號暝壑，煙霧靄疎櫺。", "美醖浮觴玉，輕衣拂劍星。"]'),
('caf4d048-9767-4502-82f2-403c7fabaaf4','夜船與盤雲聯句回文','白玉蟾','宋','宋诗','song-poetry','','[]','烟山暮滴翠，露葉秋翻紅。',48,'全唐诗/poet.song.207000.json','["烟山暮滴翠，露葉秋翻紅。", "川急回斜岸，草枯凋薄霜。", "蟬寒嘶月淡，鴈過唳天長。", "船泊宜沙浦，夜深同詠觴。"]'),
('f72ab593-d550-4636-bcd6-661851a757bf','潘紫巖與余賦雪約不得用色數并實字及比喻','白玉蟾','宋','宋诗','song-poetry','','[]','不似尋常凍，俄而散漫飛。',144,'全唐诗/poet.song.207000.json','["不似尋常凍，俄而散漫飛。", "羞明猶欲落，等伴未全晞。", "承得圓還碎，看來是復非。", "積深仍密密，舞急轉霏霏。", "弗是篩成細，何如拾取歸。", "今焉皆璀璨，昨者只浽𧇠。", "掃去依元有，呵來忽漸微。", "亂飄寒轉甚，相映遠生輝。", "莫踏凹中滿，遥知凸處肥。", "嚴凝吟不厭，凜冽飲無威。", "賞翫真堪樂，豐穰不用祈。", "嬋娟雖可待，融散恐幾希。"]'),
('d2f70c44-4b78-411f-82ec-68b14eb5e6d5','疊字招隠  其一','白玉蟾','宋','宋诗','song-poetry','','[]','逐逐何時知足。',127,'全唐诗/poet.song.207000.json','["逐逐何時知足。", "來歸山，共種菊。", "有松爲酒，有藜當肉。", "亦有澗底芝，亦有巖上瀑。", "白日自覺如年，青山長是對目。", "閑雲與充封門人，清風爲作掃室僕。", "朝宴息乎長松之陰，夜偃仰乎冷翠之谷。", "我無涕唾津精氣血液，了絕喜怒哀樂愛惡欲。", "練空碧毓紫沖兮身如玉，乘氣御飛兮詠九霞之曲。"]'),
('83fa4473-a01b-4c83-8bc6-83fa0ba82826','疊字招隠  其二','白玉蟾','宋','宋诗','song-poetry','','[]','逐逐且貪怎足。',127,'全唐诗/poet.song.207000.json','["逐逐且貪怎足。", "戀松楸，愛蓮菊。", "食玉衣錦，池酒林肉。", "甕埋地閣鍾，月瀉天窗瀑。", "鄭衛殆塞其聰，趙燕可盲其目。", "鏡盟釵詛謾交交，馬跡車塵何僕僕。", "名傷神兮寵辱若驚，事掣肘兮進退惟谷。", "一真妄兮故知空不空，觀徼妙兮常有欲無欲。", "吾將先天後天明月之珠，裁作左仙右仙賓雲之曲。"]'),
('1f2cc522-865f-4781-a6b0-7d840c54d7f8','紫溪偶成回文體','白玉蟾','宋','宋诗','song-poetry','','[]','鸝黄並柳風飄絮，蝶粉粘花露浥香。',32,'全唐诗/poet.song.207000.json','["鸝黄並柳風飄絮，蝶粉粘花露浥香。", "離別恨深深院靜，少年人去去途長。"]'),
('9bc9aea4-99e1-4407-a2f4-ac63d9c3ab40','集句贈王秀才','白玉蟾','宋','宋诗','song-poetry','','[]','富貴必從勤苦得，名位豈肯卑微休。',32,'全唐诗/poet.song.207000.json','["富貴必從勤苦得，名位豈肯卑微休。", "勸君更盡一杯酒，與爾同銷萬古愁。"]'),
('126f0e3e-df74-4d8e-87e7-47781ae5cb1e','玉真瑞世頌','白玉蟾','宋','宋诗','song-poetry','','[]','西華王母，紫虛元君。',240,'全唐诗/poet.song.207000.json','["西華王母，紫虛元君。", "咀嚼九日，偃仰三雲。", "毛竹秦娥，簫臺周女。", "夜騎天風，曉詣帝所。", "琪花開盛，鳳鳥歌雍。", "霞旌舞翠，煙幢麗空。", "金莖露飛，玉樹月淡。", "蒼苔丹墀，紅藥宋檻。", "北斗后德，陽春母儀。", "飈乘鶴驅，霓裳羽衣。", "懿淑靖都，恭柔慧閑。", "金玉淵海，瓊瑶丘山。", "聖學光明，寶翰芳美。", "四海歌謠，關雎麟趾。", "仙儀沖粹，道性熙怡。", "福祿來爲，葛藟螽斯。", "金鼎凝霜，玉爐煅月。", "芝田黄芽，桂館白雪。", "青鳥不至，翠蓬忘歸。", "玉真瑞世，吾教光輝。", "詳延方士，酬酢道要。", "營魄守雌，玄牝觀妙。", "廣寒兔老，衡嶽松青。", "至尊萬壽，永保坤寧。"]'),
('2a7ea01e-da86-4d76-9522-af8c3bc1b95f','鶴林傳法明心頌','白玉蟾','宋','宋诗','song-poetry','','[]','萬法從心生，心心即是法。',96,'全唐诗/poet.song.207000.json','["萬法從心生，心心即是法。", "語嘿與動靜，皆法所使然。", "無疑是真心，守一是正法。", "守一而無疑，法法皆心法。", "法是心之臣，心是法之主。", "無疑則心正，心正則法靈。", "守一則心專，心專則法驗。", "非法之靈驗，蓋汝心所以。"]'),
('ac78920f-0a1b-46b1-8786-a09d831c3000','狗子佛性頌','白玉蟾','宋','宋诗','song-poetry','','[]','雨過西風寒，蒼苔封戰骨。',24,'全唐诗/poet.song.207000.json','["雨過西風寒，蒼苔封戰骨。", "可憐老將軍，飲馬長城窟。"]'),
('bacb9951-7223-4531-9066-9cf5a6544eff','李伯陽贊  其一','白玉蟾','宋','宋诗','song-poetry','','[]','三花聚頂，五氣朝元。',20,'全唐诗/poet.song.207000.json','["三花聚頂，五氣朝元。", "入衆妙門，玄之又玄。"]'),
('f220f874-2c65-439f-ada8-e3dd09730d7e','李伯陽贊  其二','白玉蟾','宋','宋诗','song-poetry','','[]','道是太乙元君，又是河上丈人。',28,'全唐诗/poet.song.207000.json','["道是太乙元君，又是河上丈人。", "渺渺太清之境，巍然道德之身。"]'),
('3b7609e0-efc4-4824-865f-f8c8dcc657cf','李伯陽贊  其三','白玉蟾','宋','宋诗','song-poetry','','[]','蓬萊三萬里，道德五千言。',24,'全唐诗/poet.song.207000.json','["蓬萊三萬里，道德五千言。", "一自青牛去，函關烟雨昏。"]'),
('06eee90f-eb5f-4352-890f-e15b91d5213f','高祖聖師天台紫陽真人贊','白玉蟾','宋','宋诗','song-poetry','','[]','元豐一皂吏，三番遭配隸。',24,'全唐诗/poet.song.207000.json','["元豐一皂吏，三番遭配隸。", "空餘悟真篇，带些鉛汞氣。"]'),
('a22fc201-e92e-4ed0-8059-b1dbca1b6306','曾祖聖師真一還源真人贊','白玉蟾','宋','宋诗','song-poetry','','[]','杏林驛，雪之夕。',31,'全唐诗/poet.song.207000.json','["杏林驛，雪之夕。", "老師張，弟子石。", "凜凜清風生八極，那些兒消一滴。"]'),
('661914c0-b04e-4d0e-95a6-4931db4f1caf','師祖雞足紫賢真人贊','白玉蟾','宋','宋诗','song-poetry','','[]','禿頭儉相，做盡模樣。',34,'全唐诗/poet.song.207000.json','["禿頭儉相，做盡模樣。", "張平叔若不再來，石得之不成信向。", "你即是道光和尚。"]'),
('3349d085-d4cb-4560-9dde-83bf08b4b183','先師翠虛泥丸真人贊','白玉蟾','宋','宋诗','song-poetry','','[]','惠州是生緣，嘉州是得遇。',24,'全唐诗/poet.song.207000.json','["惠州是生緣，嘉州是得遇。", "漳州走落水，潭州沒去處。"]'),
('3773151a-878d-43b9-b0ae-62c16a358ed1','虛靖先生像贊','白玉蟾','宋','宋诗','song-poetry','','[]','七返還丹阿誰無，先生歸去誰識渠。',32,'全唐诗/poet.song.207000.json','["七返還丹阿誰無，先生歸去誰識渠。", "時人要見真虛靖，北斗西邊一點如。"]'),
('0ec60882-c0a3-4eff-bda7-5161fcd90930','沖虛侍宸王文卿像贊','白玉蟾','宋','宋诗','song-poetry','','[]','醉持鐵尺叫風雷，玉帝綸言召兩回。',32,'全唐诗/poet.song.207000.json','["醉持鐵尺叫風雷，玉帝綸言召兩回。", "到得人間無鬼蜮，依然長嘯入西臺。"]'),
('cec24f26-a0b7-4710-ad6f-766e079e7d06','天師侍晨追封妙濟真人林靈素像贊','白玉蟾','宋','宋诗','song-poetry','','[]','大宋天師林侍晨，飛罡躡紀召風霆。',32,'全唐诗/poet.song.207000.json','["大宋天師林侍晨，飛罡躡紀召風霆。", "四十五年人事足，中秋歸去月三更。"]'),
('9189be7d-758f-48f2-8cee-5ae4e88b5e0c','許旌陽贊','白玉蟾','宋','宋诗','song-poetry','','[]','曾傳諶母煉丹訣，夜夜西山採明月。',64,'全唐诗/poet.song.207000.json','["曾傳諶母煉丹訣，夜夜西山採明月。", "壺裏滿盛烏兔精，劍尖尚带蛟龍血。", "一自旌陽縣歸來，拔宅騰空入金闕。", "但留仵道八百年，未教他喫東華雪。"]'),
('ec535a65-c6f0-40bf-a84d-2d77009845d9','韓湘子贊','白玉蟾','宋','宋诗','song-poetry','','[]','白雪滿空夜，黄芽一朵春。',24,'全唐诗/poet.song.207000.json','["白雪滿空夜，黄芽一朵春。", "藍關歸去後，問甚世間人。"]'),
('f2eb80fd-d17f-4c9c-9934-fb91fcf745aa','陳七子贊','白玉蟾','宋','宋诗','song-poetry','','[]','一卷無人識，千鍾對客談。',24,'全唐诗/poet.song.207000.json','["一卷無人識，千鍾對客談。", "桃花開欲謝，猶自戀寒巖。"]'),
('402f5a5e-75b9-488a-8953-921aecc3f4dc','何仙姑贊','白玉蟾','宋','宋诗','song-poetry','','[]','閬苑無蹤跡，唐朝有姓名。',24,'全唐诗/poet.song.207000.json','["閬苑無蹤跡，唐朝有姓名。", "不知紅玉洞，千古夜猿聲。"]'),
('43710f86-bfc0-4929-8321-65d964d98288','曹國舅贊','白玉蟾','宋','宋诗','song-poetry','','[]','竊得玉京桃，踏斷金華草。',24,'全唐诗/poet.song.207000.json','["竊得玉京桃，踏斷金華草。", "白雲滿簑衣，內有金丹寶。"]'),
('64621cc4-7645-42dc-a9fd-864378f6bdb2','黄風子贊','白玉蟾','宋','宋诗','song-poetry','','[]','先生不狂是詩狂，先生不顛是酒顛。',54,'全唐诗/poet.song.207000.json','["先生不狂是詩狂，先生不顛是酒顛。", "顛顛狂狂人不識，歸去青城今幾年。", "曾將詩酒瞞人眼，不是酒仙與詩仙，只是箇黄顛。"]'),
('66fa9632-ae22-4aa0-9a61-9429101c0ee2','朱文公像贊','白玉蟾','宋','宋诗','song-poetry','','[]','皇極墜地，公歸于天。',20,'全唐诗/poet.song.207000.json','["皇極墜地，公歸于天。", "武夷松竹，落日鳴蟬。"]'),
('894d52b7-8842-4f05-941f-8b013fc8e93b','自贊  其一','白玉蟾','宋','宋诗','song-poetry','','[]','日月藏瓢裏，溪山掛杖頭。',24,'全唐诗/poet.song.207000.json','["日月藏瓢裏，溪山掛杖頭。", "有些難說處，夜夜是中秋。"]'),
('a9412143-11c9-41f8-9013-ef27ae0310da','自贊  其二','白玉蟾','宋','宋诗','song-poetry','','[]','千古蓬頭跣足，一生服氣餐霞。',28,'全唐诗/poet.song.207000.json','["千古蓬頭跣足，一生服氣餐霞。", "笑指武夷山下，白雲深處吾家。"]'),
('97ef3057-721f-4347-80a1-25eb45a1adc8','自贊  其三','白玉蟾','宋','宋诗','song-poetry','','[]','神府雷霆吏，瓊山白玉蟾。',24,'全唐诗/poet.song.207000.json','["神府雷霆吏，瓊山白玉蟾。", "本來真面目，水墨寫霜縑。"]'),
('8d68b190-5f22-4aea-b9f0-d13819369499','許紫沖求真容贊  其一','白玉蟾','宋','宋诗','song-poetry','','[]','虎已伏，龍已降，獼猴不復窺六窗。',32,'全唐诗/poet.song.207000.json','["虎已伏，龍已降，獼猴不復窺六窗。", "萬籟無聲秋夜靜，一輪明月照西江。"]'),
('8fda9882-975e-495d-8584-e97c82196bd5','許紫沖求真容贊  其二','白玉蟾','宋','宋诗','song-poetry','','[]','盧山之下，繡谷之中。',32,'全唐诗/poet.song.207000.json','["盧山之下，繡谷之中。", "一江夜月，萬壑松風。", "此意誰能委，岳陽城外松。"]'),
('3274d4a5-95bf-4ca5-94b7-f515d7494f28','種桃齋寫神贊','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','南海瓊山子，香山居士孫。',70,'全唐诗/poet.song.207000.json','["南海瓊山子，香山居士孫。", "習文不若陸賈，習武不如孫臏。", "八千餘里琴劍，二十一年水雲。", "偶過廬山之下，痛飲蟾溪之濱。", "縱饒畫得十分似，何似天邊一月輪。"]'),
('7d275460-725e-4444-8574-365829541a9f','周伯神喜神贊','白玉蟾','宋','宋诗','song-poetry','','[]','方丈老仙客，寸心水一滴。',40,'全唐诗/poet.song.207000.json','["方丈老仙客，寸心水一滴。", "雙臉紅朱砂，兩眼點黑漆。", "白鬚撫掌笑呵呵，白鶴一去無人識。"]'),
('4905583f-8f0f-442a-b02a-1bad3372a9fc','倪梅窗喜神贊','白玉蟾','宋','宋诗','song-poetry','','[]','燕頷虎頭古班超，龍章鳳姿晉嵇康。',32,'全唐诗/poet.song.207000.json','["燕頷虎頭古班超，龍章鳳姿晉嵇康。", "高人心地本無象，風清月冷倪梅窗。"]'),
('ce2bdbd1-46c4-442e-b529-f286733e098f','醉作觀音像仍爲書贊  其一','白玉蟾','宋','宋诗','song-poetry','','[]','柳絮多頭緒，桃花好面皮。',24,'全唐诗/poet.song.207000.json','["柳絮多頭緒，桃花好面皮。", "夫是之謂誰，東海比丘尼。"]'),
('2b163f16-271c-4250-b055-c30cae07d619','醉作觀音像仍爲書贊  其二','白玉蟾','宋','宋诗','song-poetry','','[]','頂戴彌陀呈醜拙，手持楊柳惹塵埃。',32,'全唐诗/poet.song.207000.json','["頂戴彌陀呈醜拙，手持楊柳惹塵埃。", "縱饒入得三摩地，當甚街頭破草鞋。"]'),
('3cea1f90-ee08-48d0-97a0-bae467fffd1e','醉作觀音像仍爲書贊  其三','白玉蟾','宋','宋诗','song-poetry','','[]','花紅柳綠菩提相，燕語鶑啼般若宗。',32,'全唐诗/poet.song.207000.json','["花紅柳綠菩提相，燕語鶑啼般若宗。", "更去補陀山上覓，雲濤煙浪捲天風。"]'),
('de4efd6f-b6ab-4b25-849c-0b3cae00957e','布袋和尚贊','白玉蟾','宋','宋诗','song-poetry','','[]','布袋包盡太虛空，拄杖擊破三千界。',132,'全唐诗/poet.song.207000.json','["布袋包盡太虛空，拄杖擊破三千界。", "世界若還擊得碎，拄杖何止如許大。", "若言包得太虛空，虛空却在布袋外。", "如何偏愛此等物，常與小兒作一隊。", "問世人，會不會。", "奪了他拄杖，搶了他布袋。", "打殺許多小孩兒，看他彌勒何能解。", "彌勒撫掌笑呵呵，明月清風無罣礙。", "等到龍華三會時，依前有一彌勒在。"]'),
('b1689a8e-ce1d-4af8-83ef-78d10a8694a9','穢跡贊','白玉蟾','宋','宋诗','song-poetry','','[]','寶杵動時天地黑，鐶鈴震處鬼神驚。',56,'全唐诗/poet.song.207000.json','["寶杵動時天地黑，鐶鈴震處鬼神驚。", "釋迦臨入涅槃日，六慾天中現此身。", "現此身，無邊際。", "太圓鏡中點檢看，箇箇三頭并六臂。"]'),
('fb57b56b-65c8-442f-8813-cf52e621e5d1','戲作墨竹二本贈鶴林因爲之贊  其一','白玉蟾','宋','宋诗','song-poetry','','[]','新梢凝翠，落照餘紅。',20,'全唐诗/poet.song.207000.json','["新梢凝翠，落照餘紅。", "亂鴉噪罷，葉葉清風。"]'),
('a28c0679-8062-42f1-bc9b-9ff6e351e3cc','戲作墨竹二本贈鶴林因爲之贊  其二','白玉蟾','宋','宋诗','song-poetry','','[]','一枝嫩綠，數葉老蒼。',20,'全唐诗/poet.song.207000.json','["一枝嫩綠，數葉老蒼。", "夜半月明，清露瀼瀼。"]'),
('19e65449-3b6f-496a-8a9b-0310f92b83e6','金剛經偈寄示西林總長老','白玉蟾','宋','宋诗','song-poetry','','[]','以字不成，八字不是。',20,'全唐诗/poet.song.207000.json','["以字不成，八字不是。", "如是我聞，早落第二。"]'),
('2e785b9b-e822-4b09-a955-6f8cce3120a3','喜無憂求偈','白玉蟾','宋','宋诗','song-poetry','','[]','禪不用參，道不用學。',20,'全唐诗/poet.song.207000.json','["禪不用參，道不用學。", "行住坐卧，是大圓覺。"]'),
('2496ec1b-112e-448f-a70c-b3117db83ba7','爲禪悟剪髮偈','白玉蟾','宋','宋诗','song-poetry','','[]','一毛頭上一如來，一一如來鼻孔開。',32,'全唐诗/poet.song.207000.json','["一毛頭上一如來，一一如來鼻孔開。", "把得這般刀在手，剪教斷了喚教回。"]'),
('22f0b27f-2669-469a-95df-c09f8ec4c2ff','鄭天谷寫神隨喜說偈','白玉蟾','宋','宋诗','song-poetry','','[]','大道本來無形，安得這般面觜。',94,'全唐诗/poet.song.207000.json','["大道本來無形，安得這般面觜。", "是你不合带來，只得任他贊毀。", "三分似人，七分似鬼。", "不是骷髏，不是傀儡。", "這箇是第幾箇身，這箇是第幾箇你。", "有人更問如何，向道劍去久矣。", "三尺浪高魚化龍，癡人猶戽夜塘水。"]'),
('8036c8ae-c57b-45d7-9692-ebb3f80ee769','贈知宮王南紀洞章歌','白玉蟾','宋','宋诗','song-poetry','','[]','黄道珠躔闕一點，方寸無人洞門掩。',272,'全唐诗/poet.song.207000.json','["黄道珠躔闕一點，方寸無人洞門掩。", "桑田未變海水減，琪樹開花綠苒苒。", "小有瑶章落龍虎，月壇香冷宮誰主。", "真人颺下神霄鸞，天騶慘慘歸紫府。", "千山萬山鎖青煙，三樹兩樹啼斷猿。", "風飛楊花三月寒，人在城門煙水村。", "生而神靈長威武，笑携一卷黄庭去。", "坐斷琳宮主㠭粥，星弁霞裙滿堂廡。", "四海橫香航燭人，肘行膝步來如雲。", "愛河翻波渺無際，花生鐵柱酆都春。", "把握陰陽一呼吸，長嘯一聲鬼神泣。", "仗劍喚雨輕撼環，化篆召雷略舉筆。", "當年檄赴內道場，黄麻紫墨星爭光。", "歸來百慶喜具舉，規模輪奐重鋪張。", "翻思龍漢元年事，撞破混元識行李。", "滿鼎鉛霜火燄飛，綠顔雪齒君知否。", "松竹瀟瀟生泠風，白鶴一去草廬空。"]'),
('f5e5ab09-e21b-4fe7-aab6-70a14383e0ac','天開畫樓圖','白玉蟾','宋','宋诗','song-poetry','','[]','層簷疊巘入蒼冥，千山萬山相送迎。',64,'全唐诗/poet.song.207000.json','["層簷疊巘入蒼冥，千山萬山相送迎。", "晴雲一抹收未了，溪尾更濯餘霞明。", "化工朝暮費點染，丹青變態隨深淺。", "凭欄展空千里眼，却愁此軸難舒卷。"]'),
('a4f5a152-cb81-44a2-a4c3-72ce3c526aa6','贈何道人','白玉蟾','宋','宋诗','song-poetry','','[]','冠褐滿天下，幾箇能賢賢。',48,'全唐诗/poet.song.207000.json','["冠褐滿天下，幾箇能賢賢。", "忽來龍虎山，結這粥飯緣。", "方丈最高處，幽居今幾年。", "一雙巖電眼，識盡地行仙。"]'),
('5ca375cd-0ad2-4b73-9cf6-dc268f9875e5','贈潘高士  其一','白玉蟾','宋','宋诗','song-poetry','','[]','冬至煉朱砂，夏至煉水銀。',48,'全唐诗/poet.song.207000.json','["冬至煉朱砂，夏至煉水銀。", "常使居土釜，莫令鉛汞分。", "子母既相感，火候常溫溫。", "如是既久久，功成昇紫雲。"]'),
('729616bf-6471-42f8-847d-f45b9083596e','贈潘高士  其二','白玉蟾','宋','宋诗','song-poetry','','[]','龍虎戰百六，烏兔交七九。',48,'全唐诗/poet.song.207000.json','["龍虎戰百六，烏兔交七九。", "坎離直寅申，艮巽司卯酉。", "一粒同朱橘，千古永不朽。", "八月十五夜，三杯冬至酒。"]'),
('bb113699-b8ec-45c5-b7dc-7bd35c8d027d','梅窗','白玉蟾','宋','宋诗','song-poetry','','[]','南窗屋數楹，一點陽和生。',48,'全唐诗/poet.song.207000.json','["南窗屋數楹，一點陽和生。", "枝上雪粧瘦，牆頭風作清。", "霜天酒自暖，月夜夢難成。", "何處人吹笛，黄昏送幾聲。"]'),
('1d4c979d-f658-4a5e-8adb-6bb7049fab70','張進甫靜寮','白玉蟾','宋','宋诗','song-poetry','','[]','脫俗卧雲眠，胸中別有天。',48,'全唐诗/poet.song.207000.json','["脫俗卧雲眠，胸中別有天。", "壁間五六榻，屋上兩三椽。", "風月真滋味，溪山舊面緣。", "靜中有真靜，猿嘯暮林邊。"]'),
('7f81ecd5-21a9-4aeb-a023-3004670cb63c','立秋有感','白玉蟾','宋','宋诗','song-poetry','','[]','流年急似箭，日月跳如丸。',48,'全唐诗/poet.song.207000.json','["流年急似箭，日月跳如丸。", "炎皇初解印，白帝又彈冠。", "方旦喜無暑，教人又怕寒。", "人生只如許，不覺鼻頭酸。"]'),
('6c5a47c2-6a2b-4890-9983-e058415a580c','贈王太尉','白玉蟾','宋','宋诗','song-poetry','','[]','笑曳華裾出禁庭，一聲長嘯萬山青。',64,'全唐诗/poet.song.207000.json','["笑曳華裾出禁庭，一聲長嘯萬山青。", "歸來車馬如雲擁，掃去簪纓似夢醒。", "紅碼碯杯斟白酒，碧珊瑚枕倚朱屏。", "也須趁取些强學，作箇唐人五達靈。"]'),
('f51e9bdf-bc20-4870-b663-e30ebe8e603e','和葉宰韻題無咎齋','白玉蟾','宋','宋诗','song-poetry','','[]','蝸角蠅頭既可憎，如何又問利和名。',64,'全唐诗/poet.song.207000.json','["蝸角蠅頭既可憎，如何又問利和名。", "學他太古先天妙，合取中庸一點誠。", "乾坤所謂日月祖，坎離乃是天地精。", "工夫學到震無咎，隻字拔茅乘泰亨。"]'),
('95336c54-4ddf-4d8b-a62a-77e6ce3543fa','立秋有懷陳上舍','白玉蟾','宋','宋诗','song-poetry','','[]','沒巴沒鼻落一葉，發顛發狂何處風。',64,'全唐诗/poet.song.207000.json','["沒巴沒鼻落一葉，發顛發狂何處風。", "九十日暑掃地去，滿懷汗珠尋已空。", "却煩察判潘孺子，說與上舍陳元龍。", "來宵無雨必好月，一樽還要與君同。"]'),
('7d35122c-67d5-4a7a-bddf-4783b4db2033','寓息庵送春','白玉蟾','宋','宋诗','song-poetry','','[]','筆下自然詩料飽，天工飣出好山溪。',64,'全唐诗/poet.song.207000.json','["筆下自然詩料飽，天工飣出好山溪。", "魚知水暖不勝躍，鶑見花飛只管啼。", "樹頭鳩使婦喚雨，屋後竹教孫出泥。", "太白十杯人酕𦩘，碧桃洞口日銜西。"]'),
('2f590644-25e3-4939-9b34-0cf8525e8504','胡子嬴庵中偶題','白玉蟾','宋','宋诗','song-poetry','','[]','道人慣喫胡麻飯，來到人間今幾年。',64,'全唐诗/poet.song.207000.json','["道人慣喫胡麻飯，來到人間今幾年。", "白玉樓前空夜月，黄金殿上起春煙。", "閑傾一盞中黄酒，悶掃千章內景篇。", "昨夜鍾離傳好語，教吾且作地行仙。"]'),
('b29bb8ba-4af6-4e45-82d7-7ec5f742d4b5','寄蘇侍郎','白玉蟾','宋','宋诗','song-poetry','','[]','往古來今如換肩，我疑公便是坡仙。',64,'全唐诗/poet.song.207000.json','["往古來今如換肩，我疑公便是坡仙。", "滿城都沒箇伯樂，一日可能無樂天。", "方且論文俄判袂，不知握手又何年。", "忽然鐵笛一聲響，響到金華古洞邊。"]'),
('c99710cc-0a9f-42dc-a3cd-810c3edd94e7','贈危法師','白玉蟾','宋','宋诗','song-poetry','','[]','曾見先生在九華，朝餐玉乳著瓊花。',64,'全唐诗/poet.song.207000.json','["曾見先生在九華，朝餐玉乳著瓊花。", "鹿冠夜戴青城月，鶴氅晨披紫府霞。", "偶携劍在人間世，未把琴歸仙子家。", "一笑相逢松竹裏，炷香新話啜杯茶。"]'),
('560c24fd-3391-457f-9857-6e417b15c461','燕巖遊罷與巖主話別','白玉蟾','宋','宋诗','song-poetry','','[]','西風吹作此巖遊，滿目松筠翠欲流。',64,'全唐诗/poet.song.207000.json','["西風吹作此巖遊，滿目松筠翠欲流。", "玉燕不飛明月夜，石鍾一振曉霜秋。", "惜乎分水便南北，忽爾回頭欲去留。", "且去人間辦丹料，却來山頂結茆休。"]'),
('933a1507-212b-4065-b7ab-7e2c82b3a300','題舒氏難老亭  其一','白玉蟾','宋','宋诗','song-poetry','','[]','別是人間一洞天，椿松鬰鬰起祥烟。',64,'全唐诗/poet.song.207000.json','["別是人間一洞天，椿松鬰鬰起祥烟。", "德同桂種不知歲，福與水流無盡年。", "萱草堂前千古事，蓮花池上兩神仙。", "萊衣戲綵人無恙，結盡溪山風月緣。"]'),
('18238936-1a54-460a-bf1f-d2583d777621','題舒氏難老亭  其二','白玉蟾','宋','宋诗','song-poetry','','[]','三十三天第一天，玉皇殿下裊輕烟。',64,'全唐诗/poet.song.207000.json','["三十三天第一天，玉皇殿下裊輕烟。", "不知劫數今何代，方是延康第二年。", "弱水無船歸似箭，華胥有夢且遊仙。", "携筇難老亭前坐，且結焚香瀹茗緣。"]'),
('fe7e3921-62fb-4d8f-a965-8833ec77e176','題棲仙館','白玉蟾','宋','宋诗','song-poetry','','[]','好松好竹好溪山，車馬駢闐自往還。',64,'全唐诗/poet.song.207000.json','["好松好竹好溪山，車馬駢闐自往還。", "行客聞篘新酒白，入門路破嫩苔斑。", "我言物外清幽地，却似廛中闤闠間。", "穀粟桑麻空潤屋，主人陪接不曾閑。"]'),
('aa100457-85ab-4335-b7bd-c24bc41458d2','降真室','白玉蟾','宋','宋诗','song-poetry','','[]','瓊鐘發響綵旛飛，窗外青烏半夜啼。',64,'全唐诗/poet.song.207000.json','["瓊鐘發響綵旛飛，窗外青烏半夜啼。", "松竹無言爭地靜，星辰可摘覺天低。", "黄雲屋角騰金輦，素月簷頭放玉梯。", "稽首紫皇初宴罷，步虛聲斷乞刀圭。"]'),
('0190c0f5-5f4b-4ee5-a200-d91bffe67375','劣隠','白玉蟾','宋','宋诗','song-poetry','','[]','世態炎凉覺鼻酸，洞門空掩綠烟寒。',64,'全唐诗/poet.song.207000.json','["世態炎凉覺鼻酸，洞門空掩綠烟寒。", "仗三尺劍臨風舞，把一張琴對月彈。", "斫竹數竿容水過，倚松半日執經看。", "山林心緒得閑處，好煉長生不死丹。"]'),
('8ee2dc74-a924-48a9-8202-251e878ff2c1','思微堂','白玉蟾','宋','宋诗','song-poetry','','[]','思微堂裏自沖虛，高士閑居興味殊。',64,'全唐诗/poet.song.207000.json','["思微堂裏自沖虛，高士閑居興味殊。", "月冷花開數朵靜，風清鳥過一聲孤。", "誰知心上工夫妙，欲覓人間俗累無。", "九轉內丹成也未，快騎白鶴去天衢。"]'),
('6eeeb595-aad8-48b5-a89b-4e13a1188fa7','題上清法堂壁','白玉蟾','宋','宋诗','song-poetry','','[]','秋雨懸天風作寒，冷煙鎖住屋頭山。',64,'全唐诗/poet.song.207000.json','["秋雨懸天風作寒，冷煙鎖住屋頭山。", "半巖飛鳥一聲過，峭壁斷雲千古閑。", "世俗不知幽靜處，神仙隠在有無間。", "夜來小艇篙脫手，醉把霜筇入翠灣。"]'),
('4bf6a2b9-2716-40cd-8c92-1b9f414882d1','太虛堂','白玉蟾','宋','宋诗','song-poetry','','[]','滿堂冷靜爽精神，不著人間一點塵。',64,'全唐诗/poet.song.207000.json','["滿堂冷靜爽精神，不著人間一點塵。", "簷鵲噪風呼薄晚，庭花飄露落殘春。", "華胥上國今無夢，龍漢元年古有身。", "香篆飛從窗外去，雲梢孤鶴唳何人。"]'),
('431ff102-aa76-4656-9bd3-5b194d7d5456','三華院還丹詩','白玉蟾','宋','宋诗','song-poetry','','[]','絳宮無事絕塵埃，坎虎離龍戰幾回。',64,'全唐诗/poet.song.207000.json','["絳宮無事絕塵埃，坎虎離龍戰幾回。", "白雪飛空鉛蘂綻，黄雲覆鼎汞花開。", "龜蛇抱一成丹藥，烏兔凝真結望胎。", "夜半瀛洲寒月落，冷風吹鶴上蓬萊。"]'),
('9d5a2f92-8c16-4634-843f-9a6099c5a413','送江子恭  其一','白玉蟾','宋','宋诗','song-poetry','','[]','我欲楊村結草廬，不知蹤跡又江湖。',64,'全唐诗/poet.song.207000.json','["我欲楊村結草廬，不知蹤跡又江湖。", "回觀咫尺如天遠，自別丰標僅月餘。", "忽一二時思故舊，整千百里望音書。", "憶君不忍忘懷處，一片青雲點太虛。"]'),
('dc527df3-864d-48ca-8e18-e16a87e88720','送江子恭  其二','白玉蟾','宋','宋诗','song-poetry','','[]','春來行盡爛田畦，雲滿春空水滿溪。',64,'全唐诗/poet.song.207000.json','["春來行盡爛田畦，雲滿春空水滿溪。", "風漾碧波翻麥壠，日晴紅雨落桃蹊。", "杜鵑聲斷驚寒兔，蝴蝶夢殘聽曉鷄。", "人在江東寄歸信，海棠花謝燕銜泥。"]'),
('6e321749-fdb7-4ec3-8e56-8846e2fd628a','送江子恭  其三','白玉蟾','宋','宋诗','song-poetry','','[]','子到鉛山我信州，筍輿軋軋又歸休。',64,'全唐诗/poet.song.207000.json','["子到鉛山我信州，筍輿軋軋又歸休。", "數程細雨斜風路，一片落花啼鳥愁。", "何必便爲阮籍哭，不來相伴赤松遊。", "他年我到蓬萊去，一粒金丹汝去不。"]'),
('da056d9d-5c26-46df-bda3-317aabdb7cfd','送張大師','白玉蟾','宋','宋诗','song-poetry','','[]','自從汝離武夷來，險阻艱難歷幾回。',64,'全唐诗/poet.song.207000.json','["自從汝離武夷來，險阻艱難歷幾回。", "江左旅中連值雨，春深路上滑成苔。", "鳥啼花片落流水，風慘猿聲嘯古臺。", "舉眼四山如壁立，教君歸去也心灰。"]'),
('515493e7-043b-48c1-a496-84d9602ddef8','贈杜省元','白玉蟾','宋','宋诗','song-poetry','','[]','海外三山一洞天，金樓玉室有神仙。',64,'全唐诗/poet.song.207000.json','["海外三山一洞天，金樓玉室有神仙。", "南柯國裏柯巖叟，白馬江邊馬自然。", "鯨脯味甘供老廣，黄麻飯熟飼彭鏗。", "金丹煉就爐無火，桃再開花經幾年。"]'),
('77dc6bb8-7dae-4415-ad76-b3173c39316f','淡庵倪清父','白玉蟾','宋','宋诗','song-poetry','','[]','地僻人閑春晝長，了然物我兩相忘。',64,'全唐诗/poet.song.207000.json','["地僻人閑春晝長，了然物我兩相忘。", "薄披明月歸詩肆，細切清風入醉鄉。", "蠟味溪山閑裏嚼，虀羹松竹靜中嘗。", "把琴彈破世間事，凈几明窗一炷香。"]'),
('103d0ee1-0508-466e-af91-6b4cbfff289a','倪敬父柯山','白玉蟾','宋','宋诗','song-poetry','','[]','暮雲橫翠夕陽斜，啼罷歌樓林外鴉。',64,'全唐诗/poet.song.207000.json','["暮雲橫翠夕陽斜，啼罷歌樓林外鴉。", "綠竹弄摇風裏影，碧桃開遍雨中花。", "三杯淡酒邀明月，一局殘棋驚落霞。", "人在柯山山上詠，笑揮管筆走生蛇。"]'),
('1e8ee9d0-c11a-484d-8cb6-88869b722e4e','酬蔣知觀所惠詩','白玉蟾','宋','宋诗','song-poetry','','[]','新鴈飛來一朵雲，讀之毛骨聳寒鱗。',64,'全唐诗/poet.song.207000.json','["新鴈飛來一朵雲，讀之毛骨聳寒鱗。", "展開大句幾鈎墨，存想先生滿面春。", "榻上賓朋談盛德，山中冠褐混凡身。", "來朝盥手炷香去，恐是蓬萊相識人。"]'),
('c758f995-bc3a-439b-87b4-c6b1b936ab8a','題鍾','白玉蟾','宋','宋诗','song-poetry','','[]','聞道琳宮欲範鍾，上皇敕賜萬斤銅。',64,'全唐诗/poet.song.207000.json','["聞道琳宮欲範鍾，上皇敕賜萬斤銅。", "一模脫出等閑事，千古要知陶鑄功。", "敲得星飛驚落月，撞教雲破響呼風。", "于今欲爲吾皇壽，笑指瓊樓貼碧空。"]'),
('99aec2c0-0ac1-49a5-829a-4e74de05cb37','美周都監禱雨驗','白玉蟾','宋','宋诗','song-poetry','','[]','旱魃爲妖欲請雩，真人問雨幾時無。',64,'全唐诗/poet.song.207000.json','["旱魃爲妖欲請雩，真人問雨幾時無。", "先將鳳表投金闕，擬向龍潭下鐵符。", "彈指雷鳴三霹靂，舉頭雲起一須叟。", "笑將斗柄輕輕戽，倒瀉銀河萬斛珠。"]'),
('92242fc2-f6b7-49b6-80ad-21fe7daedd61','別句呈庚契吳高士','白玉蟾','宋','宋诗','song-poetry','','[]','一笑相逢在翠微，綠槐高柳借凉時。',64,'全唐诗/poet.song.207000.json','["一笑相逢在翠微，綠槐高柳借凉時。", "只將水竹煙雲興，說與風花雪月知。", "日落三杯無事酒，人閑八句自然詩。", "來朝雲過青山外，回首空聞猿鶴悲。"]'),
('955f1ce7-4083-4174-9b48-362fdbae214e','蒙谷','白玉蟾','宋','宋诗','song-poetry','','[]','淡煙輕鎖數株松，夜靜瀟瀟古谷風。',64,'全唐诗/poet.song.207000.json','["淡煙輕鎖數株松，夜靜瀟瀟古谷風。", "雲掩草舒青洞綠，鳥銜花落碧巖紅。", "神仙去後無金劍，仕宦來時有玉桐。", "未知此後誰人隠，寂寞南來幾朵峰。"]'),
('91a2510d-732b-425a-9021-07f4fd844b61','題紫芝院','白玉蟾','宋','宋诗','song-poetry','','[]','武夷山前嘯一聲，雲愁霧慘野猿驚。',64,'全唐诗/poet.song.207000.json','["武夷山前嘯一聲，雲愁霧慘野猿驚。", "閑披破衲藏風月，醉把葫蘆禁鬼神。", "杖弄銀蟾攪天地，夜烹金鼎煮星辰。", "睡酣不覺機關路，身是紅光火一輪。"]'),
('58ba5814-83fb-4e6e-8d74-82e900bc8c7a','題西軒壁','白玉蟾','宋','宋诗','song-poetry','','[]','隨身風月幾清閑，不做人間潑底官。',64,'全唐诗/poet.song.207000.json','["隨身風月幾清閑，不做人間潑底官。", "朝飲一壺朱鳳髓，暮餐八兩黑龍肝。", "打開俗網了無事，縛住時光自駐顔。", "昨夜夢回天上去，瓊樓玉闕不勝寒。"]'),
('2ddd89ec-d614-4326-8fb4-3347f3e3f29b','贈趙縣尉','白玉蟾','宋','宋诗','song-poetry','','[]','半斤雷火燒紅杏，一滴露珠凝碧荷。',64,'全唐诗/poet.song.207000.json','["半斤雷火燒紅杏，一滴露珠凝碧荷。", "錦帳中間藏玉狗，寶瓶裏面養金鵝。", "鉛花朵朵開青蘂，汞葉枝枝發絳柯。", "莫問嬰兒并姹女，等閑尋取舊黄婆。"]'),
('da3dbdfc-fe94-4f80-9428-2290af6535b3','贈趙翠雲','白玉蟾','宋','宋诗','song-poetry','','[]','金公姹女到黄家，活捉蒼龜與赤蛇。',64,'全唐诗/poet.song.207000.json','["金公姹女到黄家，活捉蒼龜與赤蛇。", "偃月爐中烹玉蘂，朱砂鼎裏結金花。", "奔歸氣海名朱驥，飛入泥丸是白鴉。", "昨夜火龍爭戰後，雪中微見月鈎斜。"]'),
('8df25af9-b197-43ca-b8b6-e3e890775342','贈雷怡真','白玉蟾','宋','宋诗','song-poetry','','[]','地魄天魂日月精，奪來鼎內及時烹。',64,'全唐诗/poet.song.207000.json','["地魄天魂日月精，奪來鼎內及時烹。", "祇行龜鬭蛇爭法，早是龍吟虎嘯聲。", "神水華池初匹配，黄芽白雪便分明。", "這些是飲刀圭處，漸漸抽添漸漸成。"]'),
('f65b84fb-64be-4a52-b136-c7363e3edace','題玉隆宮壁','白玉蟾','宋','宋诗','song-poetry','','[]','旌陽歸去太康年，石竈灰寒古洞前。',64,'全唐诗/poet.song.207000.json','["旌陽歸去太康年，石竈灰寒古洞前。", "笑斬白龍橫蓼岸，醉騎黄鶴步雲天。", "金丹玉屑不復得，鐵臼石函猶宛然。", "四十二口家何在，猿嘯西山柏樹煙。"]'),
('cb1f74b2-9095-4875-8596-454da943c322','慵庵','白玉蟾','宋','宋诗','song-poetry','','[]','絳闕清都舊姓名，此生落魄任天真。',112,'全唐诗/poet.song.207000.json','["絳闕清都舊姓名，此生落魄任天真。", "橫窗古硯前朝水，掛壁閑琴幾日塵。", "幽草莫鋤沿日靜，落花不掃襯苔勻。", "倩風來作關門僕，借月權爲伴酒人。", "書吏無言舌滋味，關山不動畫精神。", "有茶不作蝸牛戰，無夢可爲蝴蝶身。", "一得自家慵底事，幽禽簷外一般春。"]'),
('4cd735cf-9b3d-4b66-a544-a14fed1df251','題三清殿後壁','白玉蟾','宋','宋诗','song-poetry','','[]','些兒頑石些兒水，畫工撐眸幾睥睨。',256,'全唐诗/poet.song.207000.json','["些兒頑石些兒水，畫工撐眸幾睥睨。", "忽然心孔開一竅，呼吸掇來歸幅紙。", "白髮黄冠逞神通，手把武夷提得起。", "大槐宮中作螻蟻，醒來聞此心豁喜。", "芒鞋竹杖一彈指，三十六峯落眉尾。", "魏王豈是中秋死，玉骨猶存香迤邐。", "八百年來覓隻鶴，一舉直上三萬里。", "半杯澆濕曾孫齒，幔亭遺事落人耳。", "新村渡頭拽轉蓬，寒猿聲落青烟裏。", "老松今已幾年梢，毛竹于今復生米。", "巖上無人花自紅，幽鳥自鳴鳴自止。", "笑將鐵笛起清風，白雲飛過看無蹤。", "夜來月影掛梧桐，莓苔滿地綠容容。", "丹崖高處藥爐空，洞前雲深千萬重。", "我亦偶來還自去，一夜瀟瀟江上雨。", "飛廉怒作滿空雪，天柱峰前飛柳絮。"]'),
('b33d95c0-2334-462d-b6a0-32d0dfea7605','題丹樞先生草庵','白玉蟾','宋','宋诗','song-poetry','','[]','數朵奇峰如削玉，一溪秋水生寒綠。',304,'全唐诗/poet.song.207000.json','["數朵奇峰如削玉，一溪秋水生寒綠。", "幸有白雲深處茅，更兼明月壇前竹。", "誅茅伐竹結蘧廬，現成山水可樵漁。", "隨緣隨分山中住，收拾摩尼如意珠。", "草廬道人貧徹骨，一廬瀟洒空無物。", "身中有寶不求人，價大難酬不拈出。", "朝朝暮暮了身心，山自開花鳥自吟。", "未見桑田成海水，夕陽幾度鎖平林。", "住此草廬無別術，終日凝神惟兀兀。", "不是十洲三島仙，亦非閬苑蓬萊客。", "是箇逍遥無事人，廬中涵蓄一壺春。", "窗前明月千年影，枕上清風萬劫聲。", "廬內主人那箇是，古今占斷清閑地。", "忽然洗面摸得鼻，不飲不食亦不寐。", "廬空人去烟濛濛，白鶴呼雲滿碧空。", "一瞻元始天尊面，處處爲廬處處同。", "有箇草廬小復小，此是虛空那一竅。", "頂頭不掛一莖茅，萬象森羅爲拱斗。", "劫火洞然毫末盡，此廬不壞人如舊。"]'),
('2dc42b3a-1965-4b4d-b1a5-d25b01377e19','贈趙太虛畫竹石','白玉蟾','宋','宋诗','song-poetry','','[]','竹魂竹魄竹精神，飛落瀟湘淇水瀕。',320,'全唐诗/poet.song.207000.json','["竹魂竹魄竹精神，飛落瀟湘淇水瀕。", "千竿萬竿競青翠，吹風飲露千來春。", "先生筆端自風雨，驚起竹魂無著處。", "一點水墨化成龍，龍孫飛去鵞溪住。", "先生把筆無逡巡，造物不敢私爲春。", "新梢勁節森寒玉，鸞鳳無處棲夢魂。", "晉人神仙如孫且，畫竹每每天作雨。", "唐人神仙如張臻，畫竹每每聞鴈鳴。", "先生自得入神手，一竿兩竿發於酒。", "當時大醉呼墨奴，一筆掃出竹千畝。", "酒力安能奪化工，先生煉就金丹紅。", "一粒陽光照肺腑，森羅萬象羅心胸。", "有時持出風竹葉，銀海不寒皆震懾。", "有時持出雪中枝，恍如凍碧欺漣漪。", "復能濡墨作石塊，天然峭拔古且怪。", "沙中伏虎草中犀，教人持向蓬萊賣。", "竹之清虛石堅硬，以此發明真性命。", "使人觀石及愛竹，知有真箇趙元靜。", "先生醉時常風顛，世人眼孔無神仙。", "我今珍藏數本畫，雲鶴來也公歸天。"]'),
('33ea3df4-bc28-4897-bc71-b1adc45b497d','贈郭承務蘆鴈','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','畫士郭熙畫之冠，郭熙去後名未斷。',304,'全唐诗/poet.song.207000.json','["畫士郭熙畫之冠，郭熙去後名未斷。", "其裔復有郭萬里，胸中丹青飽無限。", "爲誰作此蘆鴈圖，傑出南齊宇文煥。", "烟水瀟瀟風捲蘆，沙邊鴻鴈暮相呼。", "瀟瀟洞庭此秋景，世間此畫知有無。", "幻出棲鴈三四隻，八九葉蘆橫古磧。", "欲宿未宿嘹唳聲，漁舟泊岸山烟黑。", "秋風吹落梧葉黄，過鴈往往歸衡陽。", "橫空書字人不識，飛過有影沉滄浪。", "落霞浸水江村暮，數隻翱翔回古渡。", "引領舉喙啄荷花，飛越戍樓西畔去。", "雲寒月淡西塞秋，幾聲凄切惹人愁。", "岸頭飛共丹楓落，打團成陣訪沙鷗。", "似此景物似此意，君今畫之不難事。", "數幅鵝溪冰雪縑，須臾掃出蘆鴈市。", "世間豈無學畫者，未必有與君相似。", "我欲致之篋笥間，滿笥爽氣生秋寒。", "恐君此畫無人見，有畫鬭者誰敢戰。", "掛於幽軒素壁間，一日須看千百遍。"]'),
('3d1756e7-691e-4b0c-8993-243cc080adc3','純陽會','白玉蟾','宋','宋诗','song-poetry','','[]','一點薰風舞綠槐，祝融衮火從南來。',384,'全唐诗/poet.song.207000.json','["一點薰風舞綠槐，祝融衮火從南來。", "海棠落地蜂蝶去，池館無人蓮未開。", "溶溶一掬清和髓，純乾已作牝馬矣。", "岳瀆將此英雄氣，收來頓在葫蘆裏。", "階前十有四莢蓂，諫議夜來夢麒麟。", "披槲老翁自鼻笑，胞胎未兆天元春。", "洞賓弄巧翻成拙，蓬萊路上空明月。", "牆頭梅子枝上蠟，池畔榴花葉底血。", "生來挺挺其精神，所適性癖窮天真。", "驀然悟得鉛汞機，敢謂大道無楚秦。", "忽爾金丹成九轉，十月胎團人不問。", "撼動乾坤走鬼神，青雲白鶴方解悶。", "天下後世思真人，常與真人慶誕辰。", "櫻笋厨開正來日，釋氏亦欲制蠟人。", "不知故事自誰始，實是五代譙陵起。", "王詵建會集冠褐，飛來白鶴不知幾。", "次則蕭氏建宅仙，七閩萬戶生祥煙。", "一郡二郡漸風化，駸駸知省洞賓賢。", "城南城北走幾次，人亦不知回老是。", "但見老松作人語，先生携墨歸誰氏。", "太平寺裏作篇詩，又道摩鏡嫌人癡。", "岳陽市心一長嘯，鐵笛無聲今幾時。", "寶婺有人潘氏子，功名願足心肺喜。", "髫年崇奉迄今日，四海杖屨紛如蟻。"]'),
('23f57b32-f499-4900-83c1-0217818e28f8','贈城西謝知堂','白玉蟾','宋','宋诗','song-poetry','','[]','蓬萊山上神仙翁，道貌挺挺喬如松。',384,'全唐诗/poet.song.207000.json','["蓬萊山上神仙翁，道貌挺挺喬如松。", "雙眸炯炯黑於漆，臉邊隠隠如桃紅。", "有時仰天笑開口，撮起崑崙歸右手。", "忽然虛空跌落地，不覺滿腹藏星斗。", "有時驚起老龍號，一口汲盡滄浪波。", "打破混沌揣出骨，拈起芥子貯山河。", "偃月爐中煮天地，煎煉日魄并月髓。", "笑把葫蘆禁鬼神，杖頭挑起山和水。", "欒巴噀飯飛成蜂，左慈剪艾化爲龍。", "夏月梅花冬月電，似此伎倆問呂鍾。", "撮土爲香猶是假，水底麒麟取作酢。", "鬼神眼睛突出外，無根樹下騎鐵馬。", "工夫到處戲極時，拈弄造化如兒嬉。", "大蟲舌上翻筋斗，却笑金剛學畫眉。", "女皇要補西天竅，煉石不得羲皇笑。", "秦皇鑿山通四溟，漢帝掣之一長笑。", "先生手持沒底籃，出有入無猶不凡。", "携此道術問四海，洞賓今正覓同參。", "盞裏綿包或聚散，火裏遊鱼水裏鴈。", "黄鶴樓前大醉時，撐眼撮與鍾離看。", "水盆攪散五色沙，滿地寫出龍蛇花。", "自將一盞逡巡酒，敢向人前化作茶。", "笊籬裏面一條路，透入青霄雲外去。", "十字街頭開鋪席，翻手覆手成雲雨。"]'),
('135c0b8f-9780-4207-8e8f-b7d397f9bc95','胡東原香錦亭','白玉蟾','宋','宋诗','song-poetry','','[]','東皇剖破勾芒腹，錦心繡腸香馥鬰。',192,'全唐诗/poet.song.207000.json','["東皇剖破勾芒腹，錦心繡腸香馥鬰。", "絳都風雨僝僽春，花魂無主自精神。", "黄鸝初喚柳開眼，海棠枝上春煙暖。", "放出一點兩點紅，牆頭紅腮微笑風。", "東原去後花無主，春工亦懶施機杼。", "亭前忽遇詩酒仙，花亦噴出些龍涎。", "風催雨趲花不辨，滿庭芬芳生爛熳。", "牡丹吐火花欲然，日將錦綉鋪苔氈。", "詩狂夢與花神飲，酒醉不與花神寢。", "酒闌令我憶東原，花木雖在人惻然。", "此詩終不爲花作，惆悵東原此丘壑。", "而今賞花不見人，但見蜂蝶飛閑亭。"]'),
('bf28d003-9913-4555-8c26-33364686f50d','謁仙行贈萬書記','白玉蟾','宋','宋诗','song-poetry','','[]','嶰管飛葭方孟籥，青女仍前行夜惡。',336,'全唐诗/poet.song.207000.json','["嶰管飛葭方孟籥，青女仍前行夜惡。", "連日東風料峭寒，黄鸝聲斷梅花落。", "客來武夷訪靈蹤，八字洞門無鎖鑰。", "溪頭昨夜添新雨，桃片滿溪紅灼灼。", "蒼苔滿地空綠勻，芳草無言烟漠漠。", "搗藥聲乾丹井寒，虹橋一斷收霞幕。", "千古松風學鳳笙，向晚清客滿林壑。", "山光不動舊松竹，洞中慘慘悲猿鶴。", "機巖學館空無人，紫領丹丘久蕭索。", "霧暗平林虎長嘯，碧潭生花老龍躍。", "峭崖飛鳥不敢過，萬丈蒼瓊真峻削。", "山中金蟾不可尋，石邊且取黄芝嚼。", "我生逍遥事落魄，泉石烟霞得真樂。", "身披綠麻戴青蒻，橫擔碧藜躡芒屩。", "只愛山林厭城郭，却厭膏粱愛藜藿。", "冷眠石上入華胥，夢見太虛無斧鑿。", "朅來洞中未半餉，轉盼又覺經旬朔。", "今朝雲頭雨收脚，欲歸又被溪山縛。", "欲作此地三間茅，朝餐紅霞暮飲瀑。", "已有神仙分定緣，定知道外無乾坤。", "只愁天上多官府，九轉丹成未敢吞。"]'),
('d1038e46-0f80-41f4-b1f1-a15ede9720dd','雲遊歌','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嘗記得洞庭一夜雨，無簑無笠處。',378,'全唐诗/poet.song.207000.json','["嘗記得洞庭一夜雨，無簑無笠處。", "偎傍茅簷待天明，村翁不許簷頭住。", "又記得武林七日雪，衣衫破又裂。", "不是白玉蟾，教他凍得皮迸血，只是寒徹骨。", "又記得江東夏熱時，路上石頭如火熱，教我何處歇。", "無扇可摇風，赤脚走不輟。", "又記得青城秋月夜，獨目松陰下，步虛一闋罷，口與心說話。", "寒煙漠漠萬籟靜，彼時到山方撮乍。", "又記得瀟湘些小風，吹轉華胥夢，銜山日正紅。", "一聲老鴉鳴，鴉鳴過耳尋無蹤。", "這些子歡喜，消息與誰通。", "又記得淮西兵馬起，枯骨排數里。", "欲餐又無糧，欲渴又無水。", "又記得一年到村落，瘟黄正作惡。", "人來請符水，無處堪摸索。", "神將也顯靈，亂把鬼神捉。", "又記得北邙山下行，古墓秋草生，紙錢雨未乾。", "白楊風瀟瀟，荒臺月盈盈。", "一夜鬼神哭不止，頼得度人一卷經。", "又記得通衢展手處，千家說慚愧，萬家說調數。", "倚門眼看鼻，頻頻道且過。", "滿面著盡笑，喝駡叫吾去。", "又記得入堂求掛搭，嫌我太藍縷。", "直堂與單位，知堂言不合。"]'),
('13cf61fb-0fbf-4f47-820a-3a012d563d5c','快活歌  其一','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','快活快活真快活，被我一時都掉脫。',384,'全唐诗/poet.song.207000.json','["快活快活真快活，被我一時都掉脫。", "撒手浩歌歸去來，生薑胡椒果是辣。", "如今快活大快活，有時放顛或放劣。", "自家身裏有夫妻，說向時人須笑殺。", "向時快活小快活，無影樹子和根拔。", "男兒端的會懷胎，子母同形活潑潑。", "快活快活真快活，虛空粉碎秋毫末。", "輪迴生死幾千生，這回大死方今活。", "舊時窠臼潑生涯，于今凈盡都掉脫。", "元來爹爹只是爺，懵懵懂懂自瓜葛。", "近來髣髴辨西東，七七依前四十八。", "如龍養珠心不忘，如鷄抱卵氣不絕。", "又似寒蟬吸曉風，又如老蚌含秋月。", "一箇閑人天地間，大笑一聲天地闊。", "衣則四時惟一衲，飯則千家可一鉢。", "三家村裏弄風狂，十字街頭打鶻突。", "一夫一妻將六兒，或行或坐常兀兀。", "收來放去任縱橫，即是十方三世佛。", "有酒一杯復一杯，有歌一闋復一闋。", "日中了了飯三餐，飯後齁齁睡一歇。", "放下萬緣都掉脫，脫得自如方快活。", "用盡醒醒學得癡，此時化景登晨訣。", "時人不會翻筋斗，如饑喫鹽加得渴。", "偶然放浪到廬山，身在白蘋紅蓼間。"]'),
('7caa92b5-d42f-45e7-9ceb-ebd1a8aa7cca','快活歌  其二','白玉蟾','宋','宋诗','song-poetry','','[]','破衲雖破破復補，身中自有長生寶。',384,'全唐诗/poet.song.207000.json','["破衲雖破破復補，身中自有長生寶。", "拄杖奚用巖頭藤，草鞋不用田中藁。", "或狂走，或兀坐，或端立，或仰卧。", "時人但道我風顛，我本不顛誰識我。", "熱時只飲華池雪，寒時獨向丹中火。", "饑時愛喫黑龍肝，渴時貪吸青龍腦。", "絳宮新發牡丹花，靈臺初生薏苡草。", "却笑顔回不爲夭，又道彭鏗未是老。", "一盞中黄酒更甜，千篇內景詩尤好。", "沒絃琴兒不用彈，無腔曲子無人和。", "朝朝暮暮打憨癡，且無一點閑煩惱。", "尸解飛昇總是閑，死生生死無不可。", "隨緣且喫人間飯，不用繅蠶不種稻。", "寒霜凍雪未爲寒，朝饑暮餒禁得餓。", "天上想有仙官名，人間不愛真人號。", "跨虎金翁是鉛兄，乘龍姹女爲汞嫂。", "泥丸宮裏有黄婆，解把嬰兒自懷抱。", "神關氣關與心關，三關一簇都穿過。", "六賊心如火正焚，三尸膽似天來大。", "不動干戈只霎時，破除金剛自搜邏。", "一齊縛向火爐邊，碎爲微塵誰斬挫。", "而今且喜一粒紅，已覺丁公婚老媼。", "當初不信翠虛翁，豈到如今脫關鎖。", "葉苗正嫩採歸來，猛火煉之成紫磨。"]'),
('d6d5a12f-e733-4936-b6f9-6e1511ee1a7f','必竟恁地歌','白玉蟾','宋','宋诗','song-poetry','','[]','我生不信有神仙，亦不知有大羅天。',384,'全唐诗/poet.song.207000.json','["我生不信有神仙，亦不知有大羅天。", "那堪見人說蓬萊，掩面却笑渠風顛。", "七返還丹多不實，往往將謂人虛傳。", "世傳神仙能飛昇，又道不死延萬年。", "肉既無翅必墜地，人無百歲安可延。", "滿眼且見生死俱，死生生死相循旋。", "翠虛真人與我言，他所見識大不然。", "恐人緣淺賦分薄，自無壽命歸黄泉。", "人身只有三般物，精神與氣常保全。", "其精不是交感精，廼是玉皇口中涎。", "其氣即非呼吸氣，乃知却是太素煙。", "其神即非思慮神，可與元始相比肩。", "我聞其言我亦怖，且怖且疑且擎拳。", "但知即日動止間，一物相處常團圓。", "此物根蒂乃精氣，精氣恐是身中填。", "豈知此精此神氣，根於父母未生前。", "三者未常相返離，結爲一塊太無邊。", "人之生死空自爾，此物湛寂何傷焉。", "吾將矍然以自思，老者必不虛其言。", "是我將有可愛業，渠必以此示言詮。", "開禧元年中秋夜，焚香跪地口相傳。", "朅爾行持三兩日，天地日月軟如綿。", "忽然嚼得虛空破，始知鍾呂皆參玄。", "吾之少年早留心，必不至此猶塵緣。"]'),
('6d6eb0c0-37a3-4fef-8524-2a36730ce965','安分歌','白玉蟾','宋','宋诗','song-poetry','','[]','神仙底事君知否，君若知兮求不苟。',352,'全唐诗/poet.song.207000.json','["神仙底事君知否，君若知兮求不苟。", "先且回頭自揣量，須量瞞心方開口。", "神仙有術非不傳，也要儂家有夙緣。", "若也人人皆會得，天機容易向人言。", "學道學仙須篤志，堅然一念無疑意。", "如是操心無始終，又道辨金將火試。", "你們心地荆棘多，善根纔發便成魔。", "若能先合神仙意，己分無時也奈何。", "心地不明言行惡，做出事來須是錯。", "自家無取他無求，思量何似當初莫。", "恁地思量本故然，且教自己故心堅。", "君看古今得事者，一片靈臺必不然。", "未見志人須願見，逢著人時心百變。", "何緣傳授有易難，自是玄門未歷鍊。", "問你如何不料量，自家窮達任穹蒼。", "但且奈心依本分，人言有麝自然香。", "玉蟾本是山林客，尋箇好心人難得。", "于今且趁草鞋壯，臉似桃紅眼正黑。", "玉蟾你也好獃頭，何似拂袖歸去休。", "有可度人施設處，便還鍾呂逞風流。", "無人知，獨自去，白雲千里不回顧。", "依前守取三脚鐺，且把清風明月煮。"]'),
('0acc8eaf-291a-42fe-9545-f3c81335f592','茶歌','白玉蟾','宋','宋诗','song-poetry','','[]','柳眼偷看梅花飛，百花頭上東風吹。',378,'全唐诗/poet.song.207000.json','["柳眼偷看梅花飛，百花頭上東風吹。", "壑源春到不知時，霹歷一聲驚曉枝。", "枝頭未敢展鎗旗，吐玉綴金先獻奇。", "雀舌含春不解語，只有曉露晨煙知。", "带露和煙摘歸去，蒸來細搗幾千杵。", "捏作月團三百片，火候調勻文與武。", "碾邊飛絮捲玉塵，磨下落珠散金縷。", "首山黄銅鑄小鐺，活火新泉自烹煮。", "蟹眼已沒魚眼浮，壵壵松聲送風雨。", "定州紅玉琢花甆，瑞雪滿甌浮白乳。", "綠雲入口生香風，滿口蘭芷香無窮。", "兩腋颼颼毛竅通，洗盡枯腸萬事空。", "君不見孟諫議，送茶驚起盧仝睡。", "又不見白居易，餽茶喚醒禹錫醉。", "陸羽作茶經，曹暉作茶銘。", "文正范公對茶笑，紗帽籠頭煎石銚。", "素虛見雨如丹砂，點作滿盞菖蒲花。", "東坡深得煎水法，酒闌往往覓一呷。", "趙州夢裏見南泉，愛結焚香瀹茗緣。", "吾儕烹茶有滋味，華池神水先調試。", "丹田一畝自栽培，金翁姹女採歸來。", "天爐地鼎依時節，煉作黄芽烹白雪。", "味如甘露勝醍醐，服之頓覺沉痾甦。", "身輕便欲登天衢，不知天上有茶無。"]'),
('1fb39272-28be-4cab-ab9b-537ee1682206','大道歌','白玉蟾','宋','宋诗','song-poetry','','[]','烏飛金，兔走玉，三界一粒粟。',374,'全唐诗/poet.song.207000.json','["烏飛金，兔走玉，三界一粒粟。", "山河大地幾年塵，陰陽顛倒入玄谷。", "人生石火電光中，數枚客鵲枝頭宿。", "桑田滄海春復秋，乾坤不放坎離休。", "九天高處風月冷，神仙肚裏無閑愁。", "世間學仙者，胸襟變清雅。", "丹經未讀望飛昇，指影談空相誑嚇。", "有時馳騁三寸舌，或在街頭佯做啞。", "正中恐有邪，真裏須辨假。", "若是清虛冷澹人，身外無物赤灑灑。", "都來聚氣與凝神，要鍊金丹賺幾人。", "引賊入家開寶藏，不知身外更藏身。", "身外有身身裏覓，沖虛和氣一壺春。", "生擒六賊手，活嚼三尸口。", "三尸六賊本來無，盡從心裏忙中有。", "玉帝非惟惜詔書，且要神氣相保守。", "此神此氣結真精，喚作純陽周九九。", "此時方曰聖胎圓，萬丈崖頭翻筋斗。", "鉛汞若糞土，龍虎如鷄狗。", "白金黑錫幾千般，水銀朱砂相鼓誘。", "白雪黄芽自無形，華池神水無泉溜。", "不解回頭一著子，衝風冒雨四方走。", "四方走，要尋師，尋得邪師指授時，迷迷相指可憐伊。", "大道不離方寸地，工夫細密有行持。"]'),
('16ce4afe-0936-42cd-8ae5-3121c986ab5e','畫中衆仙歌','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','不興飲盡孫權酒，正欲畫屏筆脫手。',384,'全唐诗/poet.song.207000.json','["不興飲盡孫權酒，正欲畫屏筆脫手。", "一點凝墨狀生蠅，剔之不飛心始驚。", "獻之興來拈起筆，筆如解飛自鈎掣。", "戲染松烟作牸牛，脫似偃角眠沙丘。", "蕭賁深得鶴三昧，胸中不與造化礙。", "一幅素絹如片天，雪翎欲起凌蒼烟。", "僧繇醉後齁齁睡，睡起濡墨作石塊。", "擘山裂巖而拏雲，或如伏虎如露拳。", "愷之畫蘭藏玉笥，開而視之已飛去。", "安得翠葉成寒叢，四景常使飄春風。", "聞道南齊宇文煥，精筆妙墨掃蘆鴈。", "低頸吸水昂頸飛，髣象荷枯沙瘦時。", "唐有處士吳道元，丹青之餘多畫猿。", "狀出抱子落寒泉，又如彎弓遶樹奔。", "季成畫虎常作怒，鬼神不敢正眼覷。", "但見紙上生猙獰，開口解嘯風悲鳴。", "葉公好龍故學畫，不覺心孔開一罅。", "紙上筆畫方似龍，風鬐浪鬣來爭雄。", "韓幹畫馬得滋味，霜蹄巧作追風勢。", "可憐張口嘶無聲，只惜風稜瘦骨成。", "江頭細草爲誰綠，只有風煙相管束。", "阮瞻收拾草精神，筆端與草私爲春。", "畫魚古有康靈叔，擲頭擺尾萬鱗足。", "紅鱨紫鯉成隊行，躍碎琉璃跳上冰。"]'),
('efc1634a-7de4-48fb-90cd-7594538d5be3','拙庵','白玉蟾','宋','宋诗','song-poetry','','[]','笑携藜杖倚寒松，現世神仙一拙翁。',208,'全唐诗/poet.song.207000.json','["笑携藜杖倚寒松，現世神仙一拙翁。", "冠簡投關離玉闕，天人推出鎮琳宮。", "身居星弁霞裾上，心在煙都月府中。", "豈是摩挲令髮黑，不須服餌自顔紅。", "百年贏得十分訥，萬事算來俱是空。", "解織蜘蛛空結網，能言鸚鵡被樊籠。", "閑將世味閑中嚼，靜把天機靜處窮。", "學巧不如藏巧是，忘機不與用機同。", "虛空不語虛空廣，造化無聲造化公。", "六賊奈人閑不得，十魔見我懶相攻。", "凝神多得佯呆力，養氣無非守口功。", "欲雨只消呼瀣沆，要雷畧目召豐隆。", "人間若也不容住，學騎白鶴乘天風。"]'),
('98a6c5f6-b7d8-49e6-9ebd-ea64dc05c55e','聽趙琴士鳴弦','白玉蟾','宋','宋诗','song-poetry','','[]','我尋屏跡到猿啼，雲滿山前花滿溪。',348,'全唐诗/poet.song.207000.json','["我尋屏跡到猿啼，雲滿山前花滿溪。", "高峰壁立七十二，風生兩腋天可梯。", "煉師兩鬢東風黑，紺天不流月光白。", "簷牙咬雨昨已晴，松幄張空夜瑟瑟。", "興濃抱石玄以輕，得意七絃橫玉繩。", "膝頭指弄響玲玲，燦然奪目三十星。", "初如雨滴芭蕉夜，久坐梧桐猿嘯罷。", "宛然幽澗聽鳴泉，偶雜修篁戛清夏。", "先疑易水渡荆軻，已轉似勸無渡河。", "美人金帳別項籍，壯士鐵笛吹孟婆。", "不然雙雉兩南北，或者婦牽蘇武服。", "絃中何似湘妃怨，指下爲甚明妃哭。", "又非林下感蠨蛸，更匪胡笳叫晚秋。", "自然鴈聲下遥塞，忽覺蟬噪過南樓。", "君休彈終我畏聽，滿懷今古興亡病。", "蒼梧雲愁虞舜遠，鼎湖雲出軒轅冷。", "一聲一聲復一聲，不管世間銀髮生。", "彈盡天涯夕陽影，又向山中彈月明。", "胡長卿，去已久，韓飛瓊，無此手。", "玉帝聞未曾，人間空白首。", "柳花霏霏滿江城，城外海棠紅淚傾。", "恐君餘思更未已，爲我春晝聞晴鶑。"]'),
('cb3e8427-eaef-4c10-a188-acf663832778','贈方壺高士','白玉蟾','宋','宋诗','song-poetry','','[]','蓬萊三山壓弱水，鳥飛不盡五雲起。',379,'全唐诗/poet.song.207000.json','["蓬萊三山壓弱水，鳥飛不盡五雲起。", "紫麟曉舞丹丘雲，白鹿夜嚙黄芽蘂。", "浩浩神風碧無涯，長空粘水三千里。", "中有一洞名方壺，玉顔仙翁不知幾。", "上帝賜以英瓊瑶，縫芝緝槲佩蘭芷。", "戲吹雲和下朱塵，還煉五雲長不死。", "丹砂益駐長虹容，玉石弗礪愈白齒。", "醉飛罡步躡星辰，時把葫蘆梏鬼神。", "早曾探出天地根，寸田尺宅安崑崙。", "安知我即劉晨孫，不復更覓桃花源。", "或者即是劉戽身，豈復別尋會仙村。", "一閉目頃游六合，坐裏汗漫詣渾淪。", "何必裹糧圓嶠外，寧又遠泛閬風津。", "雲屏煙障只笑傲，煙猿露鶴與相親。", "君不見剛風浩氣截碧落，上嚴天關九屏惡，俯視萬方萬聚落。", "絲長歲月能幾時，米大功名安用爲。", "不將世界寄一粟，便請芥子納須彌。", "初從螺江問草屧，已判此身輕似葉。", "及其流湘過衡嶽，一笑江山闊如楪。", "如今坐斷煙霞窩，已誦東皇太乙歌。", "不作竹宮桂館夢，奈此四海黄冠何。", "夜來坐我酌桂醁，不敢起舞賓雲曲。", "何年踏踏去方壺，我欲騎風後相逐。"]'),
('082e50d9-c33c-41df-949f-f07874737347','贈蓬壺丁高士琴','白玉蟾','宋','宋诗','song-poetry','','[]','瓠巴騎鯨上天去，伯牙成連亦千古。',356,'全唐诗/poet.song.207000.json','["瓠巴騎鯨上天去，伯牙成連亦千古。", "淺世斷無鍾子期，弦中妙意爲誰舉。", "春風春雨滿瀟湘，人在蓬窗閉竹房。", "竹裏鵑啼喉舌冷，花間鶑宿夢魂香。", "客從漓沅下衡岳，滿懷詩愁無處著。", "請君拂去水晶塵，瀹茗一了撫然作。", "道人問予若爲情，伊絃凄兮余莫聽。", "一春十病九困酒，三月都無二日晴。", "俛首沉吟聲一曲，吟扭一罷撚撥續。", "初如雪泉嗽鳴玉，已轉忽如雨簌簌。", "於中亦有蠨蛸鳴，倏忽變作冷猿聲。", "始疑荆軻渡易水，乃是湘妃夜涕零。", "昔從撫斷南風了，羑里幽人始能曉。", "可嘆壇中苦杏花，山高水寒即聲杳。", "道人此意非人間，笑詠洞章鏘佩環。", "能令鳳舞下丹漢，雲裏大地垂頭看。", "世間鷄蟲互得失，只好牧羊坐花石。", "何爲兒女謾昵昵，候蟲時鳴徒戚戚。", "輸君朝朝在翠微，鶴已睡去人不知。", "笑思古今一俯仰，彈到千山月落時。", "君知否，梧桐枝上雙燕語，盡將萬事等風絮。", "琴中日月何翛閑，肯使事逐孤鴻度。"]'),
('d0e876cb-8415-4c4f-bec8-b9b33808a0e8','南岳九真歌題壽寧沖和閣','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','笑携魏王大瓠落，往觀洞庭張帝樂。',240,'全唐诗/poet.song.207000.json','["笑携魏王大瓠落，往觀洞庭張帝樂。", "醉騎八風訪廣漠，九天之上無南岳。", "我尋九貢誚冥寞，亂雲深中湧樓閣。", "玉帝苦詔陳興明，雙童前吹紫鸞笙。", "尹君道全驂後塵，先殿後衛森火鈴。", "皓首惠度其姓陳，却立虹橋叫霜鷹。", "施友粲然索天笑，露冷松寒月華皎。", "無人爲呼張法要，萬山猿啼夜虎嘯。", "張復有若如珍少，煉得身形成鶴瘦。", "我今只憶徐靈期，嗽煉華池灌玉芝。", "天柱峯頭鳳鄧鬰，旦旦黄芽飼白龜。", "玉仙靈輿昔無期，想跨九鳳衣羽衣。", "香火在帝去已久，玉笥亦九門亦九。", "壇上仙翁何仙良，爲問渺茫再來否。", "朝粵暮梧儻可到，泠然來此同樓居。"]'),
('5152b363-5804-401b-9a59-a5ca004a5792','夜宴清勝軒醉吟呈倪梅窗吳道士隠南','白玉蟾','宋','宋诗','song-poetry','','[]','山前浩歌覺聲乾，長嘯直入碧雲間。',96,'全唐诗/poet.song.207000.json','["山前浩歌覺聲乾，長嘯直入碧雲間。", "梅窗主人携百壺，一夜談話秋雨寒。", "燈紅吐出玉蟲巧，道人大嘯拍床吼。", "連榻隠南吳庚契，要看紙上生蛇走。", "停杯撐眼發詩顛，橫捉一筆半欲眠。", "笑把崑崙蘸滄海，寫出新詞數萬篇。"]'),
('37a47cb6-fae4-4ee2-9ff1-11477edfb904','題清勝軒','白玉蟾','宋','宋诗','song-poetry','','[]','滿林幽竹夜來風，南極一點飛寒空。',192,'全唐诗/poet.song.207000.json','["滿林幽竹夜來風，南極一點飛寒空。", "玉爐異香繞琳宮，此間知有神仙翁。", "清勝軒中頗幽絕，白鬚道士持檀笏。", "眉毛掀起溪上雲，眼光爍破峯頭月。", "瓊房壁上掛瑶琴，把劍舞罷千古心。", "蓬萊一別醉吹笛，今日一見歌長吟。", "天祇呵道綠煙起，滿前王趙皆珠履。", "倦虬縮尾青蛇死，彈指傾倒天河水。", "砂篆一揮走神鬼，雷電霹靂動天地。", "信知妙用古所無，猶未收拾歸天衢。", "月冷風清白鶴唳，寶旛飛霞繞玉壺。", "武夷散人好詩酒，昔者見君今番又。"]'),
('77ab330f-c9aa-46f6-931b-2d33f398e2ed','仙巖金仙閣','白玉蟾','宋','宋诗','song-poetry','','[]','寒煙瑣斷梵王家，一篆博山飛冷蛇。',80,'全唐诗/poet.song.207000.json','["寒煙瑣斷梵王家，一篆博山飛冷蛇。", "滿天秋雨落瓊花，清溪漲綠浸平沙。", "老松壓石巖爭聳，青蘿拽樹牽雲遮。", "竹根倒出烏翅斜，夜半寒風攪宿鴉。", "木魚喚粥蝴蝶醒，巖頭殘月沉丹井。"]'),
('27b9285b-d0c3-4614-833d-a23df6b25b05','雷怡真小隠送春','白玉蟾','宋','宋诗','song-poetry','','[]','天不欲留春，東君暗歸去。',24,'全唐诗/poet.song.207000.json','["天不欲留春，東君暗歸去。", "碧梧枝上看，瀟瀟風送雨。"]'),
('72fc93ad-f034-49c1-b17f-8953f414b884','旅邸睡起','白玉蟾','宋','宋诗','song-poetry','','[]','雲爲山積翠，雨倩草添青。',24,'全唐诗/poet.song.207000.json','["雲爲山積翠，雨倩草添青。", "一覺南柯夢，俄然鳥喚醒。"]'),
('d6f6b3e5-2746-4725-b124-8c0f5decd808','仙巖無塵軒','白玉蟾','宋','宋诗','song-poetry','','[]','麈尾清虛語，銅爐起澹煙。',24,'全唐诗/poet.song.207000.json','["麈尾清虛語，銅爐起澹煙。", "嶺頭猿叫罷，月落碧潭圓。"]'),
('80ffda7a-a005-4b32-8366-e7a99e1afb69','曲肱詩  其一','白玉蟾','宋','宋诗','song-poetry','','[]','昔在青華第一宮，祇緣醉後怒騎龍。',32,'全唐诗/poet.song.207000.json','["昔在青華第一宮，祇緣醉後怒騎龍。", "傾翻半滴金瓶水，不覺人間雨發洪。"]'),
('15205b4f-fc3a-490c-ba28-c7cc2c2a7da3','曲肱詩  其二','白玉蟾','宋','宋诗','song-poetry','','[]','玉皇有敕問神霄，誰去騎龍亂作妖。',32,'全唐诗/poet.song.207000.json','["玉皇有敕問神霄，誰去騎龍亂作妖。", "自別雷城一迴首，人間天上已相遼。"]'),
('f27b9da5-ea2e-4129-9c30-1ce9818e713d','曲肱詩  其三','白玉蟾','宋','宋诗','song-poetry','','[]','謫君塵世意徘徊，煉盡金丹待鶴來。',32,'全唐诗/poet.song.207000.json','["謫君塵世意徘徊，煉盡金丹待鶴來。", "歸去神霄朝玉帝，依前命我掌風雷。"]'),
('37760941-19d1-4910-afeb-cc37ab21fe8f','曲肱詩  其四','白玉蟾','宋','宋诗','song-poetry','','[]','五雷深鎖玉清宮，白鶴呼風唳碧空。',32,'全唐诗/poet.song.207000.json','["五雷深鎖玉清宮，白鶴呼風唳碧空。", "說著這般辛苦處，三千玉女蹙眉峯。"]'),
('c17ef68a-72f1-40e8-b3e1-bcb1c569f4d0','曲肱詩  其五','白玉蟾','宋','宋诗','song-poetry','','[]','太乙天皇謁紫清，翠娥百萬擁雲軿。',32,'全唐诗/poet.song.207000.json','["太乙天皇謁紫清，翠娥百萬擁雲軿。", "當時不合抬頭看，忽見天丁叱火鈴。"]'),
('fa75f3a1-93af-4498-9140-154495a2b904','曲肱詩  其六','白玉蟾','宋','宋诗','song-poetry','','[]','我不生嗔怨玉皇，翠娥無復舞霓裳。',32,'全唐诗/poet.song.207000.json','["我不生嗔怨玉皇，翠娥無復舞霓裳。", "如何天上神仙女，染污清都一散郎。"]'),
('db6c7894-05ed-4372-a1a4-a832d154fa15','曲肱詩  其七','白玉蟾','宋','宋诗','song-poetry','','[]','夢斷南柯覺昨非，因緣盡處兩分飛。',32,'全唐诗/poet.song.207000.json','["夢斷南柯覺昨非，因緣盡處兩分飛。", "寒松空鎖翠娥夢，我獨于今未得歸。"]'),
('f50fbec6-200b-40d4-8dd3-b3f91fea9c90','曲肱詩  其八','白玉蟾','宋','宋诗','song-poetry','','[]','玉府官僚無甚人，上皇憐我最辛勤。',32,'全唐诗/poet.song.207000.json','["玉府官僚無甚人，上皇憐我最辛勤。", "忽然詔下催歸去，猿叫萬山空白雲。"]'),
('f83a1c99-3691-44ed-84c0-ab7b5059c7ca','曲肱詩  其九','白玉蟾','宋','宋诗','song-poetry','','[]','瑶池王母宴群仙，兩部笙歌簇綺筵。',32,'全唐诗/poet.song.207000.json','["瑶池王母宴群仙，兩部笙歌簇綺筵。", "誤取一枚仙李喫，又來人世不知年。"]'),
('101ccc07-5132-416e-9f94-c10241eaae3a','曲肱詩  其一○','白玉蟾','宋','宋诗','song-poetry','','[]','我到人間未百年，恰如頃刻在三天。',32,'全唐诗/poet.song.207000.json','["我到人間未百年，恰如頃刻在三天。", "向來我本雷霆吏，今更休疑作甚仙。"]'),
('295c317a-a886-4a81-9048-810e2cb1ddc0','曲肱詩  其一一','白玉蟾','宋','宋诗','song-poetry','','[]','往昔逍遥在太華，朝餐玉乳看瓊花。',32,'全唐诗/poet.song.207000.json','["往昔逍遥在太華，朝餐玉乳看瓊花。", "當年身著六銖服，不識人間有苧麻。"]'),
('cad942a3-5057-4676-958b-056f709dcbf4','曲肱詩  其一二','白玉蟾','宋','宋诗','song-poetry','','[]','做到天仙地位時，三遭天譴落天墀。',32,'全唐诗/poet.song.207000.json','["做到天仙地位時，三遭天譴落天墀。", "却嫌天上多官府，且就人間洞府嬉。"]'),
('bddb00ac-2863-47ff-93c7-6f6bc6465aee','曲肱詩  其一三','白玉蟾','宋','宋诗','song-poetry','','[]','白雲隨我見天台，又趁金華路上迴。',32,'全唐诗/poet.song.207000.json','["白雲隨我見天台，又趁金華路上迴。", "棲鳳亭中留不去，武夷山下野猿哀。"]'),
('2388b3b2-e80a-4046-83c5-550cd4b0e04f','曲肱詩  其一四','白玉蟾','宋','宋诗','song-poetry','','[]','說與清風明月知，揚州有鶴未能騎。',32,'全唐诗/poet.song.207000.json','["說與清風明月知，揚州有鶴未能騎。", "夜來五鳳樓前看，天上白雲空自飛。"]'),
('830af1a9-b719-4633-a0f0-ac26937381c7','曲肱詩  其一五','白玉蟾','宋','宋诗','song-poetry','','[]','跣足蓬頭破衲衣，悶來飲酒醉吟詩。',32,'全唐诗/poet.song.207000.json','["跣足蓬頭破衲衣，悶來飲酒醉吟詩。", "廛中走遍無人識，我是東華大帝兒。"]'),
('42cd147a-3446-4eb7-83bf-0d6699888f93','曲肱詩  其一六','白玉蟾','宋','宋诗','song-poetry','','[]','這回空過二十年，肉重不能飛上天。',32,'全唐诗/poet.song.207000.json','["這回空過二十年，肉重不能飛上天。", "抖擻衲頭還自笑，囊中也沒一文錢。"]'),
('3a3725dc-ad17-4f3d-ab2b-c726a1295493','曲肱詩  其一七','白玉蟾','宋','宋诗','song-poetry','','[]','我有隨身一顆珠，見時似有覓時無。',32,'全唐诗/poet.song.207000.json','["我有隨身一顆珠，見時似有覓時無。", "金鷄叫罷無人見，月射寒光滿太虛。"]'),
('51097133-2085-465b-b9d7-44774e3e9146','曲肱詩  其一八','白玉蟾','宋','宋诗','song-poetry','','[]','不識看經不坐禪，饑來喫飯困來眠。',32,'全唐诗/poet.song.207000.json','["不識看經不坐禪，饑來喫飯困來眠。", "玉皇若不開青眼，却是凡夫骨未仙。"]'),
