('4b4c67a1-2066-4eb5-9057-b3d3ce2626bc','贊歷代天師 第十二代諱仲常字德潤','白玉蟾','宋','宋诗','song-poetry','','[]','鶴書曾詔赴宸京，歸作分形化景人。',32,'全唐诗/poet.song.207000.json','["鶴書曾詔赴宸京，歸作分形化景人。", "昨日飲酣曾吐酒，醒來又薄甕頭春。"]'),
('630a4ae6-00b0-4ed7-bbad-87b58180202f','贊歷代天師 第十三代諱光字德昭','白玉蟾','宋','宋诗','song-poetry','','[]','幾年辟穀學飛行，揮破秋空一點青。',32,'全唐诗/poet.song.207000.json','["幾年辟穀學飛行，揮破秋空一點青。", "纔到暮林風月夜，洞天隠隠步虛聲。"]'),
('03c55f45-35d5-4df1-8af8-ce258b740a62','贊歷代天師 第十四代諱慈正字子明','白玉蟾','宋','宋诗','song-poetry','','[]','丹鼎能乾活水銀，舉家一念贍貧民。',32,'全唐诗/poet.song.207000.json','["丹鼎能乾活水銀，舉家一念贍貧民。", "空中動破雲韶樂，白鶴飛來風雨春。"]'),
('45cfa386-7359-47a6-90b0-7d6f42fff7f4','贊歷代天師 第十五代諱高字士龍','白玉蟾','宋','宋诗','song-poetry','','[]','丹臺一點玉髯翁，千古天師張士龍。',32,'全唐诗/poet.song.207000.json','["丹臺一點玉髯翁，千古天師張士龍。", "招弄斸山詩技巧，吐吞風月酒神通。"]'),
('3b3b6b8e-1097-4f18-a00b-fbc7b5e178e0','贊歷代天師 第十六代諱應詔字治鳳','白玉蟾','宋','宋诗','song-poetry','','[]','一畝閑雲獨自耕，草廬寂寂誦黄庭。',32,'全唐诗/poet.song.207000.json','["一畝閑雲獨自耕，草廬寂寂誦黄庭。", "又言辟穀歸山後，月夜時聞鐵笛聲。"]'),
('9929125c-17ba-4330-953f-d6fcf2f1a9a0','贊歷代天師 第十七代諱順字仲孚','白玉蟾','宋','宋诗','song-poetry','','[]','貴谿一尉隠家山，靜結茅廬三兩間。',32,'全唐诗/poet.song.207000.json','["貴谿一尉隠家山，靜結茅廬三兩間。", "九十歲時尸解日，時人猶見是童顔。"]'),
('5d4342db-cb87-4895-b4b0-ce3167cd51e8','贊歷代天師 第十八代諱士元字仲良','白玉蟾','宋','宋诗','song-poetry','','[]','神水華池養白鴉，玉爐進火結丹砂。',32,'全唐诗/poet.song.207000.json','["神水華池養白鴉，玉爐進火結丹砂。", "仙家妙用無人識，頃刻能開桃李花。"]'),
('9a2b2dbb-0c33-421d-bffe-6a424f7f0b4a','贊歷代天師 第十九代諱修字德真','白玉蟾','宋','宋诗','song-poetry','','[]','玉局瑶篇龍鳳文，三元開度士如雲。',32,'全唐诗/poet.song.207000.json','["玉局瑶篇龍鳳文，三元開度士如雲。", "翻身踏著蓬萊路，浴罷焚香自入墳。"]'),
('3a2599ee-1493-42c8-93a3-19ea288ad100','贊歷代天師 第二十代諱諶字堅德','白玉蟾','宋','宋诗','song-poetry','','[]','吸乾酒海一須臾，冠冕玄壇百歲餘。',32,'全唐诗/poet.song.207000.json','["吸乾酒海一須臾，冠冕玄壇百歲餘。", "不食人間煙火氣，能傳天上電花書。"]'),
('02222e29-0ac9-47d4-8bf0-0f83c93de1f5','贊歷代天師 第二十一代諱秉字溫甫','白玉蟾','宋','宋诗','song-poetry','','[]','火腹金龜夢正疑，琳房初誕謫仙兒。',32,'全唐诗/poet.song.207000.json','["火腹金龜夢正疑，琳房初誕謫仙兒。", "丹傳祖印百來歲，執笏歸仙地震時。"]'),
('9cb56a4a-e456-40a6-ab8b-d0a5fcb65e40','贊歷代天師 第二十二代諱善字元長','白玉蟾','宋','宋诗','song-poetry','','[]','參遍名山謁洞天，相逢却是活神仙。',32,'全唐诗/poet.song.207000.json','["參遍名山謁洞天，相逢却是活神仙。", "歸來換骨回陽日，屈指人間九十年。"]'),
('9f8aa7f9-5d9f-4bd0-9dee-1c5bde34db7f','贊歷代天師 第二十三代諱季文字仲歸','白玉蟾','宋','宋诗','song-poetry','','[]','玉盂祝水起波雲，筆下雷聲泣鬼神。',32,'全唐诗/poet.song.207000.json','["玉盂祝水起波雲，筆下雷聲泣鬼神。", "龍虎山前山後問，先生活盡幾多人。"]'),
('ca06820a-88ca-412d-a6fd-aedfb2da2f72','贊歷代天師 第二十四代諱正隨字寶神','白玉蟾','宋','宋诗','song-poetry','','[]','人在犂鋤烟水鄉，結茅高卧小松崗。',32,'全唐诗/poet.song.207000.json','["人在犂鋤烟水鄉，結茅高卧小松崗。", "敕封真靜先生號，一卷仙經一炷香。"]'),
('46263aa1-3541-4ebb-b3b6-3a2ee59ade16','贊歷代天師 第二十五代諱乾曜','白玉蟾','宋','宋诗','song-poetry','','[]','橫握鏌鋣入洞天，洞天漠漠掩寒煙。',32,'全唐诗/poet.song.207000.json','["橫握鏌鋣入洞天，洞天漠漠掩寒煙。", "仁宗親問金丹訣，笑指斜陽噪亂蟬。"]'),
('30deebd1-e8e1-42b5-b66e-e3e8aadc4362','贊歷代天師 第二十六代諱嗣宗','白玉蟾','宋','宋诗','song-poetry','','[]','朱砂鼎裏煉金晶，默禱天皇入紫冥。',32,'全唐诗/poet.song.207000.json','["朱砂鼎裏煉金晶，默禱天皇入紫冥。", "月落半山丹井水，猿聲驚斷滿天星。"]'),
('14e753d7-fb54-4f3e-bcb7-ffefce34a335','贊歷代天師 第二十七代諱象中字拱辰','白玉蟾','宋','宋诗','song-poetry','','[]','仁皇恩賜紫衣時，方是寧馨七歲兒。',32,'全唐诗/poet.song.207000.json','["仁皇恩賜紫衣時，方是寧馨七歲兒。", "閑把洞章歌一闋，不知鸞鶴滿天飛。"]'),
('2db27a73-b4a9-4187-b7ec-311608faa8df','贊歷代天師 第二十八代諱敦復字延之','白玉蟾','宋','宋诗','song-poetry','','[]','棘圍戰罷笑歸來，一寸功名心已灰。',32,'全唐诗/poet.song.207000.json','["棘圍戰罷笑歸來，一寸功名心已灰。", "白鶴何年歸洞府，夕陽影裏野猿哀。"]'),
('805d9adc-ec6b-478e-9ff0-f6702e0bc5e6','贊歷代天師 第二十九代諱景端字子仁','白玉蟾','宋','宋诗','song-poetry','','[]','當年仙去鶴巢空，萬壑千崖夕照紅。',32,'全唐诗/poet.song.207000.json','["當年仙去鶴巢空，萬壑千崖夕照紅。", "人在丹丘玄圃外，瀟瀟松桂夜來風。"]'),
('87031fe8-3683-4d03-9290-0e85ae6d08dc','贊歷代天師 第三十代諱繼先字遵正','白玉蟾','宋','宋诗','song-poetry','','[]','築著成都人姓劉，丹成蛻跡入羅浮。',32,'全唐诗/poet.song.207000.json','["築著成都人姓劉，丹成蛻跡入羅浮。", "瓊樓數紙御書在，虛靜先生已掉頭。"]'),
('cefe810f-09ac-4e88-a778-3e928bb6bba4','贊歷代天師 第三十一代諱時修字朝英','白玉蟾','宋','宋诗','song-poetry','','[]','是箇清都一散郎，凝神聚氣煉丹陽。',32,'全唐诗/poet.song.207000.json','["是箇清都一散郎，凝神聚氣煉丹陽。", "片雲孤鶴無蹤跡，半夜風寒萬里霜。"]'),
('4dfb972e-8c66-457e-8e1e-6c6586e66922','贊歷代天師 第三十二代諱守真字遵一','白玉蟾','宋','宋诗','song-poetry','','[]','鶴頸龜腮骨已仙，星壇長嘯誦瓊篇。',32,'全唐诗/poet.song.207000.json','["鶴頸龜腮骨已仙，星壇長嘯誦瓊篇。", "自從闕下歸仙後，一枕清風幾萬年。"]'),
('0d8a0a9a-e00e-4ad7-a861-2b312c8a82e2','知宮王琳甫贊','白玉蟾','宋','宋诗','song-poetry','','[]','青布衲，碧藜筇。',143,'全唐诗/poet.song.207000.json','["青布衲，碧藜筇。", "詩吟白芍藥，曲唱紫芙蓉。", "一局著殘人事醒，七絃彈破世間空。", "時乎泛一葉於滄海之外，時乎飛片羽於虛空之中。", "鐵笛橫吹老龍泣，金樽一倒琪花紅。", "孤猿嘯夜月，淡露滴秋風。", "雲錦溪深碧無底，天蒼山秀綠不窮。", "白鶴卧占眠牛草，丹鵲飛上棲鴉松。", "真人一聲長嘯於蓬萊之東，青童回首指道神仙中之最雄。"]'),
('56e18f0c-5b14-40d7-b539-472321d11186','陳綠雲先生之像贊','白玉蟾','宋','宋诗','song-poetry','','[]','瞻師之神，寒空片月。',190,'全唐诗/poet.song.208000.json','["瞻師之神，寒空片月。", "知師之心，紅爐點雪。", "聞師之德，冰清玉潔。", "見師之蹟，霜炎冰熱。", "師之一言，斬釘截鐵。", "師之一行，殺人見血。", "風月情懷，松筠志節。", "道法陸沉，玄徒瓦裂。", "師領郡檄，雷轟電掣。", "冠冕洞宮，興大施設。", "輪輿楩楠，陶埏坯甈。", "麗以粉奐，飾以藻楶。", "不逾年間，滄江貫折。", "度五神足，霞裙森列。", "方有倫緒，閈閭洽悅。", "胡爲雲鶴，奄歸帝闕。", "溪山失翠，猿鳥悽切。", "散詞玉祠，柏子一爇。", "追慕替絢，使人哽咽。"]'),
('0c9b4440-10d6-421b-9916-25af0168081a','頤庵喜神贊','白玉蟾','宋','宋诗','song-poetry','','[]','江月射雙眼，巖雲飛兩眉。',69,'全唐诗/poet.song.208000.json','["江月射雙眼，巖雲飛兩眉。", "自是上饒一團和氣，點化自家方寸真機。", "能落筆作泣鬼神之詩，能坐石下爛柯之棋。", "千人萬人，瞻禮不已。", "笑騎白鹿，獨步天墀。"]'),
('5385fd10-8434-4845-9c50-9e2ac2da491c','隸軒真贊','白玉蟾','宋','宋诗','song-poetry','','[]','骨氣已神仙，玄圃挺生賢。',78,'全唐诗/poet.song.208000.json','["骨氣已神仙，玄圃挺生賢。", "面上四時春，心次一壺天。", "人皆就法門棟梁上踔他光景，我道隷軒高士志趣飄然。", "若也未知涯涘，爲君指出言詮。", "丹成若未歸蓬島，且結溪山風月緣。"]'),
('736e33cf-255a-46e3-8248-a423cde28aa1','潘龍游喜神贊','白玉蟾','宋','宋诗','song-poetry','','[]','龍章鳳姿，既非嵇叔夜。',58,'全唐诗/poet.song.208000.json','["龍章鳳姿，既非嵇叔夜。", "燕頷虎頸，又非班定遠。", "機鳴籟動，聽其自然。", "虛心何物，何增何損。", "花滿一壺春色好，半班頓露與人看。"]'),
('4ce7779b-247d-4ffc-84f6-6866ca7de024','郭信叔喜神贊','白玉蟾','宋','宋诗','song-poetry','','[]','萬丈崖頭立一梯，百丈竿頭垂一手。',78,'全唐诗/poet.song.208000.json','["萬丈崖頭立一梯，百丈竿頭垂一手。", "綿團裹鐵雲包月，麒麟海裏翻筋斗。", "回天拓地立教門，斬新氣概鼎乾坤。", "倪王人指碧溪水，盡是渠儂無盡恩。", "誰乎，沖靖之上足郭信叔者也。"]'),
('b77f0fee-15c6-4636-ac33-fc0c0fabc60b','薛直歲喜神贊','白玉蟾','宋','宋诗','song-poetry','','[]','和風滿面紫芝春，雙臉常如酒半醺。',64,'全唐诗/poet.song.208000.json','["和風滿面紫芝春，雙臉常如酒半醺。", "法籙把除符券柄，宗門立盡棟梁勳。", "鳳冠夜戴瓊林月，鶴氅朝披玉洞雲。", "自是神仙真氣象，多生曾是薛真君。"]'),
('5e2b0531-15ca-4e68-a1b1-0741b3a6df3e','木郎祈雨咒','白玉蟾','宋','宋诗','song-poetry','','[]','乾晶瑶輝玉池東，盟威聖者命青童。',306,'全唐诗/poet.song.208000.json','["乾晶瑶輝玉池東，盟威聖者命青童。", "擲火萬里坎震宮，雨騎迅發來太濛。", "木郎太乙三山雄，霹靂破石泉源通。", "神震巽土皓靈翁，猛馬四張㘞火衝。", "流精鬰光奔祝融，巨神泰華登雲中。", "墨旛皂纛揚虛空，掩曦蒸雨屯雲濃。", "閼伯撼動崑崙峯，幽靈翻海玄溟同。", "馮夷鼓舞長呼風，蓬萊弱水興都功。", "龍鷹捷疾先禦兇，朱髮巨翅雙目彤。", "雷電吐毒驅五龍，四溟靉靆羅陰容。", "一聲四海改昏蒙，雨陣所至川流洪。", "金光流精斬旱虹，洞陽幽靈召豐隆。", "玉雷浩師變崆峒，虛皇泰華掃妖爞。", "群梁玄黄號前鋒，祠泉恣蜃威天公。", "㘞火律令翻穹窿，鞭擊妖魅驅蛇蟲。", "勾婁吉利炎赫蹤，登僧澤頤悉聽從。", "織女四哥心公忠，輔我救旱助勛隆。", "赤鷄紫鵝飛無窮，攝虐縛祟送北酆。", "敕紫虛元君降攝，急急如火鈴大帥律令。"]'),
('607f484d-8a8e-4e7d-93cd-0c9b8888a26a','題清勝軒壁','白玉蟾','宋','宋诗','song-poetry','','[]','奇花兩朵香一爐，片心無事便清虛。',64,'全唐诗/poet.song.208000.json','["奇花兩朵香一爐，片心無事便清虛。", "壁頭有琴床有劍，浩歌梵曲聲虛徐。", "物外志趣本不俗，山軒清勝萬事足。", "自勸之酒三兩盃，無爭之棋三兩局。"]'),
('46931dcc-18aa-4ffc-8f8a-49cb44febdb1','題清虛堂','白玉蟾','宋','宋诗','song-poetry','','[]','月移花影來窗外，風引松聲到枕邊。',64,'全唐诗/poet.song.208000.json','["月移花影來窗外，風引松聲到枕邊。", "長劍舞餘烹茗試，新詩吟就抱琴眠。", "酒醅初潑青螺髓，香篆常燒紫馬鞭。", "九曲溪頭沖佑觀，清虛堂裏有神仙。"]'),
('3f448ba2-ad12-4c6c-9d8d-d0923a9c7c25','賦詩二首呈懶翁  其一','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','驚秋鏡裏鬢邊星，到處溪山皆洞庭。',64,'全唐诗/poet.song.208000.json','["驚秋鏡裏鬢邊星，到處溪山皆洞庭。", "怒雨打蓮欹沼綠，顛風掣竹過牆青。", "趁船紫燕辭芹渚，縮頸白鷗眠蓼汀。", "荷笠欲尋懶翁去，带些爽氣入疎櫺。"]'),
('070f9bfe-ff40-4e55-9669-4e017cd63dd2','賦詩二首呈懶翁  其二','白玉蟾','宋','宋诗','song-poetry','','[]','懶翁老白結忘年，秋入淡煙疎雨天。',80,'全唐诗/poet.song.208000.json','["懶翁老白結忘年，秋入淡煙疎雨天。", "醉把黑甜圓箇夢，時將草聖放些顛。", "杖藜還盡溪山債，盃酌結交風月緣。", "梭督青童馳訥槧，鱗煩紫吏饋雄篇。", "金華都似一楪大，却貯兩枚詩酒仙。"]'),
('49ee5613-b412-46f4-a9d3-2e4582b2dd23','暮抵懶翁齋醉吟','白玉蟾','宋','宋诗','song-poetry','','[]','旋開白酒買蓮房，滿瀉桐膏炤玉缸。',64,'全唐诗/poet.song.208000.json','["旋開白酒買蓮房，滿瀉桐膏炤玉缸。", "月女冷窺青斗帳，風神輕撼碧紗窗。", "公疑我是今皇甫，我恐公爲昔老龐。", "醉後唾珠粘紙面，笑將筆力與人扛。"]'),
('849e8bb8-9ad6-4675-b6a5-154d5537b6d9','白蓮詩','白玉蟾','宋','宋诗','song-poetry','','[]','淵明歸西天，不作東林社。',120,'全唐诗/poet.song.208000.json','["淵明歸西天，不作東林社。", "不見張昌宗，無人舉此話。", "誰家栽綠荷，薰風漾碧波。", "波底水晶空，化出玉姮娥。", "嫣然冷無語，冰肌卧曉雨。", "東君如夏日，此花不受暑。", "一點天然香，隨風入畫堂。", "折之置坐隅，窈窕弄玉郎。", "忽然心緒變，如覩佳人面。", "寄語明月樓，莫貯雙飛燕。"]'),
('d388b129-aeca-4e3a-bb85-856c6ba0501c','鍊丹不成','白玉蟾','宋','宋诗','song-poetry','','[]','八兩日月精，半斤雲霧屑。',96,'全唐诗/poet.song.208000.json','["八兩日月精，半斤雲霧屑。", "輕似一鴻毛，重如千枰鐵。", "白如天上雪，紅如猩猩血。", "收入玉葫蘆，秘之不敢泄。", "夜半忽風雷，煙氣滿寥泬。", "這般情與味，啞子咬破舌。", "捧腹付一笑，無使心腦熱。", "要整釣魚竿，再斫秋筠節。"]'),
('0215d5a1-5ddd-44e0-826c-dad78da9bad3','贈琴客陸元章','白玉蟾','宋','宋诗','song-poetry','','[]','手持一枚寒水晶，十指擊戛如玉鳴。',80,'全唐诗/poet.song.208000.json','["手持一枚寒水晶，十指擊戛如玉鳴。", "曲彈白雪陽春調，調有高山流水聲。", "松梢鶴唳恰夜半，寒煙寂寂風泠泠。", "紙衾瓦枕冷如水，展轉無夢睡不成。", "起來搔首撫一闋，吟罷滿山秋月明。"]'),
('8c36f800-eda2-456b-a49b-2907f0146c51','倪昭卿賦贈葉神童  其一','白玉蟾','宋','宋诗','song-poetry','','[]','神童之貌清且奇，神童之道傳希夷。',128,'全唐诗/poet.song.208000.json','["神童之貌清且奇，神童之道傳希夷。", "入室三年丹已熟，肌膚綽約光離離。", "結繒自覆有餘樂，曄曄紫芝堪療饑。", "跳入壺中人莫見，朝遊五嶽暮瑶池。", "有時混世來塵境，短髮鬅鬙滿面垂。", "頃刻龍蛇生筆下，爲將高興寄新詩。", "我疑虛靜樂山水，來歸舊隠掛冠緌。", "願策浮雲飛碧落，致身絳闕長相隨。"]'),
('b7df6aaa-958d-4ac4-b1bf-b6fb95b24e4d','倪昭卿賦贈葉神童  其二','白玉蟾','宋','宋诗','song-poetry','','[]','神童天縱何聰明，十幅一息增榮名。',96,'全唐诗/poet.song.208000.json','["神童天縱何聰明，十幅一息增榮名。", "若非唐朝李太白，靖通真人當復生。", "擊石轟雷驚四座，寶卷拈出安群情。", "八卦五行有妙用，金丹大藥自然成。", "布衲蹁躚賤羅綺，銀鈎婉娩鬼神驚。", "仙山便好留仙佩，何必蓬萊頂上行。"]'),
('3b0b781a-eb34-4fd0-b11f-260a94040ac2','憶神童歌','白玉蟾','宋','宋诗','song-poetry','','[]','高懷落落如可羈，芳辭葳蕤誰摘奇。',208,'全唐诗/poet.song.208000.json','["高懷落落如可羈，芳辭葳蕤誰摘奇。", "我獨一覽如醉癡，恨不快覩紫芝眉。", "望美人兮天一涯，面不相識心相知。", "青牛不跨策蒺藜，金波停飲忘醇醨。", "句高耿耿橫虹蜺，列星北斗不敢輝。", "玄猿號木驥縮蹄，霜鶻攣翼鬼神悲。", "天籟自鳴非噓吹，肯與蛙蚓湫污泥。", "何當握手談玄機，蟠桃未熟香難期。", "金牌玉字空陸離，碧雲謾鎖騫林枝。", "謫籍塵寰辭玉墀，凡埃俗氣非所宜。", "世緣未了如沸糜，徒將姹女媒嬰兒。", "丹霄玉詔何時飛，青鸞久約宴瑶池。", "他年騎鹿相追隨，玉笥山前同採芝。"]'),
('e567dd6e-9080-431e-b63a-b29d74edd886','贈蕊珠侍經潘常吉','白玉蟾','宋','宋诗','song-poetry','','[]','一點紅塵惹人心，蘂珠殿上墮遺簪。',64,'全唐诗/poet.song.208000.json','["一點紅塵惹人心，蘂珠殿上墮遺簪。", "當時同降瑶臺路，祇是于今彭鶴林。", "夢到人間不知退，夜夜窗下調玉琴。", "笑指神霄歸未得，絳闕清都煙靄深。"]'),
('85b5fbf5-3d30-46b8-b369-078d7d237514','贈紫華侍經周希清','白玉蟾','宋','宋诗','song-poetry','','[]','螓首蛾眉天上人，不知何事到紅塵。',64,'全唐诗/poet.song.208000.json','["螓首蛾眉天上人，不知何事到紅塵。", "神霄蘂笈今誰侍，紫府琪花不敢春。", "無夢去陪王母宴，前生多是紫虛身。", "寄言尋取蓬萊路，風送雙鸞上太旻。"]'),
('c6603eef-8466-4fec-a6d7-80554b725288','萬法歸一歌','白玉蟾','宋','宋诗','song-poetry','','[]','金丹大藥妙無窮，一點丹頭內外紅。',384,'全唐诗/poet.song.208000.json','["金丹大藥妙無窮，一點丹頭內外紅。", "真汞真鉛纔入手，片時伏虎活擒龍。", "黄公聘入丁公舍，巽位吹噓九轉功。", "十月胎圓坎離外，紫雲飛出玉爐空。", "短褐包巾滿廛市，尋草燒茅烹藥柜。", "自己三黄及四神，誰知安竈烹爐意。", "紙襖麻衣要隠山，餐松飲水守饑寒。", "日魂月魄空呼吸，到底方知入道難。", "黑山山下鬼窟裏，背曲頭垂口流水。", "夢中夢見夢中人，幾時待得硫黄死。", "薄福癡人不斷淫，尾閭閉了採他陰。", "元精摇撼無牆壁，錯認黄泥喚作金。", "容成三峯學御女，採精吸血兼服乳。", "大道本來無陰陽，勞形著相徒自苦。", "叩齒吞精咽氣聲，轆轤空動髑髏形。", "妄將口鼻爲玄牝，謾說金精肘後盈。", "鼻頭閉息空畫餠，幾人日中逃得影。", "客風邪氣肚中鳴，安得長靈砂在鼎。", "參禪見性契真如，莫道無心便靠虛。", "悟了不行乾智慧，千崖萬壑涉程途。", "多少老儒學周易，豈知太極歸無極。", "忘形便欲任天真，只恐春歸草無力。", "明教專門事滅魔，七時功德便如何。", "不知清凈光明意，面色痿黄空自磨。"]'),
('341c34ba-c887-4167-ac88-d2c2a9fabacc','武夷歌','白玉蟾','宋','宋诗','song-poetry','','[]','天下武夷兮第一山溪，昇真有洞兮大王天柱交相齊。',462,'全唐诗/poet.song.208000.json','["天下武夷兮第一山溪，昇真有洞兮大王天柱交相齊。", "不知何年中秋兮玉帝賜宴會曾孫，幔亭結雲霞兮綵橋跨虹霓。", "欲訪仙蹟兮搜剔地靈，遡洄乘舟兮陟險杖藜。", "身輕欲生羽翰兮捫煙蘿而躡天梯，下視人境杳邈兮但見亂峯參錯相高低。", "龍洞通天池兮巖鶴舞雙翎，鐵骨藏玉匣兮玉蛻和香泥。", "月浸觀音石兮恍有金身現普陀，風號玉女峯兮疑是湘江虞妃啼。", "仙館學堂兮聞書聲，丹爐茶竈兮曉煙迷。", "船架半壑兮使星會泛河漢歸，機留古洞兮天孫去作牽牛妻。", "棋盤開巖石兮釣臺瞰晴川，巖有虎嘯兮窠有金雞棲。", "獅子伏巖兮耀日氣猶鮮，仙羊化石兮眠雲青草萋。", "大小藏藴靈異兮下有龍湫水泠泠，一線天通九有兮旁有風洞凉凄凄。", "翰墨羅列兮因之生興，廩石高貯兮可以忘饑。", "紅塵迥絕兮山中發蘭桂，神仙何許兮雲間聞犬雞。", "茶洞幽窅兮懸崖飛瀑布，桃源深邃兮沿流得徑蹊。", "有人卜居大隠屏兮學宗周孔事鹽虀，但見此心止止兮煉成大藥服刀圭。", "武夷君去後兮有十三仙之同時，代不乏人之兮仙階陸續躋。", "或尸解兮隻履歸去，或飛昇兮鐵笛長嘶。", "以今視昔兮吳李可接踵，不須懷古兮感慨而愴悽。", "作詩勉同志兮欲倩仙掌摩丹崖，我醉揮椽筆兮大書特書而留題。"]'),
('9645a96f-fd94-4106-8561-32d9658c871c','金液大還丹','白玉蟾','宋','宋诗','song-poetry','','[]','烏兔乾坤鼎，龜蛇復姤壇。',72,'全唐诗/poet.song.208000.json','["烏兔乾坤鼎，龜蛇復姤壇。", "世間無事客，心內大還丹。", "白虎水中吼，青龍火裏蟠。", "汞鉛泥蘂艷，金木雪花寒。", "離坎非心腎，東西不肺肝。", "三旬窮七返，九轉出泥丸。"]'),
('609e3aac-dca1-4e37-8278-b6d72025cb64','題桐柏觀','白玉蟾','宋','宋诗','song-poetry','','[]','淡月籠蒼松，清流蘸脩竹。',24,'全唐诗/poet.song.208000.json','["淡月籠蒼松，清流蘸脩竹。", "水深蟾不設，長伴道人宿。"]'),
('fa3d9750-04e6-4999-8a89-531e9df88417','贈天慶觀','白玉蟾','宋','宋诗','song-poetry','','[]','買得螺江一葉舟，功名如蠟何休休。',64,'全唐诗/poet.song.208000.json','["買得螺江一葉舟，功名如蠟何休休。", "我無曳尾乞憐態，早作灰心不仕謀。", "已學漆園耕白兆，甘爲關令候青牛。", "刀圭底事憑誰會，明月清風爲點頭。"]'),
('46026cfa-6cba-4025-bba7-26d68e1f9264','題嶽祠','白玉蟾','宋','宋诗','song-poetry','','[]','南來一劍住三山，分得平生風月懽。',64,'全唐诗/poet.song.208000.json','["南來一劍住三山，分得平生風月懽。", "雖宰旌陽應施藥，本求勾漏爲脩丹。", "蒙莊且慕漆園祿，李老嘗爲柱下官。", "我視榮華真慣見，何如早煉碧琅玕。"]'),
('0cc81a79-5184-4cc6-802c-9ba8b6044fd3','桐柏觀留別','白玉蟾','宋','宋诗','song-poetry','','[]','身落天台古洞天，蒲團未暖又飄然。',64,'全唐诗/poet.song.208000.json','["身落天台古洞天，蒲團未暖又飄然。", "如何菴不瓊臺地，想是吾非桐柏仙。", "無復得餐三井水，未曾深結九峯緣。", "杖頭挑月下山去，空使寒猿嘯曉煙。"]'),
('5af0e6af-171a-4750-b574-9d04b76c87df','龍井','白玉蟾','宋','宋诗','song-poetry','','[]','山腰石有千年潤，海眼泉無一日乾。',32,'全唐诗/poet.song.208000.json','["山腰石有千年潤，海眼泉無一日乾。", "天下蒼生望霖雨，不知龍在此中蟠。"]'),
('003517e2-a59c-4115-8d8c-881e5b7c8ca7','題桐柏觀','白玉蟾','宋','宋诗','song-poetry','','["\u8861\u5c71"]','仙翁夜來扣林壑，約我明朝過南嶽。',32,'全唐诗/poet.song.208000.json','["仙翁夜來扣林壑，約我明朝過南嶽。", "石壇對坐話松風，鶴唳一聲山月落。"]'),
('928fc975-7b63-46f2-9d6e-d27365ace162','西林入室歌','白玉蟾','宋','宋诗','song-poetry','','[]','有一明珠光爍爍，照破三千大千國。',240,'全唐诗/poet.song.208000.json','["有一明珠光爍爍，照破三千大千國。", "觀音菩薩正定心，釋迦如來大圓覺。", "或如春色媚山河，或似秋光爽巖壑。", "亦名九轉大還丹，謂之長生不死藥。", "步步華嚴妙宮殿，重重彌勒寶樓閣。", "牆壁瓦礫相渾融，水鳥樹林共寥廓。", "缺唇石女駕土牛，跛脚木人騎紙鶴。", "三業三毒雲去來，六根六塵月綽約。", "所以然者本體空，誰言何似當初莫。", "此珠價大實難酬，不許巧錐妄穿鑿。", "若要秘密大總持，只於寂滅中摸索。", "幾多衲子聽蟄雷，幾箇道人藏尺蠖。", "茫茫盡向珠外求，不知先天那一著。", "何須重注脚注脚，也不惡好呵兄弟。", "杜宇聲隨曉雨啼，海棠夜聽東風落。"]'),
('764e749c-ffc4-4a3a-8773-d3a7f6545004','金丹火候訣','白玉蟾','宋','宋诗','song-poetry','','[]','攢簇乾坤造化來，手摶日月煉成灰。',80,'全唐诗/poet.song.208000.json','["攢簇乾坤造化來，手摶日月煉成灰。", "金公無言姹女死，黄婆不老猶懷胎。", "鉛爐慢養真金液，土釜先乾活水銀。", "汞心煉神亦龍性，鉛身凝氣白虎命。", "內外渾無一點陰，萬象光中玉清鏡。"]'),
('4f47562e-3c14-4fa3-92e4-8b5d8d669d8d','金丹大藥訣','白玉蟾','宋','宋诗','song-poetry','','[]','離府龍飛，坎宮虎躍。',80,'全唐诗/poet.song.208000.json','["離府龍飛，坎宮虎躍。", "金木混融，水火擊搏。", "刑德主寶，浮沉清濁。", "一百日胎，二八兩藥。", "白雪虛無，黄芽圓覺。", "烏兔夫妻，龜蛇根萼。", "朱砂不動，水銀無著。", "鉛鼎純乾，紫霄雲約。"]'),
('14e99e4a-9409-400f-bb60-b085a3d26fdf','步虛','白玉蟾','宋','宋诗','song-poetry','','[]','玉殿朝回夜已深，三千世界靜沉沉。',64,'全唐诗/poet.song.208000.json','["玉殿朝回夜已深，三千世界靜沉沉。", "微微花雨粘琪樹，浩浩天風動寶林。", "煙鎖崑崙山上頂，月明娑竭海中心。", "步虛聲斷一回首，十二樓臺何處尋。"]'),
('e5e2d58a-3142-4bed-8704-66eaec1a35d4','題福海院','白玉蟾','宋','宋诗','song-poetry','','[]','廬阜新蘭若，龍天古道場。',72,'全唐诗/poet.song.208000.json','["廬阜新蘭若，龍天古道場。", "殿粧金彩煥，佛放白毫光。", "竹長真如翠，花開般若香。", "禪波風浩浩，慈陰日穰穰。", "鼻祖共毫老，中興乃谷堂。", "僧勤今繼志，萬載一爐香。"]'),
('2ffbb9d8-9181-4e45-b33f-19e69dc9317f','番陽旅寓留題','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','洞門深鎖綠煙寒，來享浮生半日閑。',32,'全唐诗/poet.song.208000.json','["洞門深鎖綠煙寒，來享浮生半日閑。", "城北城南無老樹，橫吹鐵笛過廬山。"]'),
('eda9f36c-29b6-4a11-95ad-f94d42f88e02','初夏','白玉蟾','宋','宋诗','song-poetry','','[]','城中厭雨過清和，偶出西郊野興多。',32,'全唐诗/poet.song.208000.json','["城中厭雨過清和，偶出西郊野興多。", "蠶簇趁晴方摘繭，麥場經潤欲生蛾。"]'),
('8c77fc6e-3251-41d0-a905-764a52f0184a','立春','白玉蟾','宋','宋诗','song-poetry','','[]','東風吹散梅梢雪，一夜挽回天下春。',32,'全唐诗/poet.song.208000.json','["東風吹散梅梢雪，一夜挽回天下春。", "從此陽春應有脚，百花富貴草精神。"]'),
('eeb64706-a07d-4e7d-8100-cdfb66d65ce4','琴','白玉蟾','宋','宋诗','song-poetry','','[]','雲水一生無別好，琴心三疊有誰知。',32,'全唐诗/poet.song.208000.json','["雲水一生無別好，琴心三疊有誰知。", "今宵松殿相期會，彈到西山月落時。"]'),
('89296669-cecd-4957-b5ad-4057605f312a','燕','白玉蟾','宋','宋诗','song-poetry','','[]','新巢故園兩依依，似與春花秋葉期。',64,'全唐诗/poet.song.208000.json','["新巢故園兩依依，似與春花秋葉期。", "雨過池塘得泥跡，日高臺榭卷簾遲。", "秋千節後初相見，祓禊人歸有所思。", "雙侶多情擬憑仗，小箋封就碧雲詩。"]'),
('7a5d797c-68e6-46e4-ba92-94a58da5d995','鴈陣','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','幾是霜翎巢白草，數行雲足篆青冥。',32,'全唐诗/poet.song.208000.json','["幾是霜翎巢白草，數行雲足篆青冥。", "方將寄字來苕霅，莫便翻身過洞庭。"]'),
('268c7ab3-ff37-4aca-b82a-5eda423f94ae','演教堂','白玉蟾','宋','宋诗','song-poetry','','[]','洞霄大滌扈神京，玉珮金璫會百靈。',64,'全唐诗/poet.song.208000.json','["洞霄大滌扈神京，玉珮金璫會百靈。", "天柱一尖凌碧落，雲關九鎖疊蒼屏。", "前峯後峯煙漠漠，東洞西洞風泠泠。", "見說坡仙詩墨在，約君同坐翠蛟亭。"]'),
('c26d3115-4d56-4a6c-9e20-9b41bbaac307','洞庭','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','帆腹膨脝飽北風，一彈指頃萬山空。',64,'全唐诗/poet.song.208000.json','["帆腹膨脝飽北風，一彈指頃萬山空。", "天垂九馬層雲外，人在孤鴻過影中。", "夙世曾遊銀世界，飛精復謁水精宮。", "湖神波吏須相識，吾在神霄舊有功。"]'),
('0e6d294e-8376-4ace-be5f-caf5d1c58bb9','贈沖虛鄒道士','白玉蟾','宋','宋诗','song-poetry','','[]','吾師有道貌，山水箇中人。',48,'全唐诗/poet.song.208000.json','["吾師有道貌，山水箇中人。", "無著故無累，是清還是真。", "煙霞供笑詠，泉石瀹精神。", "何日分峯隠，誅茅願卜鄰。"]'),
('a4f9f72c-a642-459c-ae4d-72be84170f6c','次水簾洞韻','白玉蟾','宋','宋诗','song-poetry','','[]','天上真珠直下垂，更無鉤箔惹塵埃。',64,'全唐诗/poet.song.208000.json','["天上真珠直下垂，更無鉤箔惹塵埃。", "青鸞白鶴從教入，紫詔黄封不用來。", "夜月祇爲蘇鄺照，晚風端與葛黄開。", "縱饒展掛長千尺，莫掩羅浮紫翠堆。"]'),
('218bc684-caf3-4d97-ad17-7eb5b2ffb9ad','飛雲頂','白玉蟾','宋','宋诗','song-poetry','','[]','飛雲頂上閣闌干，夜半南溟出玉盤。',32,'全唐诗/poet.song.208000.json','["飛雲頂上閣闌干，夜半南溟出玉盤。", "捲起水簾三百尺，松風吹度鐵橋寒。"]'),
('95a8aec5-a534-444c-abb1-2cb72aa1ddd5','羅浮歌朝斗回作','白玉蟾','宋','宋诗','song-poetry','','[]','紫霄飛步謁瓊樓，回首人間祇一周。',64,'全唐诗/poet.song.208000.json','["紫霄飛步謁瓊樓，回首人間祇一周。", "雲繞崑崙山上起，月沉娑竭水中浮。", "香煙欲斷歸來早，羽駕相迎未敢留。", "盡洗塵緣知熟路，瑶池花木未應秋。"]'),
('60e649f7-c5c1-4446-ba87-ca109cb06b14','青華吟','白玉蟾','宋','宋诗','song-poetry','','[]','羅浮山中春晝長，風吹蘭花滿面香。',240,'全唐诗/poet.song.208000.json','["羅浮山中春晝長，風吹蘭花滿面香。", "博山香斷一欹枕，飛神直到玉帝旁。", "火鈴將軍同直舍，忽覺羽衣驚羽駕。", "三千神女笑回眸，整裾端簡龍墀下。", "奏言臣昔因饕酒，醉墮紅塵如此久。", "袖藏一卷玉雷書，進前再拜重稽首。", "今朝天開九虎關，乃將見帝玉槃顔。", "令臣奏畢速回首，下界一去思帝難。", "此時侍仙小黄散，手執金書貼玉版。", "精神縹緲素光中，不覺瓊文照心眼。", "於中最妙何所言，青霞命下龍臺昏。", "脚撥南辰開地脈，掌翻北斗透天門。", "香煙未滅烏雲走，風驅火豬逐鐵狗。", "紫童飛出碧霄中，劍光祇見雷聲吼。", "夢回無人可與言，一嘯天地陰晴分。"]'),
('953cf2f9-6f3c-4bf6-9123-d60b46f03f0a','桃源祠','白玉蟾','宋','宋诗','song-poetry','','[]','因訪翟仙傍柳隈，不堪風景把人推。',64,'全唐诗/poet.song.208000.json','["因訪翟仙傍柳隈，不堪風景把人推。", "松杉十丈入斤斧，夏屋數間俱劫灰。", "道士潛心隠丹竈，兒童勸我舉霞杯。", "誰知自有長生訣，獨步白雲歸去來。"]'),
('e997fafc-7425-4139-93fc-5a9209e57501','白鶴觀','白玉蟾','宋','宋诗','song-poetry','','[]','琅庭珍館一何清，四壁如銀窗更明。',128,'全唐诗/poet.song.208000.json','["琅庭珍館一何清，四壁如銀窗更明。", "雨餘草色欺苔色，風送松聲雜澗聲。", "芍藥花開今四月，杜鵑啼恨到三更。", "我來暫息白鶴觀，憶著故人劉混成。", "松殿空遺金鳳舞，芝田不見鐵牛耕。", "雲迷古洞虎狼吼，煙鎖平林鳥雀驚。", "日暮山屏增紫翠，曉來天籟自簫笙。", "杖頭挑月過山北，要趁如今幾日晴。"]'),
('368ee4ce-e885-44f3-b851-9eecb9a25823','三級泉','白玉蟾','宋','宋诗','song-poetry','','[]','緣溪深入桃花塢，紫霞隠隠幽禽語。',352,'全唐诗/poet.song.208000.json','["緣溪深入桃花塢，紫霞隠隠幽禽語。", "九層峭壁剗春空，三級鳴泉飛暮雨。", "落日銜山紅影濕，冷雲抱石蒼崖古。", "激回澗底散冰花，噴上松梢雪飄縷。", "點點濺濕嫦娥衣，潭潭下有扶桑府。", "朝來似展朝天带，夜半如聞搗藥杵。", "寒入山骨吼千雷，派出銀河轟萬鼓。", "廣寒殿上銀蟾飛，水晶宮中玉龍舞。", "瓊英斧碎非月老，瀑布天成非織女。", "初疑魚鼈謁龍門，復恐星辰會牛渚。", "欲尋當下點額蛟，但見天上拖腸鼠。", "溶溶浸此一潭霜，滴滴結凍千歲乳。", "月照神珠灑翠麟，風吹天粟沾蒼虎。", "瑶虹界碧翻地軸，鐵馬盤渦捲天宇。", "谷草凝煙色凈明，野猿悲露聲清苦。", "綠苔鎖逕阻清遊，白鶴凌霄喚沖舉。", "紫元景曜神府君，仙靈詠其洞天主。", "畫屏幻出金芙蓉，仙杯琢就石鸚鵡。", "當時此地蔡尋真，青鸞一去今何許。", "錦閣憑空銀海寒，宸書麗天丹鳳翥。", "竹爐燒起紫旃檀，古琴嗚咽鳴中呂。", "曲罷蕭蕭天籟動，長笑一聲朝帝所。"]'),
('8c9d2624-25ea-42ef-9bca-9ab4c89b8fe7','山中偶成  其一','白玉蟾','宋','宋诗','song-poetry','','[]','酒惡頻頻嗅素馨，滿天風雨晚凉生。',32,'全唐诗/poet.song.208000.json','["酒惡頻頻嗅素馨，滿天風雨晚凉生。", "巖花亂落無一點，谷鳥時聞啼數聲。"]'),
('e03923fb-b5c3-48e9-9258-6ac798b95d61','山中偶成  其二','白玉蟾','宋','宋诗','song-poetry','','[]','長日扃門坐小亭，松陰竹影自清清。',32,'全唐诗/poet.song.208000.json','["長日扃門坐小亭，松陰竹影自清清。", "山翁莫問吾名姓，天上星辰地下行。"]'),
('74915466-52e1-425e-ba9a-7e30ef4bd8df','七女峰','白玉蟾','宋','宋诗','song-poetry','','[]','宋時松竹晉時苔，路轉山迴洞戶開。',32,'全唐诗/poet.song.208000.json','["宋時松竹晉時苔，路轉山迴洞戶開。", "流水也知塵世雜，依然流向此山來。"]'),
('27ae6653-048d-419c-b388-ea2a7e635c0b','洞庭廟','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','檣烏啼罷紙灰飛，神去神來人不知。',32,'全唐诗/poet.song.208000.json','["檣烏啼罷紙灰飛，神去神來人不知。", "惟有金沙堆下水，東西南北任風吹。"]'),
('05620bae-379e-48af-bca3-82900404c3ae','畫石二首  其一','白玉蟾','宋','宋诗','song-poetry','','[]','一片嵯峨墮碧空，嶔崎歷落最玲瓏。',32,'全唐诗/poet.song.208000.json','["一片嵯峨墮碧空，嶔崎歷落最玲瓏。", "從教把翫真堪醉，疑自當年栗里中。"]'),
('46ebb4b2-ac1b-4c9a-a00e-7b4fd78d511d','畫石二首  其二','白玉蟾','宋','宋诗','song-poetry','','[]','直作壺中九華看，碧于簪玉小于拳。',32,'全唐诗/poet.song.208000.json','["直作壺中九華看，碧于簪玉小于拳。", "好藏莫便令人見，恐有癡情似米顛。"]'),
('0f64bbb1-52ec-4d47-b3ae-8adf6c806949','詩一首','白玉蟾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','月冷松寒露滿襟，天容紺碧鶴聲沉。',32,'全唐诗/poet.song.208000.json','["月冷松寒露滿襟，天容紺碧鶴聲沉。", "夜深獨把闌干拍，只有長江識此心。"]'),
('1a1d9cfa-e9d1-44b9-a121-10a290b16a00','鳳凰臺','白玉蟾','宋','宋诗','song-poetry','','[]','鳳去臺空事尚存，晨鐘暮鼓換罏薰。',64,'全唐诗/poet.song.208000.json','["鳳去臺空事尚存，晨鐘暮鼓換罏薰。", "魚龍吞吐四海水，鸞鶴歌嘯三天雲。", "花覺月寒春又老，沙知潮落夜將分。", "紫霞真人去路杳，步虛一聲聞不聞。"]'),
