('aa65fa25-e0cf-4528-a41e-88da0c32b710','夜船與白玉蟾聯句回文','黎盤雲','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.208000.json','["無正文。"]'),
('1b86ecfd-d85e-4c3b-aedb-199648f53ce0','偈頌一百五十首  其一','釋心月','宋','宋诗','song-poetry','','[]','寰中天子勑，塞外將軍令。',34,'全唐诗/poet.song.208000.json','["寰中天子勑，塞外將軍令。", "佛祖出頭，也須乞命。", "今日合作麽生，將逐符行。"]'),
('2e83f214-44a3-4924-9a59-e2b34dfc0ef6','偈頌一百五十首  其二','釋心月','宋','宋诗','song-poetry','','[]','披牯牛皮，輥瞎馿隊。',28,'全唐诗/poet.song.208000.json','["披牯牛皮，輥瞎馿隊。", "带水拖泥，東倒西㹠。", "黄梅七百無人會。"]'),
('5bf5097a-05b9-46c5-86ad-49839536b745','偈頌一百五十首  其三','釋心月','宋','宋诗','song-poetry','','[]','元正啟祚，萬物咸新。',46,'全唐诗/poet.song.208000.json','["元正啟祚，萬物咸新。", "山形拄丈子，只麽黑鱗皴，時來也解笑翻身。", "倒腹傾腸爲君說，唱歌須是帝鄉人。"]'),
('f5371d9b-10a7-4025-bfc0-eb81b6711125','偈頌一百五十首  其四','釋心月','宋','宋诗','song-poetry','','[]','忌口自然諸病減，多情未免有時勞。',32,'全唐诗/poet.song.208000.json','["忌口自然諸病減，多情未免有時勞。", "貧居動便成違順，只得清閑一味高。"]'),
('f93576bc-ef90-401e-ac87-dbdb73a6e935','偈頌一百五十首  其五','釋心月','宋','宋诗','song-poetry','','[]','連城之璧本無瑕，何事生來便撒沙。',32,'全唐诗/poet.song.208000.json','["連城之璧本無瑕，何事生來便撒沙。", "跛脚阿師知落處，好冤家有惡冤家。"]'),
('7e2e2145-e9fd-4acf-b126-4ed49b65a482','偈頌一百五十首  其六','釋心月','宋','宋诗','song-poetry','','[]','金烏飛，玉兔走。',29,'全唐诗/poet.song.208000.json','["金烏飛，玉兔走。", "目前事，看不透。", "十日前，五日後，誰敢咳嗽。"]'),
('57d89882-f63b-4d7a-a9c3-80f5061c4bcc','偈頌一百五十首  其七','釋心月','宋','宋诗','song-poetry','','[]','無背面，有孔竅，轉相親，轉料掉。',34,'全唐诗/poet.song.208000.json','["無背面，有孔竅，轉相親，轉料掉。", "鳳臺平，石城小。", "日下孤燈，果然失照。"]'),
('f5ddad47-2683-4e29-9cf9-c2cca7aede69','偈頌一百五十首  其八','釋心月','宋','宋诗','song-poetry','','[]','竺土大僊心，東西密相付。',24,'全唐诗/poet.song.208000.json','["竺土大僊心，東西密相付。", "謹白參玄人，光陰莫虛度。"]'),
('d27e2fb6-5117-4a20-8537-f6036ad9736e','偈頌一百五十首  其九','釋心月','宋','宋诗','song-poetry','','[]','與麽則易，不與麽則難。',38,'全唐诗/poet.song.208000.json','["與麽則易，不與麽則難。", "不與麽則易，與麽則難。", "金烏飛上玉欄干，眨上眉毛子細看。"]'),
('6f2a9b9a-db88-4e5b-8c41-feb7e6853a12','偈頌一百五十首  其一○','釋心月','宋','宋诗','song-poetry','','[]','上刀山，攀劍樹。',44,'全唐诗/poet.song.208000.json','["上刀山，攀劍樹。", "雙暗雙明，裂開捻聚。", "倒跨楊岐三脚馿，踢斷巖頭末後句。", "誰是其人，目前薦取。"]'),
('1416fdc8-de13-43fa-bab7-d77c195f3023','偈頌一百五十首  其一一','釋心月','宋','宋诗','song-poetry','','[]','一即三，三即一。',38,'全唐诗/poet.song.208000.json','["一即三，三即一。", "剩則不足，少則有餘。", "相續得去底，道將一句來。", "七十三，八十四。"]'),
('24eb6241-419e-40b5-800e-5db1aad50371','偈頌一百五十首  其一二','釋心月','宋','宋诗','song-poetry','','[]','一葉落，天下秋，布袋今朝又解頭。',32,'全唐诗/poet.song.208000.json','["一葉落，天下秋，布袋今朝又解頭。", "古路不曾生寸草，慈明何事過汾州。"]'),
('ea0e94d1-a664-456f-8ab8-e7a3dfd6d53a','偈頌一百五十首  其一三','釋心月','宋','宋诗','song-poetry','','[]','夜寒錯認定盤星，金屑霏霏翳眼睛。',32,'全唐诗/poet.song.208000.json','["夜寒錯認定盤星，金屑霏霏翳眼睛。", "教壞平人至今日，惺惺剗地不惺惺。"]'),
('758aa656-f079-476a-9347-14f0b8fb758f','偈頌一百五十首  其一四','釋心月','宋','宋诗','song-poetry','','[]','頻頻喚汝不歸家，貪向門前撮土沙。',32,'全唐诗/poet.song.208000.json','["頻頻喚汝不歸家，貪向門前撮土沙。", "每到年年三月裏，滿城開盡牡丹花。"]'),
('ee2a6985-2e92-4dd1-8207-eaf9a3b05d11','偈頌一百五十首  其一五','釋心月','宋','宋诗','song-poetry','','[]','九旬禁足，三月護生。',46,'全唐诗/poet.song.208000.json','["九旬禁足，三月護生。", "護生須殺，禁足須行。", "雲收天迥，雨過山青。", "出門句裏入門句，鼻直眼橫眉亦橫。"]'),
('e97a9693-2033-4029-aad3-4c31947c5678','偈頌一百五十首  其一六','釋心月','宋','宋诗','song-poetry','','[]','一夏三箇月，已過兩箇月。',36,'全唐诗/poet.song.208000.json','["一夏三箇月，已過兩箇月。", "子細好生觀，只餘一箇月。", "說與林下人，莫空度歲月。"]'),
('57c5eb36-4ffa-4869-a358-8449c62f7eed','偈頌一百五十首  其一七','釋心月','宋','宋诗','song-poetry','','[]','一九二九，百拙千醜。',40,'全唐诗/poet.song.208000.json','["一九二九，百拙千醜。", "昨日今朝，地迥天寥。", "少林門下客，立處雪齊腰，千載令人恨不消。"]'),
('553428a1-5c29-412a-a91f-622b15ab3a5a','偈頌一百五十首  其一八','釋心月','宋','宋诗','song-poetry','','[]','打圓相，女人拜。',40,'全唐诗/poet.song.208000.json','["打圓相，女人拜。", "老楊岐，偏捏怪，依稀兔子喫牛奶。", "今日薰香瀹盞茶，豈是貧人思舊債。"]'),
('c4e3e9c0-08a6-4059-99f8-dbf84a2846a8','偈頌一百五十首  其一九','釋心月','宋','宋诗','song-poetry','','[]','一夜春風浩浩，拂盡千花百草。',30,'全唐诗/poet.song.208000.json','["一夜春風浩浩，拂盡千花百草。", "十二危樓一倚欄，珊瑚枝頭日杲杲。"]'),
('49be0762-b82a-416c-b4a8-549dc6419deb','偈頌一百五十首  其二○','釋心月','宋','宋诗','song-poetry','','[]','拄杖子，無規繩，有準則。',26,'全唐诗/poet.song.208000.json','["拄杖子，無規繩，有準則。", "長不得，短不得，恰好亦不得。"]'),
('337c2d3e-5058-4673-b0cd-b9108deacae5','偈頌一百五十首  其二一','釋心月','宋','宋诗','song-poetry','','[]','得也與麽，未得也與麽。',37,'全唐诗/poet.song.208000.json','["得也與麽，未得也與麽。", "寒灰燒殺人，冷地不可卧。", "丹霞燒木佛，因甚院主眉鬚墮。"]'),
('3d1ddeb6-d061-4eda-a60d-c58de6e9cacd','偈頌一百五十首  其二二','釋心月','宋','宋诗','song-poetry','','[]','六陰剝，一陽復。',34,'全唐诗/poet.song.208000.json','["六陰剝，一陽復。", "寒谷交肩，春容可掬。", "少室山高難措足，斷絃須是鸞膠續。"]'),
('369e0a0a-28fc-4e72-847e-6c3e0c386726','偈頌一百五十首  其二三','釋心月','宋','宋诗','song-poetry','','[]','閙中靜悄悄，靜中閙浩浩。',42,'全唐诗/poet.song.208000.json','["閙中靜悄悄，靜中閙浩浩。", "側耳聽不聞，舉步行不到。", "沒誵訛，勿尋討。", "鴉作鴉鳴，鵲作鵲噪。"]'),
('8a7fa26d-c165-4651-b543-15ce3de602fb','偈頌一百五十首  其二四','釋心月','宋','宋诗','song-poetry','','[]','至人無己，言猶在耳。',38,'全唐诗/poet.song.208000.json','["至人無己，言猶在耳。", "萬法作本根，天地相終始。", "一占帝與九齡夢，三聽山呼萬歲聲。"]'),
('0f289d4a-83a0-43df-888d-d4e06317b902','偈頌一百五十首  其二五','釋心月','宋','宋诗','song-poetry','','[]','九年面壁，有理難伸。',68,'全唐诗/poet.song.208000.json','["九年面壁，有理難伸。", "三日耳聾，無辭可措。", "堪悲堪笑，自昔自今。", "盡道以心傳心，一向將錯就錯。", "年代深遠，疑案難稽。", "既然呷汁罪同，合與一狀領過。"]'),
('c765f4c7-16fb-4474-a66d-44b784304f5e','偈頌一百五十首  其二六','釋心月','宋','宋诗','song-poetry','','[]','月不破五，歲不滿百。',45,'全唐诗/poet.song.208000.json','["月不破五，歲不滿百。", "窄處放教寬，寬處捻教窄。", "如沖天之俊鷂，如當路之白額。", "敢有近傍者麽，骼。"]'),
('da7a5f4e-9099-4da7-9e1c-bd531d3949d2','偈頌一百五十首  其二七','釋心月','宋','宋诗','song-poetry','','[]','九十日安居，二千年聖制。',62,'全唐诗/poet.song.208000.json','["九十日安居，二千年聖制。", "念念三世十方，步步十方三世。", "何如閙市裏保壽面目全露，肉案頭盤山自心密契。", "使府近有指揮，不許攀條援例。"]'),
('be633c58-c06e-4f50-b2aa-ffe28752d70d','偈頌一百五十首  其二八','釋心月','宋','宋诗','song-poetry','','[]','六月火邊坐，有眼無耳朶。',24,'全唐诗/poet.song.208000.json','["六月火邊坐，有眼無耳朶。", "鐵蛇鑽不入，鐵牛衝不破。"]'),
('5e3e26d2-fd97-4e8e-8810-d482c83f6e82','偈頌一百五十首  其二九','釋心月','宋','宋诗','song-poetry','','[]','散夏餘五日，那事穩也未。',57,'全唐诗/poet.song.208000.json','["散夏餘五日，那事穩也未。", "爭似長汀子，低頭打覺睡。", "不管你金烏東昇，玉兔西墜。", "生死到來，甚處回避。", "低聲低聲，牆壁有耳。"]'),
('bf0eae02-b4f0-4e3e-969f-ec33534fc6b9','偈頌一百五十首  其三○','釋心月','宋','宋诗','song-poetry','','[]','古人底，今人底。',36,'全唐诗/poet.song.208000.json','["古人底，今人底。", "道著道不著，一場沒巴鼻。", "象王回旋，師子遊戲，洎合扶不起。"]'),
('c6be5b1c-38f5-4f4b-9232-46a518e06b4a','偈頌一百五十首  其三一','釋心月','宋','宋诗','song-poetry','','[]','去年今年，八月九月。',81,'全唐诗/poet.song.208000.json','["去年今年，八月九月。", "一樹兩樹，丹桂離披。", "三枝四枝，黄花漏泄。", "於斯見面不相逢，於斯相逢復相別。", "老豐干心未歇，騎箇無齒大蟲，只管見人饒舌。", "阿呵呵，南北東西，一團生鐵。"]'),
('553c40ef-2e6a-4afc-b723-66626e4d6c03','偈頌一百五十首  其三二','釋心月','宋','宋诗','song-poetry','','[]','甌峰布鐵連陣，我曾長袖拂開。',58,'全唐诗/poet.song.208000.json','["甌峰布鐵連陣，我曾長袖拂開。", "甌峰擲金剛圈，我曾鐵鞭擊碎。", "沒仇讎處起仇讎，無怨對中作怨對。", "今日何以報之，報之以此爲最。"]'),
('0c6b2112-5d14-465b-89ac-363e4e39e122','偈頌一百五十首  其三三','釋心月','宋','宋诗','song-poetry','','[]','以大圓覺，爲我伽藍。',41,'全唐诗/poet.song.208000.json','["以大圓覺，爲我伽藍。", "過去諸佛罪不重科，見在菩薩理無曲斷。", "未來學人，咄，切忌草裏輥。"]'),
('10604481-e1c9-43ed-bc4f-eaf7a9282a54','偈頌一百五十首  其三四','釋心月','宋','宋诗','song-poetry','','[]','去年七月十五，去去留之不住。',42,'全唐诗/poet.song.208000.json','["去年七月十五，去去留之不住。", "今年七月十五，住住推之不去。", "去也師子翻身，住也象王回顧。"]'),
('244bb20c-c1c8-4891-a70f-327695e5c6fb','偈頌一百五十首  其三五','釋心月','宋','宋诗','song-poetry','','[]','混不得，類不齊，六爻宛轉見重離。',32,'全唐诗/poet.song.208000.json','["混不得，類不齊，六爻宛轉見重離。", "夜深下視千山白，不是其中人不知。"]'),
('5cc7ede4-0acc-419c-a85a-cfb4761adab5','偈頌一百五十首  其三六','釋心月','宋','宋诗','song-poetry','','[]','我有一言，徹根徹源。',30,'全唐诗/poet.song.208000.json','["我有一言，徹根徹源。", "舉之不全，聽之不圓。", "擬問如何，蒼天蒼天。"]'),
('f13580aa-608f-4ecf-a53e-1ddd28d78947','偈頌一百五十首  其三七','釋心月','宋','宋诗','song-poetry','','[]','我有一語，通今貫古。',30,'全唐诗/poet.song.208000.json','["我有一語，通今貫古。", "全主全賓，全規全矩。", "直下承當，未敢相許。"]'),
('f5a7b481-e0b7-4294-9158-6e8885dd0e2c','偈頌一百五十首  其三八','釋心月','宋','宋诗','song-poetry','','[]','我有一機，對面提持。',20,'全唐诗/poet.song.208000.json','["我有一機，對面提持。", "石火莫及，電光罔追。"]'),
('34821fa4-e99c-4ab8-b75b-9d82e25a3a87','偈頌一百五十首  其三九','釋心月','宋','宋诗','song-poetry','','[]','我有一要，千差齊照。',30,'全唐诗/poet.song.208000.json','["我有一要，千差齊照。", "未曾拈花，不勞微笑。", "擬問如何，雲橫海嶠。"]'),
('b0e805b2-b6c8-4d39-9536-15d8c7ff1731','偈頌一百五十首  其四○','釋心月','宋','宋诗','song-poetry','','[]','我有一句，非默非語。',25,'全唐诗/poet.song.208000.json','["我有一句，非默非語。", "日用見成，一時分付，依前罔措。"]'),
('65705c8f-a6d2-4d54-ad2b-0dabc5e203e1','偈頌一百五十首  其四一','釋心月','宋','宋诗','song-poetry','','[]','跛跛挈挈，列列𦩘𦩘。',64,'全唐诗/poet.song.208000.json','["跛跛挈挈，列列𦩘𦩘。", "跛跛挈挈處，匙挑不上。", "列列𦩘𦩘時，炎天散雪。", "十有二年，來住此地，楊岐家風，未曾漏泄。", "今漏泄，秤鎚元是一團鐵。"]'),
('b474b729-0e82-42d8-9e2c-a147327c6b15','偈頌一百五十首  其四二','釋心月','宋','宋诗','song-poetry','','[]','烹金之爐，鑄人之模，浄名一默。',31,'全唐诗/poet.song.208000.json','["烹金之爐，鑄人之模，浄名一默。", "國師三呼，你諸人又向甚麽處摸索。"]'),
('66196873-f4a5-4fad-9b2e-fe386d4cdb24','偈頌一百五十首  其四三','釋心月','宋','宋诗','song-poetry','','[]','青山白雲，紅塵閙市，見成公案，理當即行。',32,'全唐诗/poet.song.208000.json','["青山白雲，紅塵閙市，見成公案，理當即行。", "爲什麽不知有，公驗分明。"]'),
('e8f8239c-9ff3-4fe3-bd92-064e99a20119','偈頌一百五十首  其四四','釋心月','宋','宋诗','song-poetry','','[]','山遥海闊古蘭若，月白風清老比丘。',32,'全唐诗/poet.song.208000.json','["山遥海闊古蘭若，月白風清老比丘。", "萬象森羅總賓客，相逢莫不小低頭。"]'),
('1e428db9-9a2d-460f-895e-90157ea1b3f9','偈頌一百五十首  其四五','釋心月','宋','宋诗','song-poetry','','[]','出得塵來又入塵，休論便重復便輕。',32,'全唐诗/poet.song.208000.json','["出得塵來又入塵，休論便重復便輕。", "試看門外清溪水，動靜由來一樣清。"]'),
('a9916c78-df7e-4140-921b-1c00762bc225','偈頌一百五十首  其四六','釋心月','宋','宋诗','song-poetry','','[]','一番風雨送寒來，底事開爐爐未開。',32,'全唐诗/poet.song.208000.json','["一番風雨送寒來，底事開爐爐未開。", "寄語參玄諸上士，冷湫湫處且相隈。"]'),
('623f73b1-7305-4619-8b56-66e1545d8bbd','偈頌一百五十首  其四七','釋心月','宋','宋诗','song-poetry','','[]','厨庫對僧堂，三門朝佛殿。',24,'全唐诗/poet.song.208000.json','["厨庫對僧堂，三門朝佛殿。", "南來與北來，一見一切見。"]'),
('ad4909b4-7179-4d27-b427-80e43fd71719','偈頌一百五十首  其四八','釋心月','宋','宋诗','song-poetry','','[]','晝見日，夜見星，妙高山色青又青。',47,'全唐诗/poet.song.208000.json','["晝見日，夜見星，妙高山色青又青。", "便與麽去，不惟打失鼻孔，亦乃失却眼睛。", "且過在於何，黄河從源濁。"]'),
('007471ea-6262-4413-9916-6322467f264d','偈頌一百五十首  其四九','釋心月','宋','宋诗','song-poetry','','["\u897f\u6e56"]','甌阜山頭，龍蛇陣上，將頭不猛，累及三軍。',60,'全唐诗/poet.song.208000.json','["甌阜山頭，龍蛇陣上，將頭不猛，累及三軍。", "自此江西湖南，便與麽去，吳山蜀水，紛紛紜紜。", "重城夜月，青山白雲，一度思君復恨君。"]'),
('ee05760f-372e-418e-a23f-58abfa5ba7fb','偈頌一百五十首  其五○','釋心月','宋','宋诗','song-poetry','','[]','赤心報國丈夫兒，進退存亡己自知。',64,'全唐诗/poet.song.208000.json','["赤心報國丈夫兒，進退存亡己自知。", "蓋世英雄寧畏死，一時忠勇更無誰。", "冶城夜月將軍墓，蔣岳春雲武帝祠。", "從此龍光山下寺，龜哥也著載豐碑。"]'),
('9655b228-0afe-45ef-8144-c8c89f3fcca3','偈頌一百五十首  其五一','釋心月','宋','宋诗','song-poetry','','[]','三月二十五，芳春餘幾許。',58,'全唐诗/poet.song.208000.json','["三月二十五，芳春餘幾許。", "一道平常心，顛言及倒語。", "謾道舉手摘楊花，那知漫空飛柳絮。", "趁流光，猛提取。", "喫粥了也，洗鉢盂去。"]'),
('0e81fdf7-e2e8-4532-bc04-0319937617e1','偈頌一百五十首  其五二','釋心月','宋','宋诗','song-poetry','','[]','不見一法在門外，平地無端自活埋。',32,'全唐诗/poet.song.208000.json','["不見一法在門外，平地無端自活埋。", "若是金毛師子子，急須移步入門來。"]'),
('83601c4f-0867-43e0-be59-075d29828d4c','偈頌一百五十首  其五三','釋心月','宋','宋诗','song-poetry','','[]','禪禪萬萬千，眉插鬢，耳垂肩。',63,'全唐诗/poet.song.208000.json','["禪禪萬萬千，眉插鬢，耳垂肩。", "千花影裏，百草頭顛。", "或時虛空裏釘橛，或時旱地上生蓮，引得寒山子笑掀天。", "吟得新詩一兩聯，足成三百篇。"]'),
('9ca0faf6-fa57-412c-a726-449e144966ff','偈頌一百五十首  其五四','釋心月','宋','宋诗','song-poetry','','[]','青山爲家，白雲作戶。',36,'全唐诗/poet.song.208000.json','["青山爲家，白雲作戶。", "穩密田園，鴉飛不度。", "皷腹臺前一轉頭，不覺四月二十五。"]'),
('781a2e4a-06ed-4a53-8b25-507c2e4d1b83','偈頌一百五十首  其五五','釋心月','宋','宋诗','song-poetry','','[]','長安甚閙，我國晏然。',52,'全唐诗/poet.song.208000.json','["長安甚閙，我國晏然。", "古人一期酬對，不妨奇特。", "未有出身之路，喚什麽作我國。", "縱遇鋒刀常坦坦，假饒毒藥也閑閑。"]'),
('73ca141e-338e-4161-815b-0881c044a067','偈頌一百五十首  其五六','釋心月','宋','宋诗','song-poetry','','[]','一句如鐵橛子，少室秤提不起，曹溪摇撼不動。',53,'全唐诗/poet.song.208000.json','["一句如鐵橛子，少室秤提不起，曹溪摇撼不動。", "有伎倆者一任左扶右持，無伎倆者不妨全體受用。", "巴蓬集壁，去天一尺。"]'),
('ed31656c-fa48-462b-981a-ad6ccaa45f37','偈頌一百五十首  其五七','釋心月','宋','宋诗','song-poetry','','[]','鱗皴拄杖子，非長亦非短。',63,'全唐诗/poet.song.208000.json','["鱗皴拄杖子，非長亦非短。", "東行西行處十分著力，歸家穩坐時一味不管。", "著力處是我同流，不管時吾之道伴。", "且道伴同流是一是二，見成公案。"]'),
('945b69b6-e892-45ef-a7c1-de4f918a78b6','偈頌一百五十首  其五八','釋心月','宋','宋诗','song-poetry','','[]','龍蟠虎踞，今古嶷然。',20,'全唐诗/poet.song.208000.json','["龍蟠虎踞，今古嶷然。", "楚水秦淮，滔滔無間。"]'),
('b8e94fde-5ea8-4220-98b9-6e8410ce0e92','偈頌一百五十首  其五九','釋心月','宋','宋诗','song-poetry','','[]','玉轉珠回著眼看，有相干處沒相干。',32,'全唐诗/poet.song.208000.json','["玉轉珠回著眼看，有相干處沒相干。", "只將此箇以爲主，一劍倚天星斗寒。"]'),
('90a6ba48-2b39-474e-b8ec-c6ea9d24cbb6','偈頌一百五十首  其六○','釋心月','宋','宋诗','song-poetry','','[]','進一步，退一步，钁頭钁底無回互。',48,'全唐诗/poet.song.208000.json','["進一步，退一步，钁頭钁底無回互。", "以一機，奪一機，沒便宜處討便宜。", "插鍬叉手田中事，是即擔泉带月歸。"]'),
('50312096-43dd-4f29-a45b-d12efd981fe9','偈頌一百五十首  其六一','釋心月','宋','宋诗','song-poetry','','[]','蜀山楚水，江北江南。',35,'全唐诗/poet.song.208000.json','["蜀山楚水，江北江南。", "步步穩密，念念相諳。", "前三三後三三，眨上眉毛早不堪。"]'),
('941d6697-8791-4505-802a-993d87922d94','偈頌一百五十首  其六二','釋心月','宋','宋诗','song-poetry','','[]','凜凜孤風藏不得，倒騎角虎出山來。',46,'全唐诗/poet.song.208000.json','["凜凜孤風藏不得，倒騎角虎出山來。", "大唐國裏人無數，糓酒糓糟喚不回。", "喚得回，笑容未動，牙爪先開。"]'),
('6b12a23d-65d8-42e6-bd3a-04a2cd6ed076','偈頌一百五十首  其六三','釋心月','宋','宋诗','song-poetry','','[]','笑密庵巧，喜松源拙，掃臨濟喝，折德山棒。',51,'全唐诗/poet.song.208000.json','["笑密庵巧，喜松源拙，掃臨濟喝，折德山棒。", "自謂不躡前脩，又道拋三放兩。", "自謂無法與人，又道開口不在舌頭上。"]'),
('4a891319-5b8e-499a-852e-6da949287804','偈頌一百五十首  其六四','釋心月','宋','宋诗','song-poetry','','[]','偃蹇蒼髯十萬本，參差翠玉數千竿。',32,'全唐诗/poet.song.208000.json','["偃蹇蒼髯十萬本，參差翠玉數千竿。", "風敲月戶三秋冷，雨打茅堂六月寒。"]'),
('c4f51488-be38-4686-a456-1dcfa4806a7e','偈頌一百五十首  其六五','釋心月','宋','宋诗','song-poetry','','[]','德山一棒，臨濟一喝。',38,'全唐诗/poet.song.208000.json','["德山一棒，臨濟一喝。", "家貧難辦素，事忙不及草。", "三千里外見誵訛，未免蝦跳不出斗。"]'),
('25f69fa8-1df0-471c-9887-c3d96094da31','偈頌一百五十首  其六六','釋心月','宋','宋诗','song-poetry','','[]','結夏解夏，靈山舊制。',36,'全唐诗/poet.song.208000.json','["結夏解夏，靈山舊制。", "鵝以瓶拘，魚以網繫。", "風雷變化在今時，霄漢振飛何更擬。"]'),
('c4b06ad7-a21b-44b4-b3c7-22af1df0a033','偈頌一百五十首  其六七','釋心月','宋','宋诗','song-poetry','','[]','羅籠得住，以此却不住。',38,'全唐诗/poet.song.208000.json','["羅籠得住，以此却不住。", "呼喚不回，以此却又回。", "且誵訛在什麽處，惱亂春風卒未休。"]'),
('d6c75eeb-c9f4-49ca-b366-865dfeefa9f8','偈頌一百五十首  其六八','釋心月','宋','宋诗','song-poetry','','[]','曉披北山雲，暮宿北山雨。',24,'全唐诗/poet.song.208000.json','["曉披北山雲，暮宿北山雨。", "來爲北山人，須辨北山主。"]'),
('3e8a8046-0534-40d3-9b6b-a5e2154e6f58','偈頌一百五十首  其六九','釋心月','宋','宋诗','song-poetry','','[]','是不是，非不非。',48,'全唐诗/poet.song.208000.json','["是不是，非不非。", "交肩過，携手歸。", "南泉不出方丈，爲什麽在莊喫油糍。", "今兮昔兮同一時，知音知後更誰知。"]'),
('852628ae-d8f8-40bf-a300-0d16addbc5cf','偈頌一百五十首  其七○','釋心月','宋','宋诗','song-poetry','','[]','簷頭滴滴，分明歷歷。',22,'全唐诗/poet.song.208000.json','["簷頭滴滴，分明歷歷。", "好片祖師心，無端已狼籍。"]'),
('9bf10063-89d9-464a-95d7-706723f773af','偈頌一百五十首  其七一','釋心月','宋','宋诗','song-poetry','','[]','道遠乎哉，觸事而真。',54,'全唐诗/poet.song.208000.json','["道遠乎哉，觸事而真。", "聖遠乎哉，體之即神。", "百丈遭喝，三日耳聾。", "水潦被踏，起來大笑。", "何似一指頭禪，一生受用不盡。"]'),
('a888ed26-a51e-4a6b-8c46-7710f5021bf6','偈頌一百五十首  其七二','釋心月','宋','宋诗','song-poetry','','[]','鍾阜龍盤，石城虎踞。',42,'全唐诗/poet.song.208000.json','["鍾阜龍盤，石城虎踞。", "牛首橫前，方山傍住。", "正傳閣上一觀，不覺雙眉陡聚，秦淮一带西流去。"]'),
('f98b1bf1-d14d-4d73-b589-e7ee59ea0142','偈頌一百五十首  其七三','釋心月','宋','宋诗','song-poetry','','[]','廬陵米價沒高低，直下承當已是遲。',32,'全唐诗/poet.song.208000.json','["廬陵米價沒高低，直下承當已是遲。", "多少牙人并販子，却來升合較毫釐。"]'),
('33e4af59-cc33-4fc5-874f-6e0b1335ea7f','偈頌一百五十首  其七四','釋心月','宋','宋诗','song-poetry','','[]','七佛已前只與麽，七佛之後亦復然。',28,'全唐诗/poet.song.208000.json','["七佛已前只與麽，七佛之後亦復然。", "片雲生晚谷，孤鶴下遼天。"]'),
('b38b863e-a2c1-4cf4-b374-0642c4216aa5','偈頌一百五十首  其七五','釋心月','宋','宋诗','song-poetry','','[]','沒誵訛處最誵訛，美玉無瑕貴切磋。',32,'全唐诗/poet.song.208000.json','["沒誵訛處最誵訛，美玉無瑕貴切磋。", "幾度渾崙提不起，鼠肝蟲臂總由他。"]'),
('7069da16-af74-4ff4-b559-1db7a727cca9','偈頌一百五十首  其七六','釋心月','宋','宋诗','song-poetry','','[]','十一十二，無處回避。',42,'全唐诗/poet.song.208000.json','["十一十二，無處回避。", "十四十五，充塞寰宇。", "者邊那邊，或去或住。", "一箭上紅心，黄金如糞土。"]'),
('f06ca99b-d34e-4def-a45c-a089c686701d','偈頌一百五十首  其七七','釋心月','宋','宋诗','song-poetry','','[]','風磨湛湛真空體，雨洗如如法界身。',32,'全唐诗/poet.song.208000.json','["風磨湛湛真空體，雨洗如如法界身。", "大地山河并萬象，今朝與佛共生辰。"]'),
('61ff23f3-2bad-4a89-a9cb-153dd4c38c89','偈頌一百五十首  其七八','釋心月','宋','宋诗','song-poetry','','[]','說時默，默時說。',26,'全唐诗/poet.song.208000.json','["說時默，默時說。", "處處投機，門門合轍，正是虛空裏釘橛。"]'),
('85f7b939-020e-4c22-b84e-16ecf60c3f73','偈頌一百五十首  其七九','釋心月','宋','宋诗','song-poetry','','[]','大厦非一木可支，巨舟須衆手可濟。',34,'全唐诗/poet.song.208000.json','["大厦非一木可支，巨舟須衆手可濟。", "衆手既集亦復同心，南北東西無往不利。"]'),
('2fc988a1-784a-433b-a7a6-baba04110c8a','偈頌一百五十首  其八○','釋心月','宋','宋诗','song-poetry','','[]','久晴不雨則旱，旱固可憂。',50,'全唐诗/poet.song.208000.json','["久晴不雨則旱，旱固可憂。", "久雨不晴則澇，澇亦可憂。", "不旱不澇，尤爲可憂。", "不曾下得春時種，空向田頭望有秋。"]'),
('f4f2af7c-ddac-4f4c-ba17-6340470b95f5','偈頌一百五十首  其八一','釋心月','宋','宋诗','song-poetry','','[]','犀牛扇子破多時，全暗全明。',54,'全唐诗/poet.song.208000.json','["犀牛扇子破多時，全暗全明。", "問著元來總不知，最爲親切。", "無限清風與頭角，成群作隊。", "盡同雲雨去難追，鼻繩在我手裏。"]'),
('70b9f0ec-a5eb-41a3-b45a-3f9e739f9725','偈頌一百五十首  其八二','釋心月','宋','宋诗','song-poetry','','[]','四月十五，雲龍風虎。',53,'全唐诗/poet.song.208000.json','["四月十五，雲龍風虎。", "掃蕩欃槍，肅清寰宇。", "五月十五，松巒竹塢。", "明月作龕，白雲閉戶。", "即今六月十五，毒蛇橫古路。"]'),
('01535cf9-ef31-40ac-b3ac-ebada54ce901','偈頌一百五十首  其八三','釋心月','宋','宋诗','song-poetry','','[]','山前田地誰爲主，喜見靈苗戰晚風。',32,'全唐诗/poet.song.208000.json','["山前田地誰爲主，喜見靈苗戰晚風。", "將謂年年求歲稔，由來歲歲願年豐。"]'),
('837cc813-742f-4151-a070-b17605e6cd17','偈頌一百五十首  其八四','釋心月','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','三種病二種光即不問，且如何是法身。',33,'全唐诗/poet.song.208000.json','["三種病二種光即不問，且如何是法身。", "不識廬山真面目，只緣身在此山中。"]'),
('9be0d71d-5312-4e08-9339-c78e65602d90','偈頌一百五十首  其八五','釋心月','宋','宋诗','song-poetry','','[]','密密綿綿細著工，從來此室不通風。',32,'全唐诗/poet.song.208000.json','["密密綿綿細著工，從來此室不通風。", "庭前三尺齊腰雪，身在靄然和氣中。"]'),
('ead32090-a4c0-4da9-a76a-8795cc8cb35a','偈頌一百五十首  其八六','釋心月','宋','宋诗','song-poetry','','[]','於食等者，於法亦等。',30,'全唐诗/poet.song.208000.json','["於食等者，於法亦等。", "於法等者，於食亦等。", "法食雙運，平等普熏。"]'),
('bab1c648-fb9d-466b-b554-8f06c53eb482','偈頌一百五十首  其八七','釋心月','宋','宋诗','song-poetry','','[]','風前敲落珊瑚枝，白玉鞭頭直下垂。',32,'全唐诗/poet.song.208000.json','["風前敲落珊瑚枝，白玉鞭頭直下垂。", "要識香林家住處，水晶宮殿草離離。"]'),
('1333ee92-5b6a-4fd2-b3ad-6a75b704a1a7','偈頌一百五十首  其八八','釋心月','宋','宋诗','song-poetry','','[]','我佛入深山，六載冷相守。',76,'全唐诗/poet.song.208000.json','["我佛入深山，六載冷相守。", "中夜一舉頭，南辰對北斗。", "於此眼皮穿，一場成漏逗。", "普觀大地人，此事皆具有。", "至今二千年，公案宛如舊。", "不見趙州曾有言，修行變作不唧銜。"]'),
('e1734de2-e2e9-4d13-8f0a-2b88212c7230','偈頌一百五十首  其八九','釋心月','宋','宋诗','song-poetry','','[]','直上覷，直下覷。',28,'全唐诗/poet.song.208000.json','["直上覷，直下覷。", "七佛已前，閑家潑具。", "少室鐵牛，黄梅石女。"]'),
('e12a3d99-b6ce-4b09-999f-38c2d3fd9454','偈頌一百五十首  其九○','釋心月','宋','宋诗','song-poetry','','[]','百丈下堂句，雲門顧鑒咦。',24,'全唐诗/poet.song.208000.json','["百丈下堂句，雲門顧鑒咦。", "進前叉手立，端的許誰知。"]'),
('e3e48264-ea13-4dfa-892b-17bee7e0d9d4','偈頌一百五十首  其九一','釋心月','宋','宋诗','song-poetry','','[]','法身向上法身邊，會得咸通無後先。',32,'全唐诗/poet.song.208000.json','["法身向上法身邊，會得咸通無後先。", "一箇矬來一箇跛，擔爲一擔更無偏。"]'),
('76e21451-cca2-4322-a7db-0526dcc2db76','偈頌一百五十首  其九二','釋心月','宋','宋诗','song-poetry','','[]','平懷常實事同風，正在昏昏夢寐中。',32,'全唐诗/poet.song.208000.json','["平懷常實事同風，正在昏昏夢寐中。", "扶起脊梁重猛省，莫教蹉過五更鍾。"]'),
('586457a6-b302-47af-bbca-c6f1b8594aa6','偈頌一百五十首  其九三','釋心月','宋','宋诗','song-poetry','','[]','一句子，有時坐斷乾坤籠罩今古，有時風高月冷海晏河清，有時變化晦明興雲致雨。',53,'全唐诗/poet.song.208000.json','["一句子，有時坐斷乾坤籠罩今古，有時風高月冷海晏河清，有時變化晦明興雲致雨。", "今日總拋向面前，切不得世諦流布。"]'),
('d3356bc6-c53e-4742-9965-b9943ad7e265','偈頌一百五十首  其九四','釋心月','宋','宋诗','song-poetry','','[]','憑欄拭目舊山川，疊疊峰巒带曉煙。',32,'全唐诗/poet.song.208000.json','["憑欄拭目舊山川，疊疊峰巒带曉煙。", "不是夢中論夢事，今朝正是普通年。"]'),
('5cba4160-0463-48c7-8a7e-82f7efe067b7','偈頌一百五十首  其九五','釋心月','宋','宋诗','song-poetry','','[]','白髮垂垂一葉身，今年貧似去年貧。',32,'全唐诗/poet.song.208000.json','["白髮垂垂一葉身，今年貧似去年貧。", "住山不與山爲主，水石煙雲也笑人。"]'),
('8f9b1ae3-61eb-437e-9fdb-791264991c0e','偈頌一百五十首  其九六','釋心月','宋','宋诗','song-poetry','','[]','與麽也在我，不與麽也在我。',35,'全唐诗/poet.song.208000.json','["與麽也在我，不與麽也在我。", "明眼漢擔拄杖遶天下橫行，爲什麽透這些子不得。"]'),
('54de586a-82ce-4434-8035-49ec0ffdf298','偈頌一百五十首  其九七','釋心月','宋','宋诗','song-poetry','','[]','二千年前，靈山付囑品。',22,'全唐诗/poet.song.208000.json','["二千年前，靈山付囑品。", "二千年後，吳地流通分。"]'),
('5d5125e4-c1d7-4d30-90ae-87ac2367f909','偈頌一百五十首  其九八','釋心月','宋','宋诗','song-poetry','','[]','把手同歸者，琅琅笑語新。',48,'全唐诗/poet.song.208000.json','["把手同歸者，琅琅笑語新。", "移身藏北斗，舉步入南辰。", "少室殘冬雪，武林三月春。", "轆轤千萬偈，頑石兩眉伸。"]'),
('6f5dc676-6be0-426f-94c2-3772d74b2748','偈頌一百五十首  其九九','釋心月','宋','宋诗','song-poetry','','[]','知之而行，見之而止，對面白雲千萬里。',52,'全唐诗/poet.song.208000.json','["知之而行，見之而止，對面白雲千萬里。", "言中定旨，語外明宗，一重一重復一重。", "斯門寂寂無關鎖，清坐不知誰與同。"]'),
('15b508e0-a395-47b9-b4cb-363ea3ba9106','偈頌一百五十首  其一○○','釋心月','宋','宋诗','song-poetry','','[]','未出胞胎事已蹉，出胞胎後轉誵訛。',32,'全唐诗/poet.song.208000.json','["未出胞胎事已蹉，出胞胎後轉誵訛。", "韶陽拄杖頭邊眼，供佛燒香不在多。"]'),
('104cf85b-8118-4dd3-b334-0c2eb3d9c00e','偈頌一百五十首  其一○一','釋心月','宋','宋诗','song-poetry','','[]','天高地迥，海闊山遥。',20,'全唐诗/poet.song.208000.json','["天高地迥，海闊山遥。", "秋風襲衣，拄杖𨁝跳。"]'),
('96901d1e-c904-47b6-94a1-f228edc23301','偈頌一百五十首  其一○二','釋心月','宋','宋诗','song-poetry','','[]','初三十一，上上大吉。',48,'全唐诗/poet.song.208000.json','["初三十一，上上大吉。", "中九下七，有口掛壁。", "雙林傅大士儒履道冠，蔣山梁寶公剪刀曲尺，笑倒生公臺畔石。"]'),
('2ac8ae83-93d4-4752-8301-f95a2b5daf50','偈頌一百五十首  其一○三','釋心月','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',28,'全唐诗/poet.song.208000.json','["有句無句，如藤倚樹。", "樹倒藤枯，毒蛇橫路。", "咄咄咄，縮頭去。"]'),
('68088965-36d7-4271-9a43-af663b93c5e9','偈頌一百五十首  其一○四','釋心月','宋','宋诗','song-poetry','','[]','諸佛機，祖師意。',54,'全唐诗/poet.song.208000.json','["諸佛機，祖師意。", "百草頭，雙眉底。", "不可得而一，不可得而二。", "趙州關即且置，雲門曲作麽生。", "一堂風冷淡，千古意分明。"]'),
('593a94a0-2f5a-4f73-8343-5cf9be3fa145','偈頌一百五十首  其一○五','釋心月','宋','宋诗','song-poetry','','[]','座已陞，衣已披，法作麽生說。',26,'全唐诗/poet.song.208000.json','["座已陞，衣已披，法作麽生說。", "但得雪消去，自然春到來。"]'),
('486d055f-230a-411e-b54d-7a608848a7bb','偈頌一百五十首  其一○六','釋心月','宋','宋诗','song-poetry','','[]','五九四十五，太陽開門戶。',114,'全唐诗/poet.song.208000.json','["五九四十五，太陽開門戶。", "一點微雲何處來，散作人間三日雨。", "曉來忽推窗，所見非常處。", "白玉作樓臺，爛銀爲國土。", "鹽官王老師，歡喜無著處。", "拈起須彌槌，擊動虛空皷。", "清音聞遠近，雅韻貫今古。", "法眼和一通，聽之猶莽鹵。", "古人有言兮，千年田，八百主。"]'),
('ffcf83ce-922b-4f5b-9cd3-c6f53473ac03','偈頌一百五十首  其一○七','釋心月','宋','宋诗','song-poetry','','[]','最初機，末後句。',28,'全唐诗/poet.song.208000.json','["最初機，末後句。", "有准繩，沒規矩。", "豈可錯承當，豈可錯分付。"]'),
('6e7316f3-da55-487f-923b-828e2c2940cf','偈頌一百五十首  其一○八','釋心月','宋','宋诗','song-poetry','','["\u8861\u5c71"]','初五初十，鐵蛇鑽不入。',43,'全唐诗/poet.song.208000.json','["初五初十，鐵蛇鑽不入。", "有也莫將去，無也莫將來。", "南嶽自南嶽，天台自天台，那更峨嵋對五臺。"]'),
('00e0f664-09cc-4330-9160-54f891cc7cf1','偈頌一百五十首  其一○九','釋心月','宋','宋诗','song-poetry','','[]','藥山休去，直得三十二相八十種好，一時現前。',32,'全唐诗/poet.song.208000.json','["藥山休去，直得三十二相八十種好，一時現前。", "然雖如是，也好與一杓。"]'),
('eeec87c8-2f05-445d-8833-4875861ce053','偈頌一百五十首  其一一○','釋心月','宋','宋诗','song-poetry','','[]','虎丘家風，內空外空。',42,'全唐诗/poet.song.208000.json','["虎丘家風，內空外空。", "十分富貴，十分貧窮。", "有時揚聲止響，有時詐啞佯聾，猶是平常小脫空。"]'),
('73f4dd76-aef6-4b16-9127-95ebbdaecbfb','偈頌一百五十首  其一一一','釋心月','宋','宋诗','song-poetry','','[]','青山門外白雲飛，楊柳溪邊引客歸。',32,'全唐诗/poet.song.208000.json','["青山門外白雲飛，楊柳溪邊引客歸。", "莫怪坐來頻勸酒，自從別後見君稀。"]'),
('9070dbf9-8fc3-460b-b73d-2307f3cea82b','偈頌一百五十首  其一一二','釋心月','宋','宋诗','song-poetry','','[]','敕書來自九重天，寶墨琳琅色尚鮮。',32,'全唐诗/poet.song.208000.json','["敕書來自九重天，寶墨琳琅色尚鮮。", "移取巖間枯樹子，和根植向鷲峰巔。"]'),
('375b618d-052a-4854-9d40-9675e0de8205','偈頌一百五十首  其一一三','釋心月','宋','宋诗','song-poetry','','[]','外息諸緣，心行無路。',32,'全唐诗/poet.song.208000.json','["外息諸緣，心行無路。", "入得無門之門，猶較昔日三步。", "靈蹤不在猿啼處。"]'),
('b82231fb-b73d-47b4-9cb1-8f66e9a592aa','偈頌一百五十首  其一一四','釋心月','宋','宋诗','song-poetry','','[]','髻中珠，只者是。',28,'全唐诗/poet.song.208000.json','["髻中珠，只者是。", "如優曇花，時一現爾。", "坐斷意根，方能側耳。"]'),
('087f2549-24b7-4e7a-82a2-8199da72e987','偈頌一百五十首  其一一五','釋心月','宋','宋诗','song-poetry','','[]','心同虛空界，示等虛空法。',24,'全唐诗/poet.song.208000.json','["心同虛空界，示等虛空法。", "證得虛空時，無是無非法。"]'),
('9e783df1-e389-4032-9ce8-bca47a551363','偈頌一百五十首  其一一六','釋心月','宋','宋诗','song-poetry','','[]','一人跨三脚馿，一人騎三角虎。',28,'全唐诗/poet.song.208000.json','["一人跨三脚馿，一人騎三角虎。", "三家村裏交肩，萬仞崖頭移步。"]'),
('1ad3cbc9-10eb-4cb5-b250-54cbb006b021','偈頌一百五十首  其一一七','釋心月','宋','宋诗','song-poetry','','[]','簇簇上來，却之不回。',32,'全唐诗/poet.song.208000.json','["簇簇上來，却之不回。", "簇簇下去，留之不住。", "於斯立片時，瞬目不揚眉。"]'),
('032fde71-8e26-4731-b7e2-28709ff606d6','偈頌一百五十首  其一一八','釋心月','宋','宋诗','song-poetry','','[]','巴陵三轉語，南源女人拜。',30,'全唐诗/poet.song.208000.json','["巴陵三轉語，南源女人拜。", "人貧智短，馬瘦毛長，靈鷲峰頭一炷香。"]'),
('ddfabf8d-15db-4c0e-a729-996e5275a52a','偈頌一百五十首  其一一九','釋心月','宋','宋诗','song-poetry','','[]','渠儂家住白雲鄉，南北東西路渺茫。',32,'全唐诗/poet.song.208000.json','["渠儂家住白雲鄉，南北東西路渺茫。", "幾度欲歸歸未得，忽聞巖桂送幽香。"]'),
('36b53e1a-7002-432b-9ed4-6fa1f46cb9b0','偈頌一百五十首  其一二○','釋心月','宋','宋诗','song-poetry','','[]','眼中物，物中眼。',22,'全唐诗/poet.song.208000.json','["眼中物，物中眼。", "雪峰輥三箇毯，睦州擔一片板。"]'),
('12c06053-4dcf-42bd-a73f-6d7bd69a886e','偈頌一百五十首  其一二一','釋心月','宋','宋诗','song-poetry','','[]','未見此老人已前，上是天下是地。',68,'全唐诗/poet.song.208000.json','["未見此老人已前，上是天下是地。", "既見此老人之後，山是山水是水。", "一別五十年，恩怨通身是。", "沒量大人，擡脚不起，累了兒兮累了孫，惱亂春風何日已。"]'),
('4f238050-dec8-42e6-92a6-838f957870a2','偈頌一百五十首  其一二二','釋心月','宋','宋诗','song-poetry','','[]','大仙心，休莽鹵。',58,'全唐诗/poet.song.208000.json','["大仙心，休莽鹵。", "三十三，錯分付。", "細推窮在何處，只知昨日雨今日晴，而不知今日晴昨日雨。", "靈雲陌上桃花飛，翻憶玄沙未徹語。"]'),
('95650cf2-e975-49f4-8e4e-6b0170b61def','偈頌一百五十首  其一二三','釋心月','宋','宋诗','song-poetry','','[]','常在途中久不歸，可憐庭戶草離離。',32,'全唐诗/poet.song.208000.json','["常在途中久不歸，可憐庭戶草離離。", "青山門外忽相見，問著剛然道不知。"]'),
('8d7736a0-2246-48dd-b340-e71060be27ce','偈頌一百五十首  其一二四','釋心月','宋','宋诗','song-poetry','','[]','此君面目甚分明，曲曲斜斜是幾莖。',32,'全唐诗/poet.song.208000.json','["此君面目甚分明，曲曲斜斜是幾莖。", "但得一回親見後，不隨風雨聽虛聲。"]'),
('08f7bf72-4c22-4161-abd3-afc0d204792c','偈頌一百五十首  其一二五','釋心月','宋','宋诗','song-poetry','','[]','作麽生，是什麽。',48,'全唐诗/poet.song.208000.json','["作麽生，是什麽。", "獅子當門，猛虎據坐。", "千人萬人，一箇半箇。", "石火電光中，掣斷黄金鎖，擬議依然還蹉過。"]'),
('5402f5f0-eef3-4413-822e-ad5add2bac3a','偈頌一百五十首  其一二六','釋心月','宋','宋诗','song-poetry','','[]','山蒼蒼，水茫茫。',56,'全唐诗/poet.song.208000.json','["山蒼蒼，水茫茫。", "直下是，非相當。", "整三玄戈甲，淬三要鋒鋩。", "舉意非他物，回眸即故鄉。", "好將馬祖舊遊地，題作渝州選佛場。"]'),
('7d54c07e-5217-4e52-be69-b768db1c778d','偈頌一百五十首  其一二七','釋心月','宋','宋诗','song-poetry','','[]','雲門一曲，臘月二十五。',37,'全唐诗/poet.song.208000.json','["雲門一曲，臘月二十五。", "驚起陝府鐵牛，撞倒石霜角虎。", "時節既相當，因緣難莽鹵。"]'),
('5154ebdc-9e75-4277-be1b-de68bf6036d2','偈頌一百五十首  其一二八','釋心月','宋','宋诗','song-poetry','','[]','人人有一坐具地，占斷猶來自祖翁。',32,'全唐诗/poet.song.208000.json','["人人有一坐具地，占斷猶來自祖翁。", "四界打量量不盡，及時耕種待秋風。"]'),
('cdfd7208-eb40-4559-8c22-f55380b3b9ee','偈頌一百五十首  其一二九','釋心月','宋','宋诗','song-poetry','','[]','峭峻門庭，平白道路。',40,'全唐诗/poet.song.208000.json','["峭峻門庭，平白道路。", "擔板睦州，面壁魯祖。", "不問南來北來，東去西去，須信長年不出戶。"]'),
('655004c8-4f1d-496f-ad76-5f75225fa04f','偈頌一百五十首  其一三○','釋心月','宋','宋诗','song-poetry','','[]','春山青，春水綠，獨立危亭看不足。',48,'全唐诗/poet.song.208000.json','["春山青，春水綠，獨立危亭看不足。", "李花白，桃花紅，一色同中又不同。", "知音惟有寒山子，拊掌歌笑臨春風。"]'),
('92a46681-d7d6-472b-8123-88865f25eaf2','偈頌一百五十首  其一三一','釋心月','宋','宋诗','song-poetry','','[]','閏二月十有五，靈山有語今分付。',65,'全唐诗/poet.song.208000.json','["閏二月十有五，靈山有語今分付。", "心洞十方，通今貫古。", "途路未歸人，朝朝復暮暮。", "不醉桃花村，定入杏花塢。", "何如相喚復相呼，飛來峰下喫茶去。"]'),
('f701f051-9d93-4f5b-b6aa-c79e96297c7d','偈頌一百五十首  其一三二','釋心月','宋','宋诗','song-poetry','','[]','修行作佛人無數，捏目無非是亂花。',32,'全唐诗/poet.song.208000.json','["修行作佛人無數，捏目無非是亂花。", "十劫坐來還懡㦬，不圖打草要驚蛇。"]'),
('923a0720-744e-416a-86d6-c6c6f8e1ee4e','偈頌一百五十首  其一三三','釋心月','宋','宋诗','song-poetry','','[]','一非一，二非二。',40,'全唐诗/poet.song.208000.json','["一非一，二非二。", "仰面不見天，低頭不見地。", "一即一，二即二。", "仰面見青天，低頭亦見地。"]'),
('395064a2-8d54-40c2-a36d-1fa200c9ef5f','偈頌一百五十首  其一三四','釋心月','宋','宋诗','song-poetry','','[]','與麽來者，過者邊立。',39,'全唐诗/poet.song.208000.json','["與麽來者，過者邊立。", "不與麽來者，過者邊立。", "與麽不與麽，花須連夜發，莫待曉風吹。"]'),
('12d0cdf1-1419-4958-a9b5-ba1045856356','偈頌一百五十首  其一三五','釋心月','宋','宋诗','song-poetry','','[]','我有一語，在在處處。',42,'全唐诗/poet.song.208000.json','["我有一語，在在處處。", "提起分開，放下捏聚。", "兩手持來，一手分付。", "江西曾有言，以此箇爲主。"]'),
('80042d9e-8979-4328-b072-aeabbc44d0a5','偈頌一百五十首  其一三六','釋心月','宋','宋诗','song-poetry','','[]','八月初一，好箇消息。',87,'全唐诗/poet.song.208000.json','["八月初一，好箇消息。", "積雨報初晴，新凉生八極。", "禾稻滿田疇，催人早收拾。", "一顆顆，一粒粒。", "宜愛惜，莫教遍地成狼籍。", "直待去年今年，官租私租，一時還畢。", "不妨一飽忘百饑，鼓腹謳歌度殘日。"]'),
('31ae42b9-dbaf-4408-9bee-13d1b786f97f','偈頌一百五十首  其一三七','釋心月','宋','宋诗','song-poetry','','[]','一月相拋不出門，幾經花縣幾烟村。',64,'全唐诗/poet.song.208000.json','["一月相拋不出門，幾經花縣幾烟村。", "桑麻影裏炊香早，松竹陰中笑語溫。", "幽磬朝離迎白日，疎鍾晚泊送黄昏。", "捲旗收陣歸來也，誰是知恩與報恩。"]'),
('72106394-2012-4440-99f8-c5f4d7b39e0e','偈頌一百五十首  其一三八','釋心月','宋','宋诗','song-poetry','','[]','十月十有五，敗葉堆雲，寒風推戶。',58,'全唐诗/poet.song.208000.json','["十月十有五，敗葉堆雲，寒風推戶。", "明窗下，東司頭。", "東行西行，總是提持處。", "參玄人，須記取。", "古人有言兮，百歲光陰切莫虛度。"]'),
('2f2f0970-be25-43e4-9551-0040372ac3c6','偈頌一百五十首  其一三九','釋心月','宋','宋诗','song-poetry','','[]','空手把鋤頭，步行騎水牛。',44,'全唐诗/poet.song.208000.json','["空手把鋤頭，步行騎水牛。", "人從橋上過，橋流水不流，動地清風來未休。", "咄，下座佛殿，別聽因由。"]'),
('edb94c88-60e8-47d6-81f4-f0fd49011032','偈頌一百五十首  其一四○','釋心月','宋','宋诗','song-poetry','','[]','月五日亦五，那堪時正午。',24,'全唐诗/poet.song.208000.json','["月五日亦五，那堪時正午。", "採藥藥最靈，問疾疾即愈。"]'),
('2e4225de-ead5-448d-8864-1f02d21ff05d','偈頌一百五十首  其一四一','釋心月','宋','宋诗','song-poetry','','[]','賢明宰輔聖明君，好語山中喜得聞。',32,'全唐诗/poet.song.208000.json','["賢明宰輔聖明君，好語山中喜得聞。", "願飲淳風餐至化，五香敬作一爐焚。"]'),
('f26e557b-e49e-4b3a-a408-fe1589ac5917','偈頌一百五十首  其一四二','釋心月','宋','宋诗','song-poetry','','[]','清浄慈門剎塵數，共生如來一妙相。',64,'全唐诗/poet.song.208000.json','["清浄慈門剎塵數，共生如來一妙相。", "以大願力出世間，示梵王身宣正法。", "三十六旬有六日，惟有此日最吉祥。", "稽首慇懃一瓣香，萬歲千秋爲壽考。"]'),
('2fea3ae4-ea6a-44ec-bb77-91cd4c066176','偈頌一百五十首  其一四三','釋心月','宋','宋诗','song-poetry','','[]','宸奎飛下九重天，鳳舞鸞翔墨色鮮。',32,'全唐诗/poet.song.208000.json','["宸奎飛下九重天，鳳舞鸞翔墨色鮮。", "水石山雲最佳處，慇懃一炷玉爐烟。"]'),
('1dd62d7f-84dc-48d8-926c-5c38d2208d2c','偈頌一百五十首  其一四四','釋心月','宋','宋诗','song-poetry','','[]','尊臨四海聖明君，步步毗盧頂上行。',32,'全唐诗/poet.song.208000.json','["尊臨四海聖明君，步步毗盧頂上行。", "自己法身只者是，巍然千古振佳聲。"]'),
('67064f88-74bb-4699-a3cc-c6c7fe467925','偈頌一百五十首  其一四五','釋心月','宋','宋诗','song-poetry','','[]','參禪須是鐵漢，著手心頭便判。',28,'全唐诗/poet.song.208000.json','["參禪須是鐵漢，著手心頭便判。", "直趣無上菩提，一切是非莫管。"]'),
('88fe34e9-8bf7-4403-8f6d-c780f6d4046f','偈頌一百五十首  其一四六','釋心月','宋','宋诗','song-poetry','','[]','涅槃心，差別智。',43,'全唐诗/poet.song.208000.json','["涅槃心，差別智。", "一非一，二非二。", "自古諸上賢，曾未達斯理。", "直饒恁麽會得，也是烏龜行陸地。"]'),
('f65a8a6a-6f22-49ae-9e13-d5532c9ab020','偈頌一百五十首  其一四七','釋心月','宋','宋诗','song-poetry','','[]','然燈之前，六六三十六。',52,'全唐诗/poet.song.208000.json','["然燈之前，六六三十六。", "然燈之後，九九八十一。", "數目甚分明，因甚數不出。", "數得出，弄到彌勒下生，依舊杳無消息。"]'),
('d5049236-084a-4677-9462-5883f90e4e96','偈頌一百五十首  其一四八','釋心月','宋','宋诗','song-poetry','','[]','溪山送別出門日，雲水相迎得路時。',32,'全唐诗/poet.song.208000.json','["溪山送別出門日，雲水相迎得路時。", "七佛軌儀持鉢去，滿船載得月明歸。"]'),
('a6d02ce4-7154-469a-b667-f57e4be889ab','偈頌一百五十首  其一四九','釋心月','宋','宋诗','song-poetry','','[]','五髻峰頭望海東，煙重重又水重重。',32,'全唐诗/poet.song.208000.json','["五髻峰頭望海東，煙重重又水重重。", "同人相見論心事，又得西來一信通。"]'),
('5307f6c1-f209-402e-951f-5de0599c725f','偈頌一百五十首  其一五○','釋心月','宋','宋诗','song-poetry','','[]','靈山一別二千年，聖世重逢豈偶然。',32,'全唐诗/poet.song.208000.json','["靈山一別二千年，聖世重逢豈偶然。", "細掬清泉揩老眼，豁開雲霧見青天。"]'),
('ed7709ee-4e13-4c2f-a7f9-a580e3c52311','偈頌一百五十首  其一五一','釋心月','宋','宋诗','song-poetry','','[]','雲漫漫，水漫漫。',53,'全唐诗/poet.song.208000.json','["雲漫漫，水漫漫。", "往來一致，高下同觀。", "炊無米飯，飽不來入甚易。", "喫粥了也，洗鉢盂去還難。", "難難，冬不寒，臘後看。"]'),
('5e4316f2-357d-4ddd-9fe3-f7b99a7165e8','頌古十六首  其一','釋心月','宋','宋诗','song-poetry','','[]','室內孤燈只自知，入流須辨截流機。',32,'全唐诗/poet.song.208000.json','["室內孤燈只自知，入流須辨截流機。", "遼天一鏃三關外，玉兔金烏不敢飛。"]'),
('50c33935-0040-4c46-a200-aa648d22121d','頌古十六首  其二','釋心月','宋','宋诗','song-poetry','','[]','一竿絲線兩金魚，不犯清波意自殊。',32,'全唐诗/poet.song.208000.json','["一竿絲線兩金魚，不犯清波意自殊。", "斜拽簑衣遮蓋後，空餘明月滿江湖。"]'),
('fe61e21c-2f17-4c22-b518-c9dd5063109b','頌古十六首  其三','釋心月','宋','宋诗','song-poetry','','[]','恁麽說話，大似肥處添，瘦處減。',28,'全唐诗/poet.song.208000.json','["恁麽說話，大似肥處添，瘦處減。", "殊不知東山老人，慣得其便。"]'),
('32b96020-dff0-4cce-a16d-e14bb246a760','頌古十六首  其四','釋心月','宋','宋诗','song-poetry','','[]','昭昭心目色塵裏，晃晃色塵心目間。',32,'全唐诗/poet.song.208000.json','["昭昭心目色塵裏，晃晃色塵心目間。", "直下裂開猶是鈍，那堪隨步萬重山。"]'),
('79d7af90-48a7-4c1f-9d31-75b76928fe1d','頌古十六首  其五','釋心月','宋','宋诗','song-poetry','','[]','善法堂前探淺深，寒濤平地湧千尋。',32,'全唐诗/poet.song.208000.json','["善法堂前探淺深，寒濤平地湧千尋。", "探竿靠壁出門去，也是貧兒拾得金。"]'),
('47d870d2-bb7a-4781-ae8f-5ad829d27432','頌古十六首  其六','釋心月','宋','宋诗','song-poetry','','[]','不是風兮不是幡，堂堂擺手出重關。',32,'全唐诗/poet.song.208000.json','["不是風兮不是幡，堂堂擺手出重關。", "可憐守待雞鳴者，猶在昏昏醉夢間。"]'),
('472deedd-3b7b-4eb2-a9d2-ec948524edfc','頌古十六首  其七','釋心月','宋','宋诗','song-poetry','','[]','賓中主，主中賓。',26,'全唐诗/poet.song.208000.json','["賓中主，主中賓。", "在窟獅子，互換嚬呻，相識如今能幾人。"]'),
('0d401c47-4723-40eb-a91e-9450e6d89b1d','頌古十六首  其八','釋心月','宋','宋诗','song-poetry','','[]','頭上漫漫，脚下漫漫。',36,'全唐诗/poet.song.208000.json','["頭上漫漫，脚下漫漫。", "拄定即易，瞥轉還難。", "金剛寶劍逼人寒，不墮機鋒句外看。"]'),
('166d63b9-22d8-49b3-90c4-c37969850d77','頌古十六首  其九','釋心月','宋','宋诗','song-poetry','','[]','嗟嘆聲中偃仰時，三千世界草離離。',32,'全唐诗/poet.song.208000.json','["嗟嘆聲中偃仰時，三千世界草離離。", "若教老漢明斯旨，鼻孔從來向下垂。"]'),
('1dca71be-613b-4422-bb7b-efa348d5fa96','頌古十六首  其一○','釋心月','宋','宋诗','song-poetry','','[]','朝西天，暮東土。',42,'全唐诗/poet.song.208000.json','["朝西天，暮東土。", "翫水遊山，徐行款步。", "是則不動道場，不是亦在裏許。", "誰爲證明，石霜角虎。"]'),
('0b4fc97c-3182-46c2-b6bd-87c996d86147','頌古十六首  其一一','釋心月','宋','宋诗','song-poetry','','[]','天寒人寒，影草探竿。',28,'全唐诗/poet.song.208000.json','["天寒人寒，影草探竿。", "總在裏許，振鬣擺尾，水面依然平似砥。"]'),
('20bdda96-40f6-4ab4-8d2c-319a87b4bf40','頌古十六首  其一二','釋心月','宋','宋诗','song-poetry','','[]','楊岐談笑之中，換了白雲心肝五臟。',49,'全唐诗/poet.song.208000.json','["楊岐談笑之中，換了白雲心肝五臟。", "而白雲憤悶之際，抉了楊岐鼻孔眼睛。", "若在今時亦未可，禍不入謹家之門。"]'),
('c0362df1-6adf-4cec-aed8-e01e7f3e2ac9','頌古十六首  其一三','釋心月','宋','宋诗','song-poetry','','[]','問處赤心片片，答處不負來機。',56,'全唐诗/poet.song.208000.json','["問處赤心片片，答處不負來機。", "今有問靈隠，如何是實際理地。", "天長地久，海晏河清，恁麽則事同一家。", "自天祐之，吉無不利。"]'),
('ddfc1de4-801d-4fd0-88fd-d2066ef86a19','頌古十六首  其一四','釋心月','宋','宋诗','song-poetry','','[]','京師出大黄，渾崙不覆藏。',24,'全唐诗/poet.song.208000.json','["京師出大黄，渾崙不覆藏。", "朝生金鳳子，平地快翺翔。"]'),
('a5b3ac0b-f1c8-4c16-ac1c-62ff9028852e','頌古十六首  其一五','釋心月','宋','宋诗','song-poetry','','[]','北山高處望鄉關，一度登臨一解顔。',32,'全唐诗/poet.song.208000.json','["北山高處望鄉關，一度登臨一解顔。", "目力窮邊無限意，應難寫向畫圖間。"]'),
('f955066b-4f2e-47c0-a74a-06be197fd2e2','頌古十六首  其一六','釋心月','宋','宋诗','song-poetry','','[]','父母非親親是誰，雙眸烱烱带雙眉。',32,'全唐诗/poet.song.208000.json','["父母非親親是誰，雙眸烱烱带雙眉。", "含元殿上不相識，正是岷峨相見時。"]'),
('bcd073b3-670e-4832-b900-cc21d86bdf3b','示圓闍梨偈','釋心月','宋','宋诗','song-poetry','','[]','我有明珠一顆，久被塵勞關鎖。',28,'全唐诗/poet.song.208000.json','["我有明珠一顆，久被塵勞關鎖。", "而今塵盡光生，照破青山萬朶。"]'),
('6a26629c-5669-42f4-954f-d8fca2288a98','餞泉都莊偈','釋心月','宋','宋诗','song-poetry','','[]','佛法徧在一切處，一切處求不可求。',32,'全唐诗/poet.song.208000.json','["佛法徧在一切處，一切處求不可求。", "皷腹臺前成現句，牧童也解倒騎牛。"]'),
('94d791da-828e-4a92-99e3-0848aa5c319b','示慧日侍者德禪人偈','釋心月','宋','宋诗','song-poetry','','[]','北磵磵邊纔緩步，石溪溪畔又移身。',32,'全唐诗/poet.song.208000.json','["北磵磵邊纔緩步，石溪溪畔又移身。", "俊哉龍鳳親生子，何必南陽令斬新。"]'),
('a20d9324-b92e-4820-b00a-204448051b15','寄蔣山癡絕和尚  其一','釋心月','宋','宋诗','song-poetry','','[]','急水上旗翻五色，飛流中毬輥百花。',32,'全唐诗/poet.song.208000.json','["急水上旗翻五色，飛流中毬輥百花。", "相逢相笑勿相笑，人途在中未到家。"]'),
('42931612-81ea-4d7b-97ff-86d5d446e0ec','寄蔣山癡絕和尚  其二','釋心月','宋','宋诗','song-poetry','','[]','沒絃琴三弄五弄，無孔笛一聲兩聲。',32,'全唐诗/poet.song.208000.json','["沒絃琴三弄五弄，無孔笛一聲兩聲。", "明月浮空天似水，長安歸夢恰三更。"]'),
('2504fc61-29ed-4cd4-89c0-9c4821107bcd','和掃破庵塔  其一','釋心月','宋','宋诗','song-poetry','','[]','白{亻幺刀}叢中第一尊，硬將明越作台溫。',36,'全唐诗/poet.song.208000.json','["白{亻幺刀}叢中第一尊，硬將明越作台溫。", "將頭撞破虛空後，又把金針鎖細痕。"]'),
('b0619a7c-5dc2-4a19-9961-65a1dfd51216','和掃破庵塔  其二','釋心月','宋','宋诗','song-poetry','','[]','平林風靜塢雲輕，一掬寒泉薦客情。',32,'全唐诗/poet.song.208000.json','["平林風靜塢雲輕，一掬寒泉薦客情。", "會與此山重有約，何妨一日一經行。"]'),
('00a4b591-086d-43c1-8b99-c6768cafac30','送楊尚書','釋心月','宋','宋诗','song-poetry','','[]','萬里江山圖畫開，錦帆歸去記重來。',32,'全唐诗/poet.song.208000.json','["萬里江山圖畫開，錦帆歸去記重來。", "好於彷彿烟雲裏，添箇翩翩馹使催。"]'),
('b3e8c4c5-0815-4390-8806-d880ac4ee03e','送李國史','釋心月','宋','宋诗','song-poetry','','[]','父翁伯季忠清節，凜凜同班立聖朝。',32,'全唐诗/poet.song.208000.json','["父翁伯季忠清節，凜凜同班立聖朝。", "次第到孫孫又子，老僧屈指日非遥。"]'),
