('9277dfba-edf1-4a91-8cdb-b37e00c74b60','送丁高士','釋心月','宋','宋诗','song-poetry','','[]','霞服雲冠游上苑，芒鞋竹杖過幽扉。',32,'全唐诗/poet.song.208000.json','["霞服雲冠游上苑，芒鞋竹杖過幽扉。", "故山青草纍纍塚，羞見先生化鶴歸。"]'),
('d5587f37-925a-4d68-9375-5224f2b9a47a','刺血寫法華','釋心月','宋','宋诗','song-poetry','','[]','矮窗岑寂中，一字一點血。',24,'全唐诗/poet.song.208000.json','["矮窗岑寂中，一字一點血。", "血盡筆禿時，止止不須說。"]'),
('10a59c83-90d8-4359-aeed-6782ed928e66','開諸方語','釋心月','宋','宋诗','song-poetry','','[]','收拾殘花貼故枝，游蜂舞蝶謾紛飛。',32,'全唐诗/poet.song.208000.json','["收拾殘花貼故枝，游蜂舞蝶謾紛飛。", "莫教嗅著無香處，懡㦬還從舊路歸。"]'),
('d1e07c1f-4dec-49d0-a2d8-5c26f5319362','浄髮','釋心月','宋','宋诗','song-poetry','','[]','頂門些子娘生髮，剗了還生卒未休。',32,'全唐诗/poet.song.208000.json','["頂門些子娘生髮，剗了還生卒未休。", "斜把金刀勾得著，一毫頭是一毫頭。"]'),
('8d3a49ec-c858-46ee-8d8f-00e841cde410','行者德山改名德止','釋心月','宋','宋诗','song-poetry','','[]','吾宗一德山，天下同仰企。',84,'全唐诗/poet.song.208000.json','["吾宗一德山，天下同仰企。", "寥寥數百年，清風來未已。", "汝名今與同，初非犯其諱。", "人前一呼喚，不覺聳衆耳。", "易以艮爲山，辭以艮爲止。", "宜將止易山，只移一畫子。", "吾當尊前賢，不得不如此。"]'),
('6d803dab-4b14-471d-b072-294559156c80','示天童幹延壽化士','釋心月','宋','宋诗','song-poetry','','[]','家有良醫病轉多，無棲泊處最誵訛。',32,'全唐诗/poet.song.208000.json','["家有良醫病轉多，無棲泊處最誵訛。", "水如藍也花如錦，依舊簷聲滴舊窠。"]'),
('6cb18b33-eb53-4230-8545-5aca8c95df59','再刊大慧語','釋心月','宋','宋诗','song-poetry','','[]','妙喜胸中流出底，重華天子手親書。',32,'全唐诗/poet.song.208000.json','["妙喜胸中流出底，重華天子手親書。", "大千俱壞此不壞，別板刊行亦聽渠。"]'),
('e2c13558-23f2-4203-a495-7ff4a8817e4a','明鑑先生','釋心月','宋','宋诗','song-poetry','','[]','支干念二金釘子，變態無窮無盡時。',32,'全唐诗/poet.song.208000.json','["支干念二金釘子，變態無窮無盡時。", "盡大地人都釘定，先生知後更誰知。"]'),
('aea32243-88b3-49ba-93b3-bea0dab80b09','水茶磨','釋心月','宋','宋诗','song-poetry','','[]','機輪瞥轉已多時，苦澁分明只自知。',32,'全唐诗/poet.song.208000.json','["機輪瞥轉已多時，苦澁分明只自知。", "轆轆放身隨浪輥，傍觀贏得眼如眉。"]'),
('7bae68fe-da00-4810-8aea-9b17d352fce2','甜瓜','釋心月','宋','宋诗','song-poetry','','[]','不惜渾崙次第僉，把將來語太無厭。',32,'全唐诗/poet.song.208000.json','["不惜渾崙次第僉，把將來語太無厭。", "而今一片落誰手，管取甜時徹蒂甜。"]'),
('167d0bb5-3247-4f6d-b9ac-8ecd219c15fa','見性堂','釋心月','宋','宋诗','song-poetry','','[]','髑髏瀝盡眼頭寬，炯炯圓明一顆寒。',32,'全唐诗/poet.song.208000.json','["髑髏瀝盡眼頭寬，炯炯圓明一顆寒。", "莫怪年來昏怛甚，鐘聲却被鼓聲瞞。"]'),
('43200dff-a328-40f6-a1bf-f9736dd8ad7c','立雪方丈','釋心月','宋','宋诗','song-poetry','','[]','少室門庭冷似冰，可師曾此一沉吟。',32,'全唐诗/poet.song.208000.json','["少室門庭冷似冰，可師曾此一沉吟。", "夜闌各自知寒冷，莫待齊腰三尺深。"]'),
('eb9dfd8f-f4de-4f7d-9963-d87e11753857','菩提橋','釋心月','宋','宋诗','song-poetry','','[]','石頭一路平如掌，步步風波險處行。',32,'全唐诗/poet.song.208000.json','["石頭一路平如掌，步步風波險處行。", "渡馬渡馿都莫問，等閑奪得祖師名。"]'),
('98758961-46d5-4c63-8eb5-cce1b0ee432b','一葦亭','釋心月','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江一葦浪花開，合國咸知不再來。',32,'全唐诗/poet.song.208000.json','["長江一葦浪花開，合國咸知不再來。", "千古憑欄一惆悵，豈知脚下滑如苔。"]'),
('06518c28-064d-4145-bfbd-f26fa50bb027','寶華法堂','釋心月','宋','宋诗','song-poetry','','[]','老蚌虛含素月胎，庭前花雨自成堆。',32,'全唐诗/poet.song.208000.json','["老蚌虛含素月胎，庭前花雨自成堆。", "吾將倒轉風雷舌，未必繽紛動地來。"]'),
('49e7b67c-ebe4-44de-a465-af764cbe8b1b','見山亭','釋心月','宋','宋诗','song-poetry','','[]','柳陌花衢爛熳游，不知日月去如流。',32,'全唐诗/poet.song.208000.json','["柳陌花衢爛熳游，不知日月去如流。", "擡眸忽見家山在，雙手難遮滿面羞。"]'),
('877e1155-a3b0-4b8f-91a8-14cb20b26e49','出山相贊  其一','釋心月','宋','宋诗','song-poetry','','[]','道無修證，入山何爲。',36,'全唐诗/poet.song.208000.json','["道無修證，入山何爲。", "法無去來，出山何之。", "黄金屋宅草離離，天上人間說向誰。"]'),
('4ea36c7d-7ce5-41b2-a606-6b3fabc98588','出山相贊  其二','釋心月','宋','宋诗','song-poetry','','[]','六載入山緣底事，復緣底事出山來。',32,'全唐诗/poet.song.208000.json','["六載入山緣底事，復緣底事出山來。", "毒心毒行人難見，但見春風笑臉開。"]'),
('4cde644a-91fc-4184-a1ae-3d62180b4b74','水月觀音贊','釋心月','宋','宋诗','song-poetry','','[]','覺天無雲，性海無風。',32,'全唐诗/poet.song.208000.json','["覺天無雲，性海無風。", "玉輪蘸影，金浪翻空。", "非惟觀世音，我亦遊其中。"]'),
('a676b9dc-e065-433c-ab3c-c57de4514755','思惟相觀音贊  其一','釋心月','宋','宋诗','song-poetry','','[]','春禽晝啼，秋蟲夜吟。',40,'全唐诗/poet.song.208000.json','["春禽晝啼，秋蟲夜吟。", "有耳皆聞，何獨觀音。", "如是而知，如是而覺。", "面目現前，超諸餘學。"]'),
('6c7fa076-04fe-4c29-a456-72b5b0d80156','思惟相觀音贊  其二','釋心月','宋','宋诗','song-poetry','','[]','燕語鶑吟，鴉鳴鵲噪。',40,'全唐诗/poet.song.208000.json','["燕語鶑吟，鴉鳴鵲噪。", "聲有差殊，聞無顛倒。", "聞性既寂，聲塵亦空。", "一點悲心，在處圓通。"]'),
('95c530af-a412-43de-903f-b2bbd1cd0684','開眼入定贊','釋心月','宋','宋诗','song-poetry','','[]','六用如如體不分，耳能觀色眼能聲。',32,'全唐诗/poet.song.208000.json','["六用如如體不分，耳能觀色眼能聲。", "而今老大宜安分，眼自觀兮耳自聽。"]'),
('14a69a2e-f9b6-428e-b534-2c541b265b5c','趙通判請贊觀音','釋心月','宋','宋诗','song-poetry','','[]','輪數珠，泛蓮舟。',138,'全唐诗/poet.song.208000.json','["輪數珠，泛蓮舟。", "覺天雲靜，性海風休。", "以悲爲心，救衆生苦。", "以慈爲眼，觀衆生憂。", "衆生何憂，憂忘內修。", "衆生何苦，苦於外求。", "故現宰官身，所說宰官法。", "不出乎盡忠孝，守名節，保祿位，教子孫，勿墜於箕裘。", "夫如是普門一十九類，楞嚴三十二應，熙怡微笑，唯唯點頭。", "公堂日永篆煙浮，誓與慈容同去留。"]'),
('2e17a14b-0906-4cd7-b3a2-0602cac33b6c','魚婦贊','釋心月','宋','宋诗','song-poetry','','[]','左提魚籃，右搴衣袂。',36,'全唐诗/poet.song.208000.json','["左提魚籃，右搴衣袂。", "浩浩塵中，一聲活底。", "傾國傾城眼豁開，早已白雲千萬里。"]'),
('d47452d0-2f38-425f-95da-90f84762eb66','馬郎婦贊','釋心月','宋','宋诗','song-poetry','','[]','鏡裏精神，風前調度。',36,'全唐诗/poet.song.208000.json','["鏡裏精神，風前調度。", "手執蓮經，換人腸肚。", "錦鱗吞釣上鈎來，黄金骨已騰空去。"]'),
('ca6e5619-ec76-400f-8519-2e6ea638f064','草衣文殊贊','釋心月','宋','宋诗','song-poetry','','[]','草離離，髮垂垂。',66,'全唐诗/poet.song.208000.json','["草離離，髮垂垂。", "神出鬼沒，佛眼難窺。", "能坐毗耶之舌，而不能出女子之定。", "能行法王之令，而不能免迦葉之疑。", "五臺山勢峭巍巍，返擲還他獅子兒。"]'),
('5fd18eff-9903-4250-8310-679761ad69ca','文殊贊','釋心月','宋','宋诗','song-poetry','','[]','獅子吼，無畏說。',48,'全唐诗/poet.song.208000.json','["獅子吼，無畏說。", "空處挨，緊處捻。", "彼上人，縮却舌。", "不二門，都敗闕。", "五髻童真七佛師，却證烏龜成白鱉。"]'),
('74dce9d9-9348-4388-bb24-61a359b58265','維摩贊','釋心月','宋','宋诗','song-poetry','','[]','呵二乘，彈十地。',48,'全唐诗/poet.song.208000.json','["呵二乘，彈十地。", "以强詞，奪正理。", "問疾人，根到底。", "語與默，都不是。", "金粟如來居士身，盡大地人扶不起。"]'),
('1610d54d-a258-4a04-9ad6-f8dd4024c4fe','布袋贊  其一','釋心月','宋','宋诗','song-poetry','','[]','儱侗十圍腹，婆娑三尺軀。',64,'全唐诗/poet.song.208000.json','["儱侗十圍腹，婆娑三尺軀。", "折拄杖攪無邊香水海，破布囊貯百億須彌盧。", "等箇人㗭哩㗭哩，覓文錢蘇嚕蘇嚕。", "天上無，地下無，四明山色開畫圖。"]'),
('e1185cbf-c69b-4b65-a64a-1d64d931852f','布袋贊  其二','釋心月','宋','宋诗','song-poetry','','[]','放布袋而立，携布袋而去。',78,'全唐诗/poet.song.208000.json','["放布袋而立，携布袋而去。", "他日下生來，別道一轉語。", "補處之尊，弄真像假。", "拋却內宮，來使奉化。", "回觀時髑髏眼睛瀝未盡，緊靠處布袋骨董放不下。", "放得下，未必遭人强描畫。"]'),
('f7b1af98-047e-4b98-9cf8-86e585a8cfcc','須菩提贊  其一','釋心月','宋','宋诗','song-poetry','','[]','倚杖而立，示真般若。',34,'全唐诗/poet.song.208000.json','["倚杖而立，示真般若。", "手中冊子，云何抄寫。", "長老若不放下，疑殺後生尊者。"]'),
('ce6e74f8-f543-46ab-bc85-df7d459021d9','須菩提贊  其二','釋心月','宋','宋诗','song-poetry','','[]','常宴坐，常危立。',26,'全唐诗/poet.song.208000.json','["常宴坐，常危立。", "一片虛凝，萬境空寂。", "巖前花雨已狼籍。"]'),
('feaf76e4-1398-46db-8950-9f5c6fce62db','豐干寒拾贊  其一','釋心月','宋','宋诗','song-poetry','','[]','只解踞虎頭，不解收虎尾。',48,'全唐诗/poet.song.208000.json','["只解踞虎頭，不解收虎尾。", "你若訐露人，人也訐露你。", "出沒虎聲中，卷舒牛跡上。", "半是小兒嬉，半是大人相。"]'),
('7a8d9e22-6be8-4b92-baa9-b9b351d997b3','豐干寒拾贊  其二','釋心月','宋','宋诗','song-poetry','','[]','執爨灰滿頭，掃地塵撲面。',24,'全唐诗/poet.song.208000.json','["執爨灰滿頭，掃地塵撲面。", "巖下細思量，一場不著便。"]'),
('c3051470-26e3-4668-9d31-6fd2ea648f7c','豐干寒拾贊  其三','釋心月','宋','宋诗','song-poetry','','[]','道兮無貧，德兮有鄰。',56,'全唐诗/poet.song.208000.json','["道兮無貧，德兮有鄰。", "五峰雙磵，誰主誰賓。", "相靠而睡也，象王回顧。", "相呼而笑也，獅子嚬呻。", "噫，不省這箇意，修行徒苦辛。"]'),
('f38e9ad3-0136-4d6a-a461-357e250b403a','豐干寒拾贊  其四','釋心月','宋','宋诗','song-poetry','','[]','雙磵底，五峰前。',36,'全唐诗/poet.song.208000.json','["雙磵底，五峰前。", "塊石上，磨松煙。", "多無一兩字，少有三百篇，明明此意落誰邊。"]'),
('3927efe7-c130-47a4-b0a1-88d1b740a50f','豐干寒拾贊  其五','釋心月','宋','宋诗','song-poetry','','[]','微風吹，巖松鳴。',36,'全唐诗/poet.song.208000.json','["微風吹，巖松鳴。", "聽愈好，吟愈清。", "渾崙一句子，文彩甚分明，筆下如何寫得成。"]'),
('faaab7a3-009c-44ab-91e2-b94f845bf068','豐干寒拾贊  其六','釋心月','宋','宋诗','song-poetry','','[]','左手執卷，右手指示。',30,'全唐诗/poet.song.208000.json','["左手執卷，右手指示。", "覿露不覆藏，幾人知此意。", "回首臺山鎖寒翠。"]'),
('72f27967-4ccc-42ab-8cbb-c261bb78514c','豐干寒拾贊  其七','釋心月','宋','宋诗','song-poetry','','[]','對面撫掌，兩鏡相照。',30,'全唐诗/poet.song.208000.json','["對面撫掌，兩鏡相照。", "雙磵與五峰，冷地齊失笑。", "喚作普賢還料掉。"]'),
('bb681801-c166-41b8-acea-73f6c3c893b3','達磨贊  其一','釋心月','宋','宋诗','song-poetry','','[]','面壁而坐，見成行貨。',28,'全唐诗/poet.song.208000.json','["面壁而坐，見成行貨。", "立雪求之，還同蹉過。", "須知罪犯彌天大。"]'),
('2f3c80c7-efc9-4a97-a368-3a17b4645134','達磨贊  其二','釋心月','宋','宋诗','song-poetry','','[]','來泛一杯千頃浪，去携隻履萬重雲。',32,'全唐诗/poet.song.208000.json','["來泛一杯千頃浪，去携隻履萬重雲。", "自言傳法傳何法，故我思君亦恨君。"]'),
('448f8ce5-bca8-4868-b388-ee06fbd3a716','達磨贊  其三','釋心月','宋','宋诗','song-poetry','','[]','萬浪千波一葦橫，翩翩隻影可憐生。',32,'全唐诗/poet.song.208000.json','["萬浪千波一葦橫，翩翩隻影可憐生。", "老蕭若會截流句，楊子江頭放你行。"]'),
('5792bcf3-e965-4d4f-96b7-c941d7cdcc64','六代祖師贊  其一','釋心月','宋','宋诗','song-poetry','','[]','竺乾正眼，震旦心宗。',28,'全唐诗/poet.song.208000.json','["竺乾正眼，震旦心宗。", "一點水墨，兩處成龍。", "至今匝地生清風。"]'),
('185a8728-2fbf-486d-b2f9-6c64faf3e506','六代祖師贊  其二','釋心月','宋','宋诗','song-poetry','','[]','諸緣息時，伎倆盡矣。',28,'全唐诗/poet.song.208000.json','["諸緣息時，伎倆盡矣。", "了了常知，不是不是。", "莫被胡僧謾著你。"]'),
('c971e273-55f7-4391-9767-c66680694af9','六代祖師贊  其三','釋心月','宋','宋诗','song-poetry','','[]','無言說中，廣說信心。',28,'全唐诗/poet.song.208000.json','["無言說中，廣說信心。", "洞然明白，非去來今。", "風病因茲轉更深。"]'),
('d3a34e49-fdbb-41dc-a161-b4d67a8f3938','六代祖師贊  其四','釋心月','宋','宋诗','song-poetry','','[]','古佛無心，知之者誰。',28,'全唐诗/poet.song.208000.json','["古佛無心，知之者誰。", "雙峰點首，石女攢眉。", "錯付黄梅箇小兒。"]'),
('4b9f2fa6-a44f-4a6a-ab66-5df5cd21aaa7','六代祖師贊  其五','釋心月','宋','宋诗','song-poetry','','[]','能與麽去，能與麽回。',28,'全唐诗/poet.song.208000.json','["能與麽去，能與麽回。", "青松鬰密，白髮摧頹。", "嶺南消息幾時來。"]'),
('9a88a746-fd6d-4f0d-ad6a-2c56d12b4245','六代祖師贊  其六','釋心月','宋','宋诗','song-poetry','','[]','字則不識，宗說俱通。',28,'全唐诗/poet.song.208000.json','["字則不識，宗說俱通。", "如風吹水，如日行空。", "破蕩箕裘是此翁。"]'),
('05b5c3a5-b08f-433e-8abe-e34bac473424','寶公和尚贊','釋心月','宋','宋诗','song-poetry','','[]','鷹窠大士，示現無方。',48,'全唐诗/poet.song.208000.json','["鷹窠大士，示現無方。", "生于宋代，老于齊梁。", "杖頭刀尺，隠顯全彰。", "巍巍堂堂，煒煒煌煌。", "至今坐斷獨龍岡。"]'),
('14e300b0-564a-4005-bec7-451d8637c0b0','北宗贊','釋心月','宋','宋诗','song-poetry','','[]','菩提有樹鏡無塵，玉兔懷胎入紫宸。',32,'全唐诗/poet.song.208000.json','["菩提有樹鏡無塵，玉兔懷胎入紫宸。", "七百僧龍第一座，信衣推與負舂人。"]'),
('10a9b5d4-9520-40d3-9fc7-53895feb5d93','明上座贊','釋心月','宋','宋诗','song-poetry','','[]','大庾嶺頭提不起，本來面目尚埃塵。',32,'全唐诗/poet.song.208000.json','["大庾嶺頭提不起，本來面目尚埃塵。", "南枝不放春消息，也是茫茫漏網人。"]'),
('dec76b5c-47da-44c0-860f-bafa78090c52','荷澤贊','釋心月','宋','宋诗','song-poetry','','[]','荷澤元來不姓高，嶺頭一網竟難逃。',32,'全唐诗/poet.song.208000.json','["荷澤元來不姓高，嶺頭一網竟難逃。", "爾曹若不論知解，知解無因到爾曹。"]'),
('1ff255ca-2de6-41de-a259-6008ae8a9785','雪峰真覺禪師贊','釋心月','宋','宋诗','song-poetry','','[]','出嶺超方，九上三到。',140,'全唐诗/poet.song.208000.json','["出嶺超方，九上三到。", "一槌便成，未是性燥。", "誦過水偈，聞色空義。", "攪炒肝腸，睡不成睡。", "棒頭領旨，句下明宗。", "夜半鰲山，如鶴拋籠。", "象骨岩高，中有鱉鼻。", "千五百人，中傷者幾。", "三毬並輥，大用全提。", "石火莫及，電光罔追。", "大地撮來，如粟米粒。", "今昔行人，看之不出。", "望州烏石，日炙風吹。", "萬福曾郎，眼戴雙眉。"]'),
('8a08f409-95d1-4320-9a82-aff07320e3dd','普化贊  其一','釋心月','宋','宋诗','song-poetry','','[]','者風僧，甚舉止。',156,'全唐诗/poet.song.208000.json','["者風僧，甚舉止。", "木鐸一摇，聲在人耳。", "邈吾真處點著便行，咬生菜時觸著便諱。", "明頭暗頭拶著便轉，今日昨日扶著便醉。", "或於道吾手裏倒送鎗頭，或於臨濟面前滿傾惡水。", "如斯伎倆，果能成褫人，建立黄蘗宗旨者耶。", "況其掣狂掣顛，有頭無尾，是皆不逃大仰之讖盤山之記。", "末後若不向東門南門西門北門覓箇走路，定不免新婦子老婆禪小廝兒撫掌笑你。"]'),
('ea477217-6ede-4208-a1f8-7bbb0cb809e2','普化贊  其二','釋心月','宋','宋诗','song-poetry','','[]','邈得先師真，鼻孔不相似。',24,'全唐诗/poet.song.208000.json','["邈得先師真，鼻孔不相似。", "大悲院裏歸，馿鳴較些子。"]'),
('1034104b-d553-445e-a851-5276a5a9eb7c','蜆子贊  其一','釋心月','宋','宋诗','song-poetry','','[]','師荒村古廟兮，人紺宇蓮宮。',176,'全唐诗/poet.song.208000.json','["師荒村古廟兮，人紺宇蓮宮。", "師紙錢堆裏兮，人瓔珞聚中。", "師撈{丷/八}摝蜆兮，人打鳳羅龍。", "師鱣鮮枯槁兮，人玉食雍容。", "師與人隠顯各異兮，卷舒一同。", "爲華嚴之弟兮，不入華嚴保社。", "爲洞山之子兮，不紹洞山門風。", "欲遯其迹迹愈著，欲晦其名名愈崇。", "夫能謹初護末，不沿他酒臺盤兮，人莫知師之所知。", "師獨樂其樂，樂亦無窮。", "果如是兮，安有今日。", "持短尺以量虛空，磨淡墨以邈虛空者哉。"]'),
('24aca834-112a-498e-a3ed-51f40a2d5873','蜆子贊  其二','釋心月','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','古廟爐灰冷，長江烟水寒。',24,'全唐诗/poet.song.208000.json','["古廟爐灰冷，長江烟水寒。", "再三撈摝得，難上酒臺盤。"]'),
('56cd5d0c-d60b-4605-a828-89a57e868e8c','政黄牛贊  其一','釋心月','宋','宋诗','song-poetry','','[]','湖水湖山面面奇，烟雲風月總新詩。',32,'全唐诗/poet.song.208000.json','["湖水湖山面面奇，烟雲風月總新詩。", "悠然句意不及處，也解將牛作馬騎。"]'),
('d98d6221-9761-4546-a721-6399a6c4de66','政黄牛贊  其二','釋心月','宋','宋诗','song-poetry','','[]','肩聳湖山瘦，眼明湖水秋。',24,'全唐诗/poet.song.208000.json','["肩聳湖山瘦，眼明湖水秋。", "往來誰是伴，白鷺與黄牛。"]'),
('78c45285-e6ef-480f-aa1e-a83a90d38523','郁山主贊  其一','釋心月','宋','宋诗','song-poetry','','[]','谿橋馿子失脚處，百尺竿頭進步時。',32,'全唐诗/poet.song.208000.json','["谿橋馿子失脚處，百尺竿頭進步時。", "頂踵一時俱換了，依前只是郁闍梨。"]'),
('e4c71605-75f5-4d89-a65b-dfaa770a2cdf','郁山主贊  其二','釋心月','宋','宋诗','song-poetry','','[]','騎馿過溪橋，一踏橋梁折。',24,'全唐诗/poet.song.208000.json','["騎馿過溪橋，一踏橋梁折。", "橋邊萬朶山，拊掌笑不歇。"]'),
('28b3abf6-e102-450e-824c-bd4192cfb981','言法華贊','釋心月','宋','宋诗','song-poetry','','[]','褰裳登九重，走筆書十三。',24,'全唐诗/poet.song.208000.json','["褰裳登九重，走筆書十三。", "兩頭俱不住，臨去又圖南。"]'),
('ca13a255-dd11-4b9e-86bc-72acbd71cf8a','十六羅漢贊','釋心月','宋','宋诗','song-poetry','','[]','飛錫五天雲冉冉，泛杯南海浪悠悠。',32,'全唐诗/poet.song.208000.json','["飛錫五天雲冉冉，泛杯南海浪悠悠。", "一毫頭上輕收拾，不是冤家不聚頭。"]'),
('0e393fdf-9605-4d62-8b59-baf343267f71','過河尊者贊','釋心月','宋','宋诗','song-poetry','','[]','前溪淥漲雨初晴，浮笠波心掌樣平。',32,'全唐诗/poet.song.208000.json','["前溪淥漲雨初晴，浮笠波心掌樣平。", "伎倆由來只如此，放教急急奔前程。"]'),
('cc0be33f-cdde-490c-b4d1-25348f911734','朝陽穿破衲贊','釋心月','宋','宋诗','song-poetry','','[]','簷前負日暖烘烘，敗壞重加補綴工。',32,'全唐诗/poet.song.208000.json','["簷前負日暖烘烘，敗壞重加補綴工。", "盡大地人窮性命，都盧劄在一針鋒。"]'),
('f3fc9de1-9ecb-4197-abad-6cbba11b7d97','待月了殘經贊','釋心月','宋','宋诗','song-poetry','','[]','數黑豆子老和尚，石上松根得意時。',32,'全唐诗/poet.song.208000.json','["數黑豆子老和尚，石上松根得意時。", "自憐末後一句子，只許天邊明月知。"]'),
('a1eefde4-faa9-4ebb-b028-70d6ba61e640','船子和尚贊','釋心月','宋','宋诗','song-poetry','','[]','機語相符句合頭，離鈎三寸已吞鈎。',32,'全唐诗/poet.song.208000.json','["機語相符句合頭，離鈎三寸已吞鈎。", "孤舟短棹都拋却，直得朱涇水逆流。"]'),
('7319399d-d459-40ea-9add-560042bc58cc','亮座主贊','釋心月','宋','宋诗','song-poetry','','[]','心與虛空講未終，一呼回首一開容。',32,'全唐诗/poet.song.208000.json','["心與虛空講未終，一呼回首一開容。", "勿言去後無消息，雲外西山翠掃空。"]'),
('f6b2e46e-49bd-4f9f-a133-e4827d6668ff','宗道者贊','釋心月','宋','宋诗','song-poetry','','[]','一雙破草鞋，無跟又無耳。',40,'全唐诗/poet.song.208000.json','["一雙破草鞋，無跟又無耳。", "袈裟包不得，拄杖挑不起。", "只知赤脚下桐城，不免桐城人笑你。"]'),
('38492395-5a5f-4b03-bcce-9901131ac238','靈照女贊','釋心月','宋','宋诗','song-poetry','','[]','盡道家貧賣笊籬，潑天富貴許誰知。',32,'全唐诗/poet.song.208000.json','["盡道家貧賣笊籬，潑天富貴許誰知。", "風前歛手一轉語，未必丹霞識得伊。"]'),
('e8804a01-107c-4b0e-b02f-f3d85daf7c90','黄蘗掌沙彌圖贊','釋心月','宋','宋诗','song-poetry','','[]','大機之用誰擔荷，斷際孤風不可追。',32,'全唐诗/poet.song.208000.json','["大機之用誰擔荷，斷際孤風不可追。", "濟北少年曾未委，風光太子已先知。"]'),
('4a335023-7bb7-45d5-95ac-f6d7514e557d','趙州不下禪床接二王圖贊','釋心月','宋','宋诗','song-poetry','','[]','折脚禪床接斷薪，猶堪傴坐揖高賓。',32,'全唐诗/poet.song.208000.json','["折脚禪床接斷薪，猶堪傴坐揖高賓。", "明知裂土熏天富，難鬭他家徹骨貧。"]'),
('349d5a23-3023-4111-a6ca-d2f0e45cdbe9','國一見代宗起立圖贊','釋心月','宋','宋诗','song-poetry','','[]','法地安然不動移，振身而立亦相宜。',32,'全唐诗/poet.song.208000.json','["法地安然不動移，振身而立亦相宜。", "勿於起坐經行外，別討大唐天子師。"]'),
('19e6123d-25b2-40a4-ac81-a15da0fab2e1','文宗嗜蛤蜊圖贊','釋心月','宋','宋诗','song-poetry','','[]','一點悲心擘不開，鑊湯衮處笑盈腮。',32,'全唐诗/poet.song.208000.json','["一點悲心擘不開，鑊湯衮處笑盈腮。", "希奇之事朕深信，是與君王說法來。"]'),
('bfe2aa5b-a957-4a1e-b19a-4f4b3e367259','莊宗中原之寶圖贊','釋心月','宋','宋诗','song-poetry','','[]','搜索乾坤宇宙間，中原之寶祕形山。',32,'全唐诗/poet.song.208000.json','["搜索乾坤宇宙間，中原之寶祕形山。", "若非呈似老興化，往往人將作等閑。"]'),
('08a34692-6651-4f70-aa1c-5635f1d74f2e','李翱見藥山圖贊','釋心月','宋','宋诗','song-poetry','','[]','千株松下謁癯仙，冷淡烟霞別是天。',32,'全唐诗/poet.song.208000.json','["千株松下謁癯仙，冷淡烟霞別是天。", "授與刀圭元不識，却來携手水雲邊。"]'),
('82eb3ba3-5715-43c6-94db-672d6ad12e25','裴休捧佛請安名圖贊','釋心月','宋','宋诗','song-poetry','','[]','持來面目已全彰，出就呈機驗當行。',32,'全唐诗/poet.song.208000.json','["持來面目已全彰，出就呈機驗當行。", "千釋迦文萬彌勒，都盧攝入一身光。"]'),
('b9b1b3dc-9b8a-44e9-b089-09b89cbd6038','韓愈請益大顛圖贊','釋心月','宋','宋诗','song-poetry','','[]','去國迢迢路八千，歸心日夕九重天。',32,'全唐诗/poet.song.208000.json','["去國迢迢路八千，歸心日夕九重天。", "當機不領到家句，且向途中快著鞭。"]'),
('c8466e86-c784-4ac0-a2df-61c44abd4459','龐居士見馬大師圖贊','釋心月','宋','宋诗','song-poetry','','[]','攪海獰龍頭角露，出林老虎爪牙張。',32,'全唐诗/poet.song.208000.json','["攪海獰龍頭角露，出林老虎爪牙張。", "至今六合風雲裏，浩浩來登選佛場。"]'),
('264aa74b-0fcd-4c82-bd9d-a1cc38f57dca','靈照對丹霞圖贊','釋心月','宋','宋诗','song-poetry','','[]','覿露風猷第二機，電光石火較遲遲。',32,'全唐诗/poet.song.208000.json','["覿露風猷第二機，電光石火較遲遲。", "丹霞去後無消息，又見牢關把定時。"]'),
('65b586e4-ad0a-491f-bcc7-79300ce0bb63','說無生話圖贊','釋心月','宋','宋诗','song-poetry','','[]','收拾山雲海月情，團欒鼻直眼眉橫。',32,'全唐诗/poet.song.208000.json','["收拾山雲海月情，團欒鼻直眼眉橫。", "龜毛拂子兔角杖，敲得虛空嚗嚗聲。"]'),
('8bb9b44c-e26a-488b-af04-a606140357c3','靈照看日早晚圖贊','釋心月','宋','宋诗','song-poetry','','[]','明暗雙雙機奪機，阿爺手裏覓便宜。',32,'全唐诗/poet.song.208000.json','["明暗雙雙機奪機，阿爺手裏覓便宜。", "果然老底能輕信，輸却日輪當午時。"]'),
('b9a86044-e4b3-4d78-ba14-af2b306e4aa1','龐大倚鉏而化圖贊','釋心月','宋','宋诗','song-poetry','','[]','老子先行行不到，郎君末後太過生。',32,'全唐诗/poet.song.208000.json','["老子先行行不到，郎君末後太過生。", "倚天衡岳最深處，雨過寒光潑眼明。"]'),
('d7d2b654-a4ca-4477-aeeb-f90045017fa4','贊東山五祖和尚','釋心月','宋','宋诗','song-poetry','','[]','輥綉毬，打瓦鼓。',43,'全唐诗/poet.song.208000.json','["輥綉毬，打瓦鼓。", "半巴音，半魯語。", "心膽傾，面目露。", "不可描，不可塑。", "故天下稱之曰東山演祖。"]'),
('d7b8a14d-54e6-4603-a2da-16f7e200e4a0','贊寂巖忠和尚','釋心月','宋','宋诗','song-poetry','','[]','師之出處，師之面顔。',60,'全唐诗/poet.song.208000.json','["師之出處，師之面顔。", "雲橫楚甸，雨過淮山。", "閲其語錄，見其作用。", "玉轉珠回，雲興泉湧。", "寂巖之道，莫能形容。", "我今贊之，持尺量空。"]'),
('9f92222a-dcb3-4963-bb63-9bbdfb69de24','贊北磵和尚','釋心月','宋','宋诗','song-poetry','','[]','調古風高，神清氣逸。',82,'全唐诗/poet.song.208000.json','["調古風高，神清氣逸。", "聞一唯陞素王之堂，見微笑入空王之室。", "恢恢綽綽兮以一而貫萬，寂寂寥寥兮會萬而歸一。", "此豈非八十三，住龍床角邊。", "南山之浄慈，佛照之真子，北磵老賊者耶。"]'),
('033ce921-fa0a-466f-a696-9a03a7d91fb1','贊癡絕和尚','釋心月','宋','宋诗','song-poetry','','[]','破蟄之雷，指南之龜。',27,'全唐诗/poet.song.208000.json','["破蟄之雷，指南之龜。", "斫圓玉斧，刮膜金篦。", "噫，非師而誰。"]'),
('d6ec6dd0-f1bc-4717-9881-e19e0647e5a2','廣福聰長老畫無準頂相請贊','釋心月','宋','宋诗','song-poetry','','[]','這慈尊，曾自贊。',60,'全唐诗/poet.song.208000.json','["這慈尊，曾自贊。", "煮不熟，燒不爛。", "有軟頑，沒思算。", "秤須彌重四兩，量虛空闊丈半。", "更有白{亻幺刀}不是處，付與無聞，從公理斷。"]'),
('73c277da-f698-4df9-b540-756f34351149','東林徹長老請贊','釋心月','宋','宋诗','song-poetry','','[]','寒浦先零之姿，古巖後凋之操。',82,'全唐诗/poet.song.208000.json','["寒浦先零之姿，古巖後凋之操。", "雪滿顛一味寒酸，雲半肩十分枯槁。", "任緣去住也，隨處有餘。", "信手拈來也，用時恰好。", "雖云理絕思惟，其柰事關懷抱。", "倚天長劍用還磨，分付明巖徹長老。"]'),
('e56e9820-816d-4e60-bbe7-79dcc9306f6a','虎丘惠長老請贊','釋心月','宋','宋诗','song-poetry','','[]','萬里晴空，一聲霹靂。',28,'全唐诗/poet.song.208000.json','["萬里晴空，一聲霹靂。", "盡大地人，掩耳不及。", "浩浩清風生八極。"]'),
('69fa37c3-d68d-4035-9f02-e9c2c7672274','祥符喜長老請贊','釋心月','宋','宋诗','song-poetry','','[]','三巖日暖經行地，雙徑風清宴坐時。',32,'全唐诗/poet.song.208000.json','["三巖日暖經行地，雙徑風清宴坐時。", "昔不少年今不老，如何描邈使人知。"]'),
('9af50fb9-00ab-4df5-a5f6-d20d19bf3f0f','圓通師孫福長老請贊','釋心月','宋','宋诗','song-poetry','','[]','虛空寥寥，吾之體也。',88,'全唐诗/poet.song.208000.json','["虛空寥寥，吾之體也。", "萬象紜紜，吾之用也。", "青山白雲，吾之賓朋也。", "山色溪聲，吾之言論也。", "作是說者，畫師之所不能幻也。", "夫畫師所不能幻者，吾亦不知吾之爲誰也。", "故强名之，曰石谿老凍畐也。"]'),
('e258150a-6771-476d-8738-26c365a634a7','資壽溱長老請贊','釋心月','宋','宋诗','song-poetry','','[]','寒浦先零之姿，古巖後凋之操。',72,'全唐诗/poet.song.208000.json','["寒浦先零之姿，古巖後凋之操。", "雪滿顛一味寒酸，雲擁肩十分枯槁。", "任緣而住也，觸處有餘。", "隨機而應也，無適不可。", "家法森嚴，鉗鎚糙暴。", "承當者誰，如溱長老。"]'),
('b00e9e42-5d1f-4d98-966d-4b0a70e531f0','西竺浄長老請贊','釋心月','宋','宋诗','song-poetry','','[]','色見聲求，二俱不是。',40,'全唐诗/poet.song.208000.json','["色見聲求，二俱不是。", "離聲色外，轉沒巴鼻。", "石火光中，掣電影裏。", "要見石谿，且莫瞌睡。"]'),
('a28c89c9-e1bf-4dee-92e2-6ba6474e53d9','楊居士請贊','釋心月','宋','宋诗','song-poetry','','[]','水中之月，鏡裏之形。',68,'全唐诗/poet.song.208000.json','["水中之月，鏡裏之形。", "一頂春雪，半肩秋雲。", "觀而無觀曰正觀，聞而無聞曰真聞。", "畫工作汝汝即我，居士識吾吾非君。", "是兮非兮分不分，贊之毀之徒云云。"]'),
('03a65ecb-6b0b-49b5-9539-5200c5b833f4','小師正恭寫松源掩室并師山行圖請贊  其一','釋心月','宋','宋诗','song-poetry','','[]','父前行，子後隨。',40,'全唐诗/poet.song.208000.json','["父前行，子後隨。", "不肖孫，愚且癡。", "三昧門，各自知。", "入深村，草離離。", "風前翻憶老楊岐。"]'),
('d20bad19-bf77-48bc-9c62-e710c3097db8','小師正恭寫松源掩室并師山行圖請贊  其二','釋心月','宋','宋诗','song-poetry','','[]','清空片雲，古潭萬象。',40,'全唐诗/poet.song.208000.json','["清空片雲，古潭萬象。", "飄然何來，湛然何往。", "識則不識，知而無知。", "鐵壁銀山，挨開者誰。"]'),
('35330d92-7f85-4860-b44d-af5d9702cbdf','開光明藏疏','釋心月','宋','宋诗','song-poetry','','[]','佛祖親傳真命脉，橘洲筆底發淵源。',32,'全唐诗/poet.song.208000.json','["佛祖親傳真命脉，橘洲筆底發淵源。", "郁乎光焰十萬丈，只貴知音一印傳。"]'),
('ada2f568-5b1a-4e35-b97f-aea1b0f8ce75','山偈奉餞九江純禪者歸東林受業','釋心月','宋','宋诗','song-poetry','','[]','年來佛法带誵訛，十卜干千不較多。',32,'全唐诗/poet.song.208000.json','["年來佛法带誵訛，十卜干千不較多。", "寄語東林略擡手，看伊眼腦是如何。"]'),
('e414b4f2-f491-47da-868e-54fb11190545','和張防禦','釋心月','宋','宋诗','song-poetry','','[]','我有一方田，於中息萬緣。',48,'全唐诗/poet.song.208000.json','["我有一方田，於中息萬緣。", "生涯雖寂爾，日用不徒然。", "知足長年樂，無求在處禪。", "西隣知此意，松竹銷寒煙。"]'),
('ab3eab0f-7a59-4b75-ada2-4432519b0813','送超禪人歸省親','釋心月','宋','宋诗','song-poetry','','[]','參玄曾未造玄微，肯學新豐十不歸。',32,'全唐诗/poet.song.208000.json','["參玄曾未造玄微，肯學新豐十不歸。", "歸舉清凉答佛話，教娘知有祖師機。"]'),
('1d87fdf1-985b-44e5-8ca1-ec1ad16a8575','歸雲','釋心月','宋','宋诗','song-poetry','','[]','拖雲從龍去又回，無心却似有心來。',32,'全唐诗/poet.song.208000.json','["拖雲從龍去又回，無心却似有心來。", "只因怕失老僧約，永日岩房撥不開。"]'),
('2ae20c58-4429-4247-b9a8-ec2d97a62c58','臭庵','釋心月','宋','宋诗','song-poetry','','[]','自家汗氣不曾覺，口未曾開人已知。',32,'全唐诗/poet.song.208000.json','["自家汗氣不曾覺，口未曾開人已知。", "熏出蘇州二石佛，一人掩鼻一攢眉。"]'),
('4ae955a6-9c4f-4ac5-8c89-b4ffa4e81000','中山','釋心月','宋','宋诗','song-poetry','','[]','英標拔俗一千丈，壁立孤危不可攀。',32,'全唐诗/poet.song.208000.json','["英標拔俗一千丈，壁立孤危不可攀。", "南北東西徒斫額，誰知步步在其間。"]'),
('1e9887ca-da7d-441e-a2ba-545e21988896','省行堂主往霅川化油','釋心月','宋','宋诗','song-poetry','','[]','火冷灰寒老病身，一燈深夜伴孤貧。',32,'全唐诗/poet.song.208000.json','["火冷灰寒老病身，一燈深夜伴孤貧。", "忍將滴滴思鄉淚，說與溪頭問疾人。"]'),
('18a7bcdd-1d31-466b-87bb-92f9a943a63a','異手相士','釋心月','宋','宋诗','song-poetry','','[]','天地同根歸一指，先生三四已爲多。',32,'全唐诗/poet.song.208000.json','["天地同根歸一指，先生三四已爲多。", "等閑豎起拳頭處，數量如何數得他。"]'),
('bb415242-057b-441d-b558-9e5e9751f75c','送保慧大師  其一','釋心月','宋','宋诗','song-poetry','','[]','生在如來家，須學如來行。',24,'全唐诗/poet.song.208000.json','["生在如來家，須學如來行。", "諸念入正念，有諍歸無諍。"]'),
('4d5a7f8d-487c-44e7-85d1-718bae434483','送保慧大師  其二','釋心月','宋','宋诗','song-poetry','','[]','少林佛國不再見，臺山大會堪憑□。',32,'全唐诗/poet.song.208000.json','["少林佛國不再見，臺山大會堪憑□。", "彼何人哉我何人，眨起眉毛宜猛省。"]'),
('df2c4ceb-0306-493b-b4a3-559f3f737bb4','送林藏主省親','釋心月','宋','宋诗','song-poetry','','[]','有十不歸今且歸，不願再見今再見。',32,'全唐诗/poet.song.208000.json','["有十不歸今且歸，不願再見今再見。", "古今大道常坦然，各自當門通一線。"]'),
('02a687c9-fdab-4a7a-84fb-2f4b9ca213ee','送珙上人之廬山','釋心月','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不到廬山不是僧，斯言斯語亦何曾。',32,'全唐诗/poet.song.208000.json','["不到廬山不是僧，斯言斯語亦何曾。", "珙今興盡還歸去，五老依前倚碧層。"]'),
('13d58e51-c6da-4bc9-a2a8-c463fc172f1d','送艮侍者隨本師歸瀘南','釋心月','宋','宋诗','song-poetry','','[]','依師參扣到無參，只麽呼三應亦三。',32,'全唐诗/poet.song.208000.json','["依師參扣到無參，只麽呼三應亦三。", "話到不相辜負處，瀘南元是舊瀘南。"]'),
('381bdf58-4810-4a18-8804-6964e0456f4d','孟府送猿有頌次韻謝之','釋心月','宋','宋诗','song-poetry','','[]','居從岩洞友熊羆，養在侯門送石溪。',32,'全唐诗/poet.song.208000.json','["居從岩洞友熊羆，養在侯門送石溪。", "要識將軍成物意，往來莫作聽猿啼。"]'),
('5a740dfb-cbc3-4a93-8c7e-b2a4fe25706c','延壽化帳','釋心月','宋','宋诗','song-poetry','','[]','捲起何如放下時，微風輕撼碧雲垂。',32,'全唐诗/poet.song.208000.json','["捲起何如放下時，微風輕撼碧雲垂。", "夜深動地蚊雷吼，病枕安然總不知。"]'),
('e88e696e-7bfb-4cbe-9b95-94ab0c77f583','沈兼簽記夢','釋心月','宋','宋诗','song-poetry','','[]','一微塵裏三千界，半剎那間八萬春。',32,'全唐诗/poet.song.208000.json','["一微塵裏三千界，半剎那間八萬春。", "如是往來如是住，不知誰主又誰賓。"]'),
('55f21d29-3836-443e-88fc-20674794cdcf','送慧大師','釋心月','宋','宋诗','song-poetry','','[]','剃除紺髮搭伽梨，經卷輪珠常自隨。',32,'全唐诗/poet.song.208000.json','["剃除紺髮搭伽梨，經卷輪珠常自隨。", "欲扣玄關參自己，好看實際訪俱胝。"]'),
('74fdbd86-b81f-42c2-bc69-2611a331b76d','昌大師住廣福說偈勉之','釋心月','宋','宋诗','song-poetry','','[]','桂岩桂子久飄香，時節催開選佛場。',32,'全唐诗/poet.song.208000.json','["桂岩桂子久飄香，時節催開選佛場。", "莫作末山施半杓，使人特地喚娘娘。"]'),
('5dd2c230-02d9-437a-910a-4ad22a31a1c1','聰大師號無聞送廣福住院','釋心月','宋','宋诗','song-poetry','','[]','來日臺山大會齋，隔身句子絕安排。',32,'全唐诗/poet.song.208000.json','["來日臺山大會齋，隔身句子絕安排。", "如今已落無聞手，雙放雙收機莫偕。"]');
